import { DOCUMENT } from "@angular/common";
import {
  Component,
  ElementRef,
  Inject,
  OnInit,
  ViewChild,
} from "@angular/core";
import {
  Router,
  RouteConfigLoadStart,
  RouteConfigLoadEnd,
  RouterOutlet,
  ActivationStart,
} from "@angular/router";
import { EnvService } from "src/app/core/services/env.service";
import {
  Gesture,
  GestureController,
  GestureDetail,
  MenuController,
} from "@ionic/angular";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";

@Component({
  selector: "app-base",
  templateUrl: "./base.component.html",
  styleUrls: ["./base.component.scss"],
})
export class BaseComponent implements OnInit {
  isLoading: boolean;
  showLoader: boolean = false;

  @ViewChild("routerOutlet") outlet: RouterOutlet;
  @ViewChild("appSidebar") appSidebar;
  @ViewChild("appNavbar") appNavbar;
  // @ViewChild("appFooter") appFooter;
  @ViewChild("mainContentWrapper") mainContentWrapper: ElementRef;

  swipeGesture: Gesture;

  constructor(
    private router: Router,
    private envService: EnvService,
    @Inject(DOCUMENT) private document: Document,
    private gestureController: GestureController,
    private menu: MenuController,
    private authService: MohassilAuthService
  ) {
    router.events.forEach((event) => {
      if (event instanceof RouteConfigLoadStart) {
        this.isLoading = true;
      } else if (event instanceof RouteConfigLoadEnd) {
        this.isLoading = false;
      }
    });
  }
  async ngOnInit() {}

  async ionViewWillEnter(): Promise<void> {
    // await this.envService.refreshApiUrl();
    // try {
    // } catch (err) {}
    await this.appSidebar.ngOnInit();
    await this.appNavbar.ngOnInit();
    // await this.appFooter.ngOnInit();
  }

  ionViewDidEnter(): void {
    if (!!this.mainContentWrapper?.nativeElement) {
      this.swipeGesture = this.gestureController.create({
        el: this.mainContentWrapper.nativeElement,
        onMove: (swipeEvent) => this.onSwipe(swipeEvent),
        gestureName: "swipe-menu",
        direction: "x",
        blurOnStart: true,
      });

      this.swipeGesture.enable();
    }
  }

  ionViewWillLeave(): void {
    this.swipeGesture?.destroy();
    this.appSidebar.CloseAllItems();
    this.appSidebar?.ngOnDestroy();
  }

  private onSwipe(swipeEvent: GestureDetail): void {
    if (
      swipeEvent.velocityX <= -1.5 &&
      window.innerWidth - swipeEvent.startX <= window.innerWidth / 3 &&
      !this.document.body.classList.contains("settings-open") &&
      !this.document.body.classList.contains("sidebar-open")
    ) {
      this.document.body.classList.add("sidebar-open");
    }

    // if (
    //   swipeEvent.velocityX >= 1.5 &&
    //   swipeEvent.startX <= window.innerWidth / 3 &&
    //   !this.document.body.classList.contains("settings-open") &&
    //   !this.document.body.classList.contains("sidebar-open")
    // ) {
    //   this.document.body.classList.add("settings-open");
    // }
  }

  closeSidebar() {
    if (this.document.body.classList.contains("settings-open")) {
      this.document.body.classList.remove("settings-open");
    } else {
      if (this.document.body.classList.contains("sidebar-open")) {
        this.document.body.classList.remove("sidebar-open");
      }
    }
  }
  async routeChanged($event: Event) {
    let isAccessTokenPresent: boolean =
      await this.authService.isAccessTokenPresent();
    if (!isAccessTokenPresent) {
      await this.authService.deleteTokens();
      await this.authService.deleteAccessRights();
      await this.authService.redirectToLoginScreen();
    }
  }

  openLoader() {
    this.showLoader = true;
  }
  closeLoader() {
    this.showLoader = false;
  }
}
