import { timeout } from "rxjs/operators";
import { arEG } from "date-fns/locale";
import { Component, NgZone } from "@angular/core";
import { Router } from "@angular/router";
import { App, URLOpenListenerEvent } from "@capacitor/app";
import { ApplicationState } from "./core/models/ApplicationState";
import { StateService } from "./core/services/state.service";
import { AlertController, Platform } from "@ionic/angular";
import { TranslateService } from "@ngx-translate/core";
import { MohassilAuthService } from "./core/services/AuthenticationServices/mohassil-auth.service";
import { Capacitor } from "@capacitor/core";
import { LocationService } from "./core/services/location.service";
import { HttpClient } from "@angular/common/http";
import { EnvService } from "./core/services/env.service";
import { StatusBar, Style } from '@capacitor/status-bar';

// import { DocumentReader } from "@regulaforensics/ionic-native-document-reader";

@Component({
  selector: "app-root",
  templateUrl: "./app.component.html",
  styleUrls: ["./app.component.scss"],
})
export class AppComponent {
  private readonly appUrl: string = "mohassil://";
  myInterval;
  locCaptureFreq: number;
  currentLanguage: string = localStorage.getItem("currentLanguage") || "ar-EG";
  textDirection: string = this.currentLanguage == "en-GB" ? "ltr" : "rtl";
  constructor(
    private env: EnvService,
    private http: HttpClient,
    private router: Router,
    private stateService: StateService,
    private platform: Platform,
    private alertController: AlertController,
    private zone: NgZone,
    private translate: TranslateService,
    private authService: MohassilAuthService,
    private location: LocationService
  ) {
    this.initializeApp();
  }

  initializeApp() {
    //  this.setStatusBar();
  //Aya
  this.platform.ready().then(async () => {
    if (this.platform.is('ios')) {
      try {
        await StatusBar.setOverlaysWebView({ overlay: false }); // Disable overlay
        await StatusBar.setStyle({ style: Style.Dark}); // Ensure dark status bar
      } catch (error) {
        console.error('StatusBar error:', error);
      }
    }
  });

    App.addListener("appRestoredResult", async (result) => {
      let appState: ApplicationState = await this.stateService.getAppState();
      if (!!appState) {
        await this.stateService.saveAppRestoredResult(result);
        this.router.navigateByUrl(appState.uri);
      }
    });
    App.addListener("appUrlOpen", (event: URLOpenListenerEvent) => {
      this.zone.run(() => {
        const slug = event.url.split(this.appUrl).pop();
        if (slug) {
          this.router.navigateByUrl(slug);
        }
      });
    });
    //Aya
    const prefersDark = window.matchMedia('(prefers-color-scheme: dark)');
    document.body.setAttribute('data-theme', prefersDark.matches ? 'dark' : 'light');
    prefersDark.addEventListener('change', (event) => {
      document.body.setAttribute('data-theme', event.matches ? 'dark' : 'light');
    });
  
  }
  async ngOnInit() {
    await this.translate.use(this.currentLanguage).toPromise();
    this.platform.backButton.subscribeWithPriority(0, (next) => {
      if (this.router.url != "/home" && this.router.url != "/") {
        this.router.navigateByUrl("/home");
      } else {
        this.exitAlert();
      }
    });
    //Aya
    const prefersDark = window.matchMedia('(prefers-color-scheme: dark)');

    // Initial check
    document.body.classList.toggle('dark', prefersDark.matches);

    // Listen for changes
    prefersDark.addEventListener('change', (event) => {
      document.body.classList.toggle('dark', event.matches);
    });
    //
    if (!localStorage.getItem("currentLanguage")) {
      localStorage.setItem("currentLanguage", this.currentLanguage);
    }
    let isAccessTokenPresent: boolean =
      await this.authService.isAccessTokenPresent();
    if (!isAccessTokenPresent) {
      await this.authService.deleteTokens();
      await this.authService.deleteAccessRights();
      await this.authService.redirectToLoginScreen();
    } else {
      this.authService.initializeSendLocation();
    }
    // this.InitializeReader();
  }

  async exitAlert(): Promise<void> {
    let alert = this.alertController.create({
      header: "الخروج",
      message: "هل انت متأكد من الخروج من البرنامج؟",
      buttons: [
        {
          text: "نعم",
          role: "OK",
          cssClass: "alert-button-confirm",
          handler: () => {
            App.exitApp();
          },
        },
        {
          text: "لا",
          cssClass: "alert-button-confirm",
          role: "cancel",
          handler: () => {},
        },
      ],
    });
    (await alert).present();
  }
}
