import { BehaviorSubject } from "rxjs";
import { Component, Input, OnInit } from "@angular/core";
import { Feature, Map } from "ol";
import { OSM, Vector as VectorSource } from "ol/source.js";
import View from "ol/View.js";
import TileLayer from "ol/layer/Tile.js";
import VectorLayer from "ol/layer/Vector";
import Style from "ol/style/Style";
import Stroke from "ol/style/Stroke";
import { useGeographic } from "ol/proj.js";
import { UserLocation } from "../../Models/Users/User";
import { LineString } from "ol/geom";

@Component({
  selector: "app-map",
  templateUrl: "./map.component.html",
  styleUrls: ["./map.component.scss"],
})
export class MapComponent implements OnInit {
  @Input() userPoints: BehaviorSubject<UserLocation[]>;
  map: Map;
  vector;
  constructor() {}

  ngOnInit() {
    useGeographic();
    this.map = new Map({
      view: new View({
        center: [0, 0],
        zoom: 15,
      }),
      layers: [
        new TileLayer({
          source: new OSM(),
        }),
      ],
      target: "ol-map",
      controls: [],
    });
    this.userPoints.subscribe((values: UserLocation[]) => {
      console.log(values);
      if (this.vector) {
        this.map.removeLayer(this.vector);
      }
      var features;
      if (values.length > 1) {
        features = new Array(values.length - 1);
        values.map((value, i) => {
          if (values[i + 1]) {
            features[i] = new Feature({
              geometry: new LineString([
                [value.longitude, value.latitude],
                [values[i + 1].longitude, values[i + 1].latitude],
              ]),
            });
          }
        });
      } else {
        features = [];
        if (values.length == 1) {
          features[0] = new Feature({
            geometry: new LineString([
              [values[0].longitude, values[0].latitude],
              [values[0].longitude, values[0].latitude],
            ]),
          });
        } else {
          features[0] = new Feature({
            geometry: new LineString([
              [0, 0],
              [0, 0],
            ]),
          });
        }
      }
      this.vector = new VectorLayer({
        source: new VectorSource({
          features: features,
        }),
        style: new Style({
          stroke: new Stroke({
            color: "#FF0000",
            width: 3,
          }),
        }),
      });
      const sumLat = values.reduce((accumulator, currentValue) => {
        return accumulator + currentValue.latitude;
      }, 0);
      const sumLong = values.reduce((accumulator, currentValue) => {
        return accumulator + currentValue.longitude;
      }, 0);
      console.log(sumLat, sumLong);
      if (values.length > 1) {
        this.map.setView(
          new View({
            center: [sumLong / values.length, sumLat / values.length],
            zoom: 15,
          })
        );
      }
      this.map.addLayer(this.vector);
    });
  }
}
