import { Injectable } from "@angular/core";
import { FormGroupDirective } from "@angular/forms";

@Injectable({
  providedIn: "root",
})
export class InputMaskingService {
  constructor() {}

  formatNumberInput(
    event: any,
    minNumber: number,
    maxNumber: number,
    decimalNumber: number,
    allowNull: boolean = true
  ): void {
    const ionInputElement = event.target as any;
    ionInputElement.getInputElement().then((inputElement: HTMLInputElement) => {
      inputElement.type = "text";

      let input = event.target.value;

      // Handle decimalNumber = 0 case
      if (decimalNumber === 0) {
        if (minNumber < 0) {
          input = input.replace(/[^0-9-]/g, "");
        } else {
          input = input.replace(/[^0-9]/g, "");
        }
      } else {
        if (minNumber < 0) {
          input = input.replace(/[^0-9.-]/g, "");
        } else {
          input = input.replace(/[^0-9.]/g, "");
        }
      }

      // Remove leading zeros, including cases like '0111'
      if (
        input.length > 1 &&
        input.startsWith("0") &&
        !input.startsWith("0.")
      ) {
        input = input.replace(/^0+/, "");
      } else if (
        input.length > 2 &&
        input.startsWith("-0") &&
        !input.startsWith("-0.")
      ) {
        input = "-" + input.replace(/^-0+/, "");
      }

      // Handle multiple negative signs
      if (input.split("-").length > 2) {
        input = input.replace(/-{2,}/g, "-");
      }
      if (input.indexOf("-") > 0) {
        input = input.replace(/-/, "");
      }
      if (input.indexOf("-") === 0) {
        input = "-" + input.slice(1).replace(/-/g, "");
      }

      // Handle multiple decimal points
      const parts = input.split(".");
      if (parts.length > 2) {
        input = parts[0] + "." + parts[1];
      }
      if (parts[1] && parts[1].length > decimalNumber) {
        input = parts[0] + "." + parts[1].substring(0, decimalNumber);
      }

      // Convert to a numeric value
      let numericValue = parseFloat(input);
      if (isNaN(numericValue)) {
        numericValue = minNumber;
      }

      // Enforce min and max range
      if (numericValue > maxNumber) {
        input = Number(maxNumber).toFixed(decimalNumber);
      } else if (numericValue < minNumber) {
        input = Number(minNumber).toFixed(decimalNumber);
      } else if (numericValue === maxNumber && parts[1]) {
        const truncatedValue = parseFloat(maxNumber.toFixed(decimalNumber));
        if (parseFloat(input) > truncatedValue) {
          input = truncatedValue.toFixed(decimalNumber);
        }
      }

      // If the input is empty after all adjustments, set it to "0" if minNumber allows it
      if (!allowNull) {
        if (input === "") {
          input = minNumber;
        }
      }

      // Update the input field with the formatted value
      event.target.value = input;
      inputElement.value = input;
    });
  }
}
