import { Component, OnDestroy, OnInit, Inject } from "@angular/core";
import { DOCUMENT } from "@angular/common";
import { Plugins } from "@capacitor/core";
import {
  CameraPreviewOptions,
  CameraPreviewPictureOptions,
} from "@capacitor-community/camera-preview";
import "@capacitor-community/camera-preview";
import { ModalController } from "@ionic/angular";
import { ScreenOrientation } from "@awesome-cordova-plugins/screen-orientation/ngx";
const { CameraPreview } = Plugins;

@Component({
  selector: "app-preview",
  templateUrl: "./camerapreview.page.html",
  styleUrls: ["./camerapreview.page.scss"],
})
export class CameraPreviewPage implements OnInit, OnDestroy {
  image = null;
  cameraActive = false;
  constructor(
    private modal: ModalController,
    private screenOrientation: ScreenOrientation,
    @Inject(DOCUMENT) private document: Document
  ) {}

  ngOnInit() {
    this.launchCamera();
  }
  ngOnDestroy(): void {
    if (this.cameraActive) this.stopCamera();
  }

  async launchCamera() {
    const cameraPreviewOptions: CameraPreviewOptions = {
      position: "rear", // front or rear
      parent: "content-test", // the id on the ion-content
      className: "",
      toBack: true,
    };
    CameraPreview.start(cameraPreviewOptions);
    this.cameraActive = true;
    document.documentElement.classList.toggle("hide-all");
    this.screenOrientation.lock(this.screenOrientation.ORIENTATIONS.LANDSCAPE);
  }

  async takePicture() {
    const cameraPreviewPictureOptions: CameraPreviewPictureOptions = {
      quality: 100,
      height: 2000,
      width: 2000,
    };
    const result = await CameraPreview.capture(cameraPreviewPictureOptions);
    this.image = result.value;
    this.stopCamera();
  }

  async stopCamera() {
    await CameraPreview.stop();
    this.cameraActive = false;
    document.documentElement.classList.remove("hide-all");
    this.modal.dismiss(this.image);
    this.screenOrientation.unlock();
  }

  async flipCamera() {
    await CameraPreview.flip();
  }

  onWillDismiss(event: Event) {
    this.stopCamera();
  }
}
