import {
  User,
  UserBranchInfo,
  UserBranches,
  UserLocation,
} from "./../../views/Models/Users/User";
import { Injectable, Injector } from "@angular/core";
import { ClientInfo } from "src/app/views/Models/Client/ClientInfo";
import { EnvService } from "./env.service";
import { HttpClient } from "@angular/common/http";
import { InsertClient } from "src/app/views/Models/Client/InsertClient";
import { IEditClient } from "src/app/views/Models/Client/EditClient";
import { AlertService } from "./alert.service";
import { ClientBranchInfo } from "../models/Client/ClientBranchInfo";
import { clientInfoFromClientRegistration } from "src/app/views/Models/Client/clientInfoFromClientRegistration";
import {
  UpdateUserPreference,
  UserPreference as UserPreference,
} from "src/app/views/Models/Users/UserPreference";
import { Observable } from "rxjs";
import { LoginResponse } from "src/app/views/Models/Settings/LoginResponse";
import { MohassilAuthService } from "./AuthenticationServices/mohassil-auth.service";

@Injectable({
  providedIn: "root",
})
export class UserService {
  constructor(
    private env: EnvService,
    private http: HttpClient,
    private injector: Injector,
    //private authService: MohassilAuthService,
    private alertService: AlertService
  ) {}

  async getUserLocations(
    startDate: string,
    endDate: string,
    username: string
  ): Promise<UserLocation[]> {
    try {
      const response = await this.http
        .post<UserLocation[]>(
          `${this.env.API_URL}api/Location/GetUserSavedLocations`,
          {
            startDate: startDate.toString(),
            endDate: endDate.toString(),
            username: username,
          }
        )
        .toPromise();
      return response;
    } catch (error) {
      console.error("Error fetching user locations:", error);
      throw error;
    }
  }
  async getUserBranchInfo(): Promise<UserBranchInfo> {
    try {
      const response = await this.http
        .get<UserBranchInfo>(`${this.env.API_URL}api/User/GetUserBranchInfo`)
        .toPromise();
      return response;
    } catch (error) {
      console.error("Error fetching getUserBranchInfo:", error);
      throw error;
    }
  }
  async getUserBranches(): Promise<UserBranches[]> {
    try {
      const response = await this.http
        .get<UserBranches[]>(`${this.env.API_URL}api/User/GetUserBranches`)
        .toPromise();
      return response;
    } catch (error) {
      console.error("Error fetching getUserBranches:", error);
      throw error;
    }
  }

  async changeUserBranch(branchCode: string) {
    try {
      const auth = this.injector.get(MohassilAuthService);
      const response = await this.http
        .post<LoginResponse>(`${this.env.API_URL}api/User/ChangeUserBranch`, {
          branch_code: branchCode,
        })
        .toPromise();
      await auth.saveLoginResponse(response);
    } catch (error) {
      console.error("Error fetching changeUserBranch:", error);
      throw error;
    }
  }

  getUserPreference = (): Observable<UserPreference> => {
    try {
      return this.http.get<UserPreference>(
        `${this.env.API_URL}api/Settings/GetUserPreference`
      );
    } catch (error) {
      console.error("Error fetching UserPreference:", error);
      throw error;
    }
  };

  updateUserPreference = (input: UpdateUserPreference) => {
    try {
      return this.http
        .post(`${this.env.API_URL}api/Settings/UpdateUserPreferences`, {
          searchWithSpace: input.searchWithSpace,
          searchWith15Client: input.searchWith15Client,
          autoCompleteSearch: input.autoCompleteSearch,
          numberOfDataDisplayResults: input.numberOfDataDisplayResults,
          numberClientsOnSearch: input.numberClientsOnSearch,
          dashboardTypeView:input.dashboardTypeView
        })
        .toPromise();
    } catch (error) {
      console.error("Error Updating updateUserPreference:", error);
      throw error;
    }
  };

  async getAllJobUsers(orgCode: string): Promise<User[]> {
    try {
      const response = await this.http
        .get<User[]>(
          `${this.env.API_URL}api/User/GetAllJobUsers?org_code=${orgCode}`,
          {}
        )
        .toPromise();
      return response;
    } catch (error) {
      console.error("Error fetching user info:", error);
      throw error;
    }
  }
}
