import { HttpClient } from "@angular/common/http";
import { Injectable } from "@angular/core";
import { MohassilAuthService } from "./AuthenticationServices/mohassil-auth.service";
import { EnvService } from "./env.service";
import { SMSAllowed, SMSByEvent } from "src/app/views/Models/Sms/SMS";
import { AlertService } from "./alert.service";

@Injectable({
  providedIn: "root",
})
export class SMSService {
  constructor(
    private http: HttpClient,
    private env: EnvService,
    private alertSerivce: AlertService,
    private authService: MohassilAuthService
  ) {}

  async SMSAllowed(event_id: string): Promise<boolean> {
    try {
      let org_code = (await this.authService.getUserInfo()).org_code;
      const response: SMSAllowed = await this.http
        .post<SMSAllowed>(this.env.API_URL + "api/Settings/SMSAllowed", {
          org_code: org_code,
          event_id: event_id,
        })
        .toPromise();
      return response.smsStatus === 1 && response.eventStatus === 1
        ? true
        : false;
    } catch (error) {
      return false;
    }
  }
  async OTP(mobileNumber: string) {
    try {
      if (!(await this.SMSAllowed("0"))) {
        return;
      }
      return await this.http
        .post(this.env.API_URL + "api/Settings/SMSOTP", {
          mobile: mobileNumber,
        })
        .toPromise();
    } catch (error) {
      this.alertSerivce.showAlertError(error, false);
      return null;
    }
  }
  VerifyOTP = async (mobileNumber: string, otpNumber: string) => {
    try {
      const result = await this.http
        .get<number>(
          this.env.API_URL +
            `api/Settings/OtpVerification?mobileNumber=${mobileNumber}&otpNumber=${otpNumber}`
        )
        .toPromise();
      return result === 1 ? true : false;
    } catch (error) {
      console.error("Error fetching VerifyOTP:", error);
      throw error;
    }
  };
  async SMSByEvent(SMSByEventObject: SMSByEvent): Promise<void> {
    try {
      if (await this.SMSAllowed(SMSByEventObject.event_id)) {
        await this.http
          .post(this.env.API_URL + "api/Settings/SMSByEvent", {
            event_id: SMSByEventObject.event_id,
            mobile: SMSByEventObject.mobile,
            client_key: SMSByEventObject.client_key,
          })
          .toPromise();
      } else {
        throw null;
      }
    } catch (error) {
      this.alertSerivce.showAlertError(error, false);
      return null;
    }
  }
  async SMSSendPerUser(
    mobileNumber: string,
    message_text: string
  ): Promise<void> {
    try {
      if (this.SMSAllowed("10")) {
        await this.http
          .post(this.env.API_URL + "api/Settings/SMSSendPerUser", {
            sms_text: message_text,
            mobile: mobileNumber,
          })
          .toPromise();
      } else {
        return;
      }
    } catch (error) {
      this.alertSerivce.showAlertError(error, false);
      return null;
    }
  }
}
