import { Injectable } from "@angular/core";
import {
  HttpRequest,
  HttpHandler,
  HttpEvent,
  HttpInterceptor,
  HTTP_INTERCEPTORS,
  HttpErrorResponse,
} from "@angular/common/http";
import { Observable, of, from, throwError, OperatorFunction } from "rxjs";
import { mergeMap, catchError, timeout } from "rxjs/operators";
import { MohassilAuthService } from "../services/AuthenticationServices/mohassil-auth.service";

@Injectable()
export class AuthenticationInterceptor implements HttpInterceptor {
  private readonly AUTHENTICATION_ENDPOINTS: string[] = [
    "api/auth/mohassillogin",
    "api/auth/refreshtoken",
  ];

  constructor(private authService: MohassilAuthService) {}

  intercept(
    request: HttpRequest<unknown>,
    next: HttpHandler
  ): Observable<HttpEvent<unknown>> {
    return this.appendAccessTokenToHttpRequest(request).pipe(
      mergeMap((req) => this.fixUndefinedServiceUrl(req)),
      mergeMap((authorizedRequest) => {
        return next.handle(authorizedRequest).pipe(
          // 15 seconds timeout when trying to login or refresh token
          this.timeoutWhen(
            this.isAuthenticationUrl(authorizedRequest.url),
            30000
          ),
          catchError((error) => {
            if (
              error instanceof HttpErrorResponse &&
              !this.isAuthenticationUrl(authorizedRequest.url) &&
              error.status === 401
            ) {
              return this.handleAuthorizationError(
                authorizedRequest,
                next,
                error
              );
            } else if (
              error instanceof HttpErrorResponse &&
              error.status === 0
            ) {
              this.authService.deleteTokens();
              this.authService.deleteAccessRights();
              this.authService.logOut();
            }
            return throwError(error);
          })
        );
      })
    );
  }

  private appendAccessTokenToHttpRequest(
    request: HttpRequest<unknown>
  ): Observable<HttpRequest<unknown>> {
    return from(this.authService.getAccessToken()).pipe(
      mergeMap((accessToken) => {
        return of(
          request.clone({
            headers: request.headers
              .set("Authorization", `Bearer ${accessToken}`)
              .append("Access-Control-Max-Age", "1728000")
              .append("Access-Control-Allow-Origin", "*"),
          })
        );
      })
    );
  }

  private fixUndefinedServiceUrl(
    request: HttpRequest<unknown>
  ): Observable<HttpRequest<unknown>> {
    if (request.url.includes("undefined")) {
      return from(this.authService.getServiceUrl()).pipe(
        mergeMap((serviceUrl) => {
          let slug: string = request.url.split("undefined")[1];
          return of(
            request.clone({
              url: `${serviceUrl}${slug}`,
            })
          );
        })
      );
    } else {
      return of(request);
    }
  }

  private handleAuthorizationError(
    request: HttpRequest<any>,
    next: HttpHandler,
    error: HttpErrorResponse
  ) {
    if (true) {
      return from(this.authService.refreshToken()).pipe(
        mergeMap((success) => {
          if (success) {
            return this.appendAccessTokenToHttpRequest(request).pipe(
              mergeMap((authorizedRequest) => {
                return next.handle(authorizedRequest);
              })
            );
          } else {
            return throwError(error);
          }
        })
      );
    }
  }

  private timeoutWhen<T>(
    condition: boolean,
    value: number
  ): OperatorFunction<T, T> {
    return (source: Observable<T>): Observable<T> => {
      return condition ? source.pipe(timeout(value)) : source;
    };
  }

  private isAuthenticationUrl(url: string) {
    return this.AUTHENTICATION_ENDPOINTS.some((e) =>
      url.toLowerCase().includes(e)
    );
  }
}

export const AuthenticationInterceptorProvider = [
  {
    provide: HTTP_INTERCEPTORS,
    useClass: AuthenticationInterceptor,
    multi: true,
  },
];
