import {
  Component,
  EventEmitter,
  OnInit,
  Output,
  ViewChild,
} from "@angular/core";
import { OverlayEventDetail } from "../../pages/registry/client-registration/overlays-interface";
import { IdData } from "../../Models/Ocr/IdData";
import { Capacitor } from "@capacitor/core";
import { IonModal, ModalController } from "@ionic/angular";
import { CameraPreviewPage } from "../camerapreview/camerapreview.page";
import { HttpClient } from "@angular/common/http";
import { EnvService } from "src/app/core/services/env.service";
import { AlertService } from "src/app/core/services/alert.service";

@Component({
  selector: "app-ocr",
  templateUrl: "./ocr.component.html",
  styleUrls: ["./ocr.component.scss"],
})
export class OcrComponent implements OnInit {
  @ViewChild(IonModal) ocrModal: IonModal;
  @Output() ocrResult: EventEmitter<IdData> = new EventEmitter();
  constructor(
    private modal: ModalController,
    private http: HttpClient,
    private env: EnvService,
    private alertService: AlertService
  ) {}
  idRes: IdData = {
    firstName: null,
    familyName: null,
    address: null,
    region: null,
    birthDate: null,
    nationalId: null,
    documentId: null,
    issueDate: null,
    occupation: null,
    maritalStatus: null,
    gender: null,
    religion: null,
    expiryDate: null,
    faceImage: null,
    frontImage: null,
    backImage: null,
  };
  showLoader: boolean = false;
  imageResults = {
    sourceFace: null,
    sourceFront: null,
    sourceBack: null,
    idFront: null,
    idBack: null,
  };
  async ngOnInit() {}

  async onWillDismiss(event: Event) {
    const ev = event as CustomEvent<OverlayEventDetail<string>>;
    if (ev.detail.role === "cancel") {
      this.idRes = {
        firstName: null,
        familyName: null,
        address: null,
        region: null,
        birthDate: null,
        nationalId: null,
        documentId: null,
        issueDate: null,
        occupation: null,
        maritalStatus: null,
        gender: null,
        religion: null,
        expiryDate: null,
        faceImage: null,
        frontImage: null,
        backImage: null,
      };
    } else {
      // this.create4Form.patchValue({ NationIDFirst: this.idRes.nationalId });
    }
  }
  IsIdResultEmpty(): boolean {
    return (
      !this.idRes.nationalId && !this.idRes.firstName && !this.idRes.familyName
    );
  }
  async openCameraModal(front: boolean) {
    try {
      if (Capacitor.getPlatform() === "web") {
        throw new Error("Web is not supported for this function");
      }

      const modal = await this.modal.create({
        component: CameraPreviewPage,
        cssClass: "",
        animated: true,
      });

      modal.onDidDismiss().then((data) => {
        if (data !== null) {
          const imageSource = "data:image/jpeg;base64," + data.data;
          front
            ? (this.imageResults.sourceFront = imageSource)
            : (this.imageResults.sourceBack = imageSource);
        }
      });

      await modal.present();
    } catch (error) {
      await this.alertService.showAlertError(error.message, false);
    }
  }
  cancel() {
    this.EmptyIdResult();
    this.ocrModal.dismiss(null, "cancel");
    this.imageResults = {
      idBack: null,
      idFront: null,
      sourceBack: null,
      sourceFace: null,
      sourceFront: null,
    };
  }
  confirm() {
    this.ocrResult.emit(this.idRes);
    this.ocrModal.dismiss(null, "confirm");
  }
  EmptyIdResult() {
    this.idRes = {
      firstName: null,
      familyName: null,
      address: null,
      region: null,
      birthDate: null,
      nationalId: null,
      documentId: null,
      issueDate: null,
      occupation: null,
      maritalStatus: null,
      gender: null,
      religion: null,
      expiryDate: null,
      faceImage: null,
      frontImage: null,
      backImage: null,
    };
  }
  async DetectIDImages() {
    if (Capacitor.getPlatform() === "web") {
      await this.alertService.showAlertError(
        "لا يمكن اخذ صورة الا من خلال التطبيق",
        false
      );
      return;
    }
    if (
      this.imageResults.sourceFront == undefined &&
      this.imageResults.sourceBack == undefined
    ) {
      await this.alertService.showAlertError(
        "يرجى التقاط صور الهوية أولا",
        false
      );
      return;
    }
    this.showLoader = true;
    this.http
      .post(this.env.API_URL + `api/IDRecognition/ReadImages`, {
        image1: this.imageResults.sourceFront.replace(
          "data:image/jpeg;base64,",
          ""
        ),
        image2: this.imageResults.sourceBack.replace(
          "data:image/jpeg;base64,",
          ""
        ),
      })
      .subscribe({
        next: async (data) => {
          let successful: number = data["successful"];
          this.idRes = data["result"];
          this.imageResults.sourceFace =
            this.idRes.faceImage != null
              ? "data:image/jpeg;base64," + this.idRes.faceImage
              : null;

          this.imageResults.sourceFront =
            this.idRes.frontImage != null
              ? "data:image/jpeg;base64," + this.idRes.faceImage
              : null;

          this.imageResults.sourceBack =
            this.idRes.backImage != null
              ? "data:image/jpeg;base64," + this.idRes.faceImage
              : null;

          this.showLoader = false;
          if (successful !== 1)
            await this.alertService.showAlertError(
              "قد تكون النتيجة غير صحيحة",
              false
            );
        },
        error: async (err) => {
          this.showLoader = false;
          await this.alertService.showAlertError(err.error, false);
        },
      });
  }
}
