import { Injectable } from "@angular/core";
import { AlertService } from "./alert.service";
import { atobSafe } from "../util/atobSafe";

@Injectable({
  providedIn: "root",
})
export class ExportingService {
  constructor(private alertService: AlertService) {}
  changeBase64ToBlob = (base64String: string) => {
    const byteArray = new Uint8Array(
      atobSafe(base64String)
        .split("")
        .map((char) => char.charCodeAt(0))
    );
    return new Blob([byteArray], { type: "application/pdf" });
  };
  async downloadBlobAsPdf(blob: Blob) {
    if (!(await this.alertService.SaveAlert())) return;
    const link = document.createElement("a");
    // create a blobURI pointing to our Blob
    link.href = URL.createObjectURL(blob);
    link.download = "IScorePdf-" + new Date().toString() + "";
    // some browser needs the anchor to be in the doc
    document.body.append(link);
    link.click();
    link.remove();
    // in case the Blob uses a lot of memory
    setTimeout(() => URL.revokeObjectURL(link.href), 7000);
  }
  async downloadPdf(base64String: string) {
    let blob = this.changeBase64ToBlob(base64String);
    await this.downloadBlobAsPdf(blob);
  }
  async blobToBase64(blob: Blob): Promise<string> {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(blob);
      reader.onloadend = () => {
        const base64String = reader.result as string;
        resolve(base64String);
      };
      reader.onerror = (error) => {
        reject(error);
      };
    });
  }
  jpegToBase64(base64: string): Promise<string> {
    return new Promise((resolve, reject) => {
      const blob = new Blob([base64], { type: "image/jpeg" });
      const reader = new FileReader();
      reader.readAsDataURL(blob);
      reader.onloadend = () => {
        const base64String = reader.result as string;
        resolve(base64String);
      };
      reader.onerror = (error) => {
        reject(error);
      };
    });
  }
  blobUrlToBase64(blobUrl: string): Promise<string> {
    return fetch(blobUrl)
      .then((response) => response.blob())
      .then((blob) => this.blobToBase64(blob))
      .catch((error) => {
        console.error("Error converting Blob URL to Base64:", error);
        return Promise.reject(error);
      });
  }

  base64ToArrayBuffer(base64: string): Uint8Array {
    const binaryString = atobSafe(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  }

  getFileSignature(base64: string): string {
    const bytes = this.base64ToArrayBuffer(base64);
    return Array.from(bytes.slice(0, 4)) // Adjust slice for different file types if needed
      .map((byte) => byte.toString(16).padStart(2, "0"))
      .join("");
  }

  getBase64Type(base64: string): string {
    const signature = this.getFileSignature(base64);
    switch (signature) {
      case "25504446": // PDF
        return "application/pdf";
      case "ffd8ffe0": // JPEG
      case "ffd8ffe1":
      case "ffd8ffe2":
      case "ffd8ffe3":
      case "ffd8ffe8":
        return "image/jpeg";
      case "89504e47": // PNG
        return "image/png";
      case "47494638": // GIF
        return "image/gif";
      case "494433": // MP3
        return "audio/mp3";
      case "000001ba": // MPEG Video
      case "000001b3":
        return "video/mpeg";
      // Add more signatures as needed
      default:
        return "unknown";
    }
  }
}
