import { Injectable, Injector } from "@angular/core";
import { EnvService } from "./env.service";
import { HttpClient } from "@angular/common/http";
import { Job } from "src/app/views/Models/Users/Job";
import { Tree } from "src/app/views/Models/Users/Tree";
import { MohassilAuthService } from "./AuthenticationServices/mohassil-auth.service";

@Injectable({
  providedIn: "root",
})
export class JobsService {
  constructor(
    private env: EnvService,
    private http: HttpClient,
    private auth: MohassilAuthService,
    private injector: Injector
  ) {}

  async getJobs(): Promise<Job[]> {
    try {
      const response = await this.http
        .get<Job[]>(this.env.API_URL + "api/Job/GetJobs")
        .toPromise();
      return response;
    } catch (error) {
      console.error("Error fetching user locations:", error);
      throw error;
    }
  }

  async getJobsSupervised(): Promise<Job[]> {
    try {
      const response = await this.http
        .get<Job[]>(this.env.API_URL + "api/Job/GetAllJobsSupervised")
        .toPromise();
      console.log(response);
      return response;
    } catch (error) {
      console.error("Error fetching user locations:", error);
      throw error;
    }
  }

  async getJobsTree(): Promise<Tree<Job>[]> {
    return await this.getTree(
      await this.getJobs(),
      null,
      true,
      true,
      true,
      false
    );
  }

  async getJobsSupervisedTree(): Promise<Tree<Job>[]> {
    let user = await this.auth.getUserInfo();
    console.log(user);
    return await this.getTree(
      await this.getJobsSupervised(),
      user.workflow_job_id,
      false,
      false,
      false,
      true
    );
  }

  private async getTree(
    jobs: Job[],
    startingJob: string,
    canAdd: boolean,
    canEdit: boolean,
    canDelete: boolean,
    canSelect: boolean
  ): Promise<Tree<Job>[]> {
    let jobHierarchy: Tree<Job>[];
    let nodeMap: Record<number, Tree<Job>> = [];
    jobHierarchy = jobs.map<Tree<Job>>((data) => {
      return {
        data: data,
        text: data.job_name,
        canAdd: canAdd,
        canDelete: canDelete,
        canEdit: canEdit,
        canSelect: canSelect,
        collapsed: true,
        initialized: false,
      };
    });

    jobHierarchy.forEach((node) => {
      nodeMap[node.data.job_id] = {
        ...node,
        children: [],
      };
    });

    jobHierarchy.forEach((node) => {
      if (node.data.supervisor_id) {
        const supervisorNode = nodeMap[node.data.supervisor_id];
        if (supervisorNode) {
          supervisorNode.children.push(nodeMap[node.data.job_id]);
        }
      }
    });

    const rootNodes = Object.values(nodeMap).filter(
      (node) => node.data.supervisor_id == startingJob
    );
    console.log(rootNodes);

    return rootNodes;
  }

  async checkJobUser() {
    try {
      const response = await this.http
        .get<number>(this.env.API_URL + "api/Job/CheckJobUser")
        .toPromise();
      console.log(response);
      return response > 0;
    } catch (error) {
      console.error("Error checking job user:", error);
      throw error;
    }
  }

  async checkJobUserStatus() {
    try {
      const response = await this.http
        .get<number>(this.env.API_URL + "api/Job/CheckJobUserStatus")
        .toPromise();
      console.log(response);
      return response > 0;
    } catch (error) {
      console.error("Error checking job user status:", error);
      throw error;
    }
  }

  async changeJobUserStatus() {
    try {
      await this.http
        .post(this.env.API_URL + "api/Job/ChangeJobUserStatus", "")
        .toPromise();
    } catch (error) {
      console.error("Error changing job user status:", error);
      throw error;
    }
  }
}
