  private async checkGeolocationPermission(): Promise<boolean> {
    let { location, coarseLocation } = await Geolocation.checkPermissions();
    return location == "granted" && coarseLocation == "granted";
  }

  private async canAskForGeolocationPermission(): Promise<boolean> {
    let { location, coarseLocation } = await Geolocation.checkPermissions();
    return location != "denied" && coarseLocation != "denied";
  }

  private async requestGeolocationPermission(): Promise<boolean> {
    let granted: boolean = await this.checkGeolocationPermission();
    if (granted) {
      return true;
    } else {
      const canAskForPermission: boolean =
        await this.canAskForGeolocationPermission();
      if (canAskForPermission) {
        await Geolocation.requestPermissions();
        granted = await this.checkGeolocationPermission();
        if (granted) {
          return true;
        }
      }
    }
    return false;
  }

