  async showLocation(coordinates: string): Promise<ViewLocationResult> {
    let result: ViewLocationResult;
    try {
      if (!!coordinates && coordinates != "") {
        if (Capacitor.getPlatform() == "web") {
          window.open(
            `https://www.google.com/maps/search/?api=1&query=${coordinates}`,
            "_blank"
          );
        } else {
          const options = {
            action: this.webIntent.ACTION_VIEW,
            url: `geo:0,0?q=${coordinates}`,
            package: "com.google.android.apps.maps",
          };

          const alternateOptions = {
            action: this.webIntent.ACTION_VIEW,
            //added to url window.open() to work with Huawei tablet because the url: `https://www.google...` is not work
            url: window.open(
              `https://www.google.com/maps/search/?api=1&query=${coordinates}`,
              "_blank"
            ),
            //url: `https://www.google.com/maps/search/?api=1&query=${coordinates}`,
          };

          try {
            await this.webIntent.startActivity(options);
          } catch (error) {
            result = {
              success: false,
              message: "خطأ في الوصول الى برنامج عرض الخرائط",
            };
          }
          result = {
            success: true,
          };
        }
      } else {
        result = {
          success: false,
          message: "لم يتم العثور على عنوان سابق",
        };
      }
    } catch (err) {
      result = {
        success: false,
        message: "خطأ عند عرض العنوان",
      };
    } finally {
      return result;
    }
  }
