import { Component, OnInit, OnDestroy, Inject } from "@angular/core";
import { Subscription } from "rxjs";
import { ActivatedRoute } from "@angular/router";
import { DOCUMENT } from "@angular/common";

import { ThemeService } from "src/app/core/services/theme.service";

@Component({
  selector: "app-error-page",
  templateUrl: "./error-page.component.html",
  styleUrls: ["./error-page.component.scss"],
})
export class ErrorPageComponent implements OnInit, OnDestroy {
  type: any;
  title: any;
  desc: any;
  private sub: Subscription;

  constructor(
    private route: ActivatedRoute,
    @Inject(DOCUMENT) private document: Document,
    private themeService: ThemeService
  ) {}

  ngOnInit(): void {
    this.updateTheme();
    this.type = this.route.snapshot.paramMap.get("type");
    this.sub = this.route.data.subscribe((param) => {
      if (param.type) {
        this.type = param.type;
      }
      if (param.title) {
        this.title = param.title;
      }
      if (param.desc) {
        this.desc = param.desc;
      }
    });

    switch (this.type) {
      case "404":
        if (!this.title) {
          this.title = "غير موجود";
        }
        if (!this.desc) {
          this.desc = "لم يتم العثور على الصفحة المطلوبة";
        }
        break;
      case "500":
        if (!this.title) {
          this.title = "خطأ في البرنامج";
        }
        if (!this.desc) {
          this.desc = "حدث خطأ في البرنامج. برجاء المحاولة لاحقاً";
        }
        break;
      default:
        // if (!this.type) {
        this.type = "404";
        // }
        if (!this.title) {
          this.title = "خطأ في البرنامج";
        }
        if (!this.desc) {
          this.desc = "حدث خطأ في البرنامج. برجاء المحاولة لاحقاً";
        }
    }
  }

  updateTheme(): void {
    if (this.themeService.isDarkMode) {
      this.document.body.classList.add("darkmode");
    } else {
      this.document.body.classList.remove("darkmode");
    }
  }

  ngOnDestroy(): void {
    this.sub.unsubscribe();
  }
}
