import {
  Component,
  EventEmitter,
  Input,
  OnChanges,
  OnInit,
  Output,
  SimpleChanges,
  ViewChild,
} from "@angular/core";
import { IonModal } from "@ionic/angular";
import { AlertService } from "src/app/core/services/alert.service";
import { InputMaskingService } from "src/app/core/services/input-masking.service";
import { PreviousItems } from "../../Models/Officer/OfficerVisitsWorkFlow";
import { Item } from "../../Models/Types/item.model";
import { VendorSubCategoryItemDetails } from "../../Models/Vendor/vendor.model";
import { StaticRef } from "../../Models/References/StaticRef";
import { ReferencesService } from "src/app/core/services/references.service";

@Component({
  selector: "app-display-vendor-items",
  templateUrl: "./display-vendor-items.component.html",
  styleUrls: ["./display-vendor-items.component.scss"],
})
export class DisplayVendorItemsComponent implements OnInit, OnChanges {
  @ViewChild("vendorItems", { static: true }) modal!: IonModal;
  @Input() objects!: VendorSubCategoryItemDetails[];
  @Input() isDisabled: boolean = false;
  @Input() selectedItems!: PreviousItems[];
  @Output() selectedItemsChange = new EventEmitter<
    VendorSubCategoryItemDetails[]
  >();
  // @Output() totalAmount = new EventEmitter<number>();

  categoryItems: Item[] = [];
  subCategoryItems = new Map<string, Item[]>();
  namingRef: StaticRef[];

  isOpened: boolean = false;
  isCategoryChanged: boolean = false;
  shouldSetToZero: boolean = true;

  constructor(
    public inputMaskingService: InputMaskingService,
    private alert: AlertService,
    private referencesService: ReferencesService
  ) {}

  ngOnChanges(changes: SimpleChanges): void {
    this.shouldSetToZero = false;
    if (changes.objects) {
      const areEqual =
        JSON.stringify(changes.objects.currentValue) ===
        JSON.stringify(changes.objects.previousValue);
      if (!areEqual) this.processInput();
    }
  }

  async ngOnInit() {
    this.processInput();
    console.log("SelectedItems", this.selectedItems);
    this.namingRef = await this.referencesService
      .getCategoriesItemsRef()
      .toPromise();
  }

  processInput() {
    let categoriesUsed: string[] = [];
    this.categoryItems = [{ text: "", value: "-1" }];
    this.subCategoryItems.clear();
    this.objects.map((object) => {
      if (this.subCategoryItems.has(object.catItemCode))
        this.subCategoryItems.set(object.catItemCode, [
          ...this.subCategoryItems.get(object.catItemCode),
          { text: object.subItemName, value: object.subItemCode },
        ]);
      else {
        this.subCategoryItems.set(object.catItemCode, [
          { text: object.subItemName, value: object.subItemCode },
        ]);
      }
      if (!categoriesUsed.includes(object.catItemCode)) {
        categoriesUsed.push(object.catItemCode);
        this.categoryItems.push({
          text: object.catItemName,
          value: object.catItemCode,
        });
      }
    });
  }

  setIsOpened(isOpened: boolean) {
    if (!isOpened) {
      this.modal.dismiss();
    }
    this.isOpened = isOpened;
  }

  onWillDismiss(event: Event) {
    this.setIsOpened(false);
  }

  setPrice(index: number, setToZero: boolean) {
    if (this.shouldSetToZero && setToZero) {
      this.selectedItems[index].new_item_price = 0;
    }
    // this.setItemPriceToDefault(index);
  }

  convertToNumber(input: string): number {
    return Number(input);
  }

  getNamingRefValue(code: string): string {
    const ref = this.namingRef?.find((ref) => ref.ref_code === code);
    return ref?.ref_desc ?? "";
  }
}
