import { Component, EventEmitter, Input, OnInit, Output } from "@angular/core";
import { AlertService } from "src/app/core/services/alert.service";
import { CameraService } from "src/app/core/services/camera.service";
import { DocumentService } from "src/app/core/services/document.service";
import {
  documentInputData,
  documentCollection,
  documentOutputData,
} from "src/app/views/Models/Documents/documentSlot";

@Component({
  selector: "app-document-slot",
  templateUrl: "./document-slot.component.html",
  styleUrls: ["./document-slot.component.scss"],
})
export class DocumentSlotComponent implements OnInit {
  @Input() inputData: documentInputData;
  @Output() outputData: EventEmitter<documentOutputData> = new EventEmitter();
  constructor(
    private documentService: DocumentService,
    private cameraService: CameraService,
    private alertService: AlertService
  ) {}

  //#region Variables
  documentCollection: documentCollection = {
    documentData: undefined,
    uploadedDocuments: [],
  };
  //#endregion

  async ngOnInit() {
    // Get all Documents
    let allDocTypes = await this.documentService
      .getActiveDocumentsTypes()
      .toPromise();
    this.documentCollection.documentData = allDocTypes.filter(
      (doc) => doc.documentTypeCode === this.inputData.loanTypeCode
    )[0];

    for (
      let index = 0;
      index < Number(this.documentCollection.documentData.documentPagesNumber);
      index++
    ) {
      if (this.inputData?.uploadedDocuments?.length) {
        const inputUploadedDocument = this.inputData?.uploadedDocuments[index];
        if (
          inputUploadedDocument !== null &&
          inputUploadedDocument !== undefined
        ) {
          this.documentCollection?.uploadedDocuments?.push({
            doc: inputUploadedDocument.doc,
          });
        }
      } else {
        this.documentCollection?.uploadedDocuments?.push({ doc: null });
      }
    }
  }

  async iconPlusBtn(pageNumber: number) {
    if (!this.inputData.canEdit) {
      return;
    }
    for (let index = 0; index < pageNumber; index++) {
      if (this.documentCollection.uploadedDocuments[index].doc === null) {
        return this.alertService.showAlertError(
          `برجاء اضافة صفحة رقم ${index + 1} قبل هذة الصفحة.`,
          false
        );
      }
    }
    let cameraResult = await this.cameraService.getPhoto();

    if (!cameraResult.success) {
      this.alertService.showAlertError(cameraResult.message, false);
      return;
    }

    this.saveCameraImageToCollection(
      pageNumber,
      cameraResult.photo.base64String
    );
  }

  saveCameraImageToCollection(pageNumber: number, image: string) {
    this.documentCollection.uploadedDocuments[pageNumber].doc = image;
    this.emitTheOutput({
      documentTypeCode: this.documentCollection.documentData.documentTypeCode,
      uploadedDocuments: this.documentCollection.uploadedDocuments,
    });
  }
  emitTheOutput(output: documentOutputData) {
    this.outputData.emit(output);
  }
}
