import { HttpClient } from "@angular/common/http";
import { Injectable } from "@angular/core";
import { EnvService } from "./env.service";
import {
  ExtractFileRequest,
  ExtractFileResponse,
} from "../models/IScore/ExtractFile";
import { IscoreExportedFileList } from "../models/IScore/IscoreExportedFileList";
import { IscoreExportedFileDataRequest } from "../models/IScore/IscoreExportedFileDataRequest";
import { HttpParams } from "@capacitor/core";

export type ClientWithLastInquiryInfo = {
  clientKey: string;
  fullClientCode: string;
  clientName: string;
  birthDate: Date | null;
  nationalId: string | null;
  clientTypeName: string;
  inquiryId: number | null;
  inquiryTimestamp: Date | null;
  validInquiry: boolean;
  applicationsWaitingInquiry: number;
  isNoHit: boolean | null;
  score: number | null;
  scoreDesc: string | null;
  pdfAvailable: boolean | null;
  username: string | null;
};

export type InquiryPdf = {
  base64String: string | null;
};

export type InquiryResponse = {
  success: boolean;
  error: string | null;
  inquiryId: number | null;
};

@Injectable({
  providedIn: "root",
})
export class IscoreHttpService {
  constructor(private envService: EnvService, private httpClient: HttpClient) {}

  public getClientWithLastInquiryInfo(clientKey: string) {
    return this.httpClient.get<ClientWithLastInquiryInfo>(
      `${this.envService.API_URL}api/IScore/ClientWithLastInquiry`,
      {
        params: {
          clientKey,
        },
      }
    );
  }

  public getInquiryPdf(inquiryId: number) {
    return this.httpClient.get<InquiryPdf>(
      `${this.envService.API_URL}api/IScore/InquiryPdf`,
      {
        params: {
          inquiryId,
          download: false,
        },
      }
    );
  }

  public inquire(clientKey: string, inquiryReason: string) {
    return this.httpClient.post<InquiryResponse>(
      `${this.envService.API_URL}api/IScore/Inquire`,
      {
        clientKey,
        inquiryReason,
      }
    );
  }

  public extractFile(request: ExtractFileRequest) {
    return this.httpClient.post<ExtractFileResponse>(
      `${this.envService.API_URL}api/IScore/ExtractFile`,
      {
        loansStartDate: request.loansStartDate,
        reportType: request.reportType,
        extractMonth: request.extractMonth,
        extractYear: request.extractYear,
        extractDate: request.extractDate,
        funders: request.funders,
        clientTypes: request.clientTypes,
        branches: request.branches,
        loanTypeCategory: request.loanTypeCategory,
        loanTypes: request.loanTypes,
        fromActivityStart: request.fromActivityStart,
      }
    );
  }

  public getIscoreExportedFileList() {
    return this.httpClient.get<IscoreExportedFileList[]>(
      `${this.envService.API_URL}api/IScore/GetIscoreExportedFileList`
    );
  }

  public getIscoreExportedFileData(request: IscoreExportedFileDataRequest) {
    const formData = new FormData();
    formData.append("batchId", request.batchId.toString());
    formData.append("fileType", request.fileType.toString());
    const httpParams: HttpParams = {
      responseType: "text/txt",
    };
    return this.httpClient.post(
      `${this.envService.API_URL}api/IScore/GetIscoreExportedFileData`,
      formData,
      httpParams
    );
  }
}
