import { EventEmitter, Injectable } from "@angular/core";
import { Capacitor } from "@capacitor/core";
import { AlertService } from "./alert.service";
import { FilesystemService } from "./filesystem.service";
import { ModalController } from "@ionic/angular";
import { PdfViewerComponent } from "src/app/views/components/pdf-viewer/pdf-viewer.component";
import { DatePipe } from "@angular/common";

declare let PDFObject: any;

@Injectable({
  providedIn: "root",
})
export class PdfViewerService {
  constructor(
    private alertService: AlertService,
    private filesystemService: FilesystemService,
    private modalController: ModalController,
    private datePipe: DatePipe
  ) {}

  public async viewPdf(pdfBase64: string, filename: string, title?: string) {
    const qualifiedFilename = filename.endsWith(".pdf")
      ? filename
      : `${filename}.pdf`;

    title = title ?? filename;

    if (!Capacitor.isNativePlatform() && !PDFObject.supportsPDFs) {
      await this.alertService.showAlertError(
        "لا يمكن عرض أو تنزيل المستند على المتصفح الحالي",
        false
      );
      return;
    }

    if (Capacitor.isNativePlatform()) {
      await this.filesystemService.saveFileToCacheAndOpen(
        pdfBase64,
        qualifiedFilename,
        "application/pdf"
      );
    } else {
      const dismiss = new EventEmitter<void>();
      const modal = await this.modalController.create({
        component: PdfViewerComponent,
        componentProps: {
          title,
          pdfBase64,
          dismiss,
        },
        animated: true,
        canDismiss: true,
        keyboardClose: true,
        initialBreakpoint: 1,
        cssClass: "fullscreen",
      });

      dismiss.subscribe(() => {
        modal.dismiss();
        dismiss.complete();
      });

      await modal.present();
    }
  }

  public canViewPdf(): boolean {
    return Capacitor.isNativePlatform() || PDFObject.supportsPDFs;
  }
}
