import { Component, Input, OnInit, Output, EventEmitter } from '@angular/core';
import { FormGroup, FormControl } from '@angular/forms';
import { formatDate } from '@angular/common';

@Component({
  selector: 'datepicker',
  templateUrl: './datepicker.component.html',
  styleUrls: ['./datepicker.component.scss'],
})
export class DatepickerComponent {
  constructor() {}

  @Input() date: string;
  @Input() pickerId: string;
  @Input() parentForm: FormGroup;
  @Input() parentFormControllerName: string;
  @Output() dateChange: EventEmitter<string> = new EventEmitter();

  ionViewWillEnter() {}

  getDateOnly(ionDatetimeInput: any): string {
    return ionDatetimeInput.value.split('T')[0];
  }

  changeDate(date: any): void {
    let dateOnly = this.getDateOnly(date);
    let formattedDate = '';
    if (!!dateOnly) {
      try {
        formattedDate = formatDate(dateOnly, 'yyyy-MM-dd', 'en-ZA');
        this.dateChange.emit(formattedDate);
      } catch (error) {
        this.dateChange.emit('');
      }
    }
    // this.dateChange.emit(formattedDate);
  }

  dateOnlyValidation(event: any) {
    const pattern = /[0-9-]/;
    let inputChar = String.fromCharCode(event.charCode);

    if (!pattern.test(inputChar)) {
      event.preventDefault();
    }
  }
}
