import {
  AfterViewInit,
  Component,
  ElementRef,
  EventEmitter,
  Input,
  OnInit,
  Output,
  ViewChild,
} from "@angular/core";
import { HttpClient } from "@angular/common/http";
import { EnvService } from "src/app/core/services/env.service";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { WizardComponent as BaseWizardComponent } from "angular-archwizard";
import { NgbDateStruct, NgbDate, NgbModule } from "@ng-bootstrap/ng-bootstrap";
import { SearchParameters } from "../../Models/References/SearchParameters";

import { ComponentsModule } from "src/app/views/components/components.module";
import { SearchResult } from "../../Models/References/SearchResult";
import { UserService } from "src/app/core/services/user.service";
import { Preferences } from "@capacitor/preferences";
import { IonInput } from "@ionic/angular";
import { LoanApplicationsService } from "src/app/core/services/loan-applications.service";
import { ClientService } from "src/app/core/services/client.service";
import { WorkFlowApp } from "../../Models/Loan/Step";
import { AlertService } from "src/app/core/services/alert.service";

@Component({
  selector: "app-client-search",
  templateUrl: "./client-search.component.html",
  styleUrls: ["./client-search.component.scss"],
})
export class ClientSearchComponent implements AfterViewInit {
  search_types = [
    ["البحث بالكود في ملف العملاء", 1],
    ["البحث بالاسم في ملف العملاء", 2],
  ];

  constructor(
    private formBuilder: FormBuilder,
    private env: EnvService,
    private http: HttpClient,
    public userService: UserService,
    private loanApplicationService: LoanApplicationsService,
    private clientService: ClientService,
    private alert: AlertService
  ) {}

  @Input() sourcePage?: number;
  @Input() pageAction?: number = 0;
  @Input() traceAddEdit?: number = 0;
  @Input() searchMethod: number = 1; // 1 --> search using search table && 2 --> search using procedure usp_search_control_new && 3 --> search workflow applications by client data
  @Input() resultType: number = 0; // 0 --> client search  && 1 --> Loan Search && 2 --> loan application search
  @Input() searchInitValue: string = null; // if you need to put a value in the searchinput
  @Input() initialSearchType: string = "1";
  @Output() selectedClient: EventEmitter<SearchResult> = new EventEmitter();
  @Output() selectedWorkflowApps: EventEmitter<WorkFlowApp[]> =
    new EventEmitter();

  @ViewChild("inputName", { static: false }) inputName: IonInput;

  searchForm: FormGroup;

  showLoader: boolean = false;
  noResults: Boolean = true;

  isSearchFormSubmitted: Boolean;
  isClientCodeAvailable: Boolean;
  isClientNameAvailable: Boolean;
  isOrgBranchCodeAvailable: Boolean;
  isApplicationCodeAvailable: Boolean;
  isEntryDateAvailable: Boolean;
  isClientTypeNameAvailable: Boolean;
  isGroupNameAvailable: Boolean;
  isLoanCodeAvailable: Boolean;

  searchResults: SearchResult[];

  ngOnInit() {
    this.searchForm = this.formBuilder.group({
      search_type: [this.initialSearchType, [Validators.required]],
      search_input: ["", [Validators.required]],
    });
    this.getPageSize();

    if (
      // this.sourcePage == 36 ||
      this.sourcePage == 31 ||
      // this.sourcePage == 35 ||
      // this.sourcePage == 37 ||
      this.sourcePage == 53 ||
      this.sourcePage == 54 ||
      this.sourcePage == 55 ||
      this.sourcePage == 58 ||
      this.searchMethod == 3
    ) {
      this.search_types.push([" البحث بكود عضو المجموعة", 3]);
      this.search_types.push([" البحث باسم عضو المجموعة", 4]);
    }
    if (
      this.sourcePage == 61 ||
      this.sourcePage == 36 ||
      this.sourcePage == 10 ||
      this.sourcePage == 11 ||
      this.sourcePage == 7 ||
      this.sourcePage == 1 ||
      this.sourcePage == 65 ||
      this.sourcePage == 56 ||
      this.sourcePage == 53 ||
      this.sourcePage == 109 ||
      this.searchMethod == 3
    ) {
      this.search_types.push([" البحث بالرقم القومى", 5]);
    }
    if (
      this.sourcePage == 7 ||
      this.sourcePage == 65 ||
      this.searchMethod == 3
    ) {
      this.search_types.push(["البحث برقم التليفون", 6]);
    }

    if (this.searchInitValue != null) {
      this.searchForm.patchValue({
        search_input: this.searchInitValue,
      });
      this.search();
    }
  }

  ngAfterViewInit() {
    setTimeout(() => {
      this.forceInputFocus();
    }, 200);
  }

  forceInputFocus() {
    this.inputName.setFocus();
  }

  inputSearch(ev: any) {
    if (ev.key === "Enter") {
      this.search();
    }
  }

  search(): void {
    console.log(this.sourcePage);
    this.isSearchFormSubmitted = true;
    if (this.searchForm.valid) {
      this.showLoader = true;
      switch (this.searchMethod) {
        case 1:
        case 2:
          this.defaultSearch();
          break;
        case 3:
          this.searchWorkflowApplicationsByClient();
          break;
      }
    }
  }

  pageSize: number; // number of viewed results
  page = 1; // the page we are viewing
  resultsCount; // the number of results
  totalPages = 1; // calculate by the pageSize and resultsCount this.totalPages = (Math.trunc(x) < (this.resultsCount/this.pageSize)) ? Math.trunc(x)+1:Math.trunc(x) ;

  defaultSearch() {
    const params: SearchParameters = {
      sourcePage: this.sourcePage,
      searchString: this.searchForm.controls.search_input.value,
      searchType: this.searchForm.controls.search_type.value,
      pageAction: this.pageAction,
      traceAddEdit: this.traceAddEdit,
    };
    this.http
      .get<any>(
        this.env.API_URL +
          `api/Search/SearchClients?sourcePage=${params.sourcePage}&searchString=${params.searchString}
                &searchType=${params.searchType}&pageAction=${params.pageAction}&traceAddEdit=${params.traceAddEdit}
                &pageNo=${this.page}&pageSize=${this.pageSize}&resultType=${this.resultType}&searchMethod=${this.searchMethod}`
      )
      .subscribe({
        next: (data) => {
          this.searchResults = data.result;
          console.log(data);
          this.resultsCount = data.count;
          let x = data.count / this.pageSize;
          this.totalPages =
            Math.trunc(x) < data.count / this.pageSize
              ? Math.trunc(x) + 1
              : Math.trunc(x);
          if (this.searchResults.length > 0) {
            if (this.searchInitValue != null) {
              this.selectClient(0);
            }
            this.noResults = false;
            this.hideEmptyColumns();
            if (this.resultsCount == 1) {
              this.selectClient(0);
            }
          } else {
            this.noResults = true;
          }
          this.showLoader = false;
        },
        error: (err) => {
          this.showLoader = false;
        },
      });
  }

  async searchWorkflowApplicationsByClient() {
    let result: WorkFlowApp[] =
      await this.clientService.searchForWorkFlowAppsWithClient(
        this.searchForm.controls.search_input.value,
        this.searchForm.controls.search_type.value
      );
    this.showLoader = false;
    if (!result || result.length == 0) {
      this.alert.showAlertError("لم يتم العثور على أي بيانات", false);
    } else {
      this.selectedWorkflowApps.emit(result);
    }
  }

  goLast() {
    if (this.page != this.totalPages) {
      this.page = this.totalPages;
    }
  }
  nextPage() {
    if (this.totalPages > this.page) {
      this.page++;
    }
  }
  prevPage() {
    if (this.page > 1) {
      this.page--;
    }
  }
  goFirst() {
    if (this.page != 1) {
      this.page = 1;
    }
  }
  changePage(newPage: number): void {
    this.page = newPage;
  }
  hideEmptyColumns() {
    if (this.searchResults != null && this.searchResults.length > 0) {
      this.isApplicationCodeAvailable =
        this.searchResults[0].application_code != null ? true : false;
      this.isClientCodeAvailable =
        this.searchResults[0].client_code != null ? true : false;
      this.isOrgBranchCodeAvailable =
        this.searchResults[0].org_branch_code != null ? true : false;
      this.isClientNameAvailable =
        this.searchResults[0].client_name != null ? true : false;
      this.isClientTypeNameAvailable =
        this.searchResults[0].client_type_name != null ? true : false;
      this.isEntryDateAvailable =
        this.searchResults[0].entry_date != null ? true : false;
      this.isGroupNameAvailable =
        this.searchResults[0].group_name != null ? true : false;
      this.isLoanCodeAvailable =
        this.searchResults[0].loan_code != null ? true : false;
    }
  }

  get searchControls() {
    return this.searchForm.controls;
  }

  selectClient(index: number) {
    this.selectedClient.emit(this.searchResults[index]);
  }

  async getPageSize(): Promise<number> {
    this.userService.getUserPreference().subscribe((x) => {
      this.pageSize = x.grid_page_size;
    });
    return this.pageSize;
  }
}
