import {
  Component,
  OnInit,
  OnChanges,
  Input,
  Output,
  EventEmitter,
  SimpleChanges,
} from "@angular/core";
import { TranslateService } from "@ngx-translate/core";
import { pagingService } from "src/app/core/services/paging.service";

@Component({
  selector: "app-pagination",
  templateUrl: "./pagination.component.html",
  styleUrls: ["./pagination.component.scss"],
})
export class PaginationComponent implements OnInit, OnChanges {
  /* Inputs */

  @Input() page: number;
  @Input() collectionSize: number;
  /* Outputs */

  @Output() pageChange: EventEmitter<number> = new EventEmitter<number>();

  /* Local Variables */

  currentLanguage: string = localStorage.getItem("currentLanguage") || "en-GB";
  textDir: string = "ltr";

  pagesCount: number;
  pageSize: number;

  constructor(
    public translate: TranslateService,
    public pagingService: pagingService
  ) {}

  ngOnInit() {
    this.pageSize = this.pagingService.getPageSizeFromLocalStorage();
    this.pagesCount = Math.ceil(this.collectionSize / this.pageSize);
    this.translate.use(this.currentLanguage);
    this.translate.get(`languages.${this.currentLanguage}.dir`).subscribe({
      next: (dir) => {
        this.textDir = dir;
      },
      error: () => {
        this.textDir = "ltr";
      },
    });
  }

  ngOnChanges(changes: SimpleChanges): void {
    if (!!changes["collectionSize"]) {
      let collectionSize = changes["collectionSize"].currentValue;
      let newPagesCount = Math.ceil(collectionSize / this.pageSize);
      if (newPagesCount < this.pagesCount && this.page == this.pagesCount)
        this.pageChange.emit(newPagesCount);
      this.pagesCount = newPagesCount;
    }

    if (!!changes["pageSize"]) {
      let pageSize = changes["pageSize"].currentValue;
      this.pageSize = pageSize;
      let newPagesCount = Math.ceil(this.collectionSize / this.pageSize);
      if (newPagesCount < this.pagesCount && this.page == this.pagesCount)
        this.pageChange.emit(newPagesCount);
      this.pagesCount = newPagesCount;
    }
  }

  first(): void {
    if (this.page !== 1) {
      this.pageChange.emit(1);
    }
  }

  previous(): void {
    if (this.page > 1) {
      this.pageChange.emit(this.page - 1);
    }
  }

  next(): void {
    if (this.page < this.pagesCount) {
      this.pageChange.emit(this.page + 1);
    }
  }

  last(): void {
    if (this.page !== this.pagesCount) {
      this.pageChange.emit(this.pagesCount);
    }
  }
}
