import { Group } from "./../../Models/Permissions/Group";
import {
  Component,
  OnInit,
  ViewChild,
  ElementRef,
  Inject,
  Renderer2,
  Output,
  EventEmitter,
} from "@angular/core";
import { DatePipe, DOCUMENT } from "@angular/common";
import { Router } from "@angular/router";
import { EnvService } from "src/app/core/services/env.service";
import { Browser } from "@capacitor/browser";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { ThemeService } from "src/app/core/services/theme.service";
import { Capacitor } from "@capacitor/core";
import { TranslateService } from "@ngx-translate/core";
import { delay, mergeMap, take } from "rxjs/operators";
import { interval, Observable } from "rxjs";
import {
  animate,
  query,
  state,
  style,
  transition,
  trigger,
} from "@angular/animations";
import { IonModal, IonPopover, IonToggle } from "@ionic/angular";
import { HttpClient } from "@angular/common/http";
import { Notification } from "../../Models/Users/Notification";
import { InfiniteScrollCustomEvent } from "@ionic/angular";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { UserService } from "src/app/core/services/user.service";
import { Interface } from "readline";
import { UserBranchInfo, UserBranches } from "../../Models/Users/User";
import { AlertService } from "src/app/core/services/alert.service";
import { Preferences } from "@capacitor/preferences";
import { JobsService } from "src/app/core/services/jobs.service";
import { ReferencesService } from "src/app/core/services/references.service";
interface UserInfo {
  userBranchInfo: UserBranchInfo | undefined;
  userBranches: UserBranches[] | undefined;
}
@Component({
  selector: "app-navbar",
  templateUrl: "./navbar.component.html",
  styleUrls: ["./navbar.component.scss"],
  animations: [
    trigger("inOutAnimation", [
      transition(
        ":enter",
        [
          style({
            opacity: 0,
            transform: "translateX({{leaveEnd}})",
          }),
          animate(
            "0.2s ease-out",
            style({
              opacity: 1,
              transform: "translateX(0%)",
            })
          ),
        ],
        {
          params: {
            leaveEnd: "",
          },
        }
      ),
      transition(
        ":leave",
        [
          style({
            opacity: 1,
            transform: "translateX(0%)",
          }),
          animate(
            "0.2s ease-in",
            style({
              opacity: 0,
              transform: "translateX({{leaveEnd}})",
            })
          ),
        ],
        {
          params: {
            leaveEnd: "",
          },
        }
      ),
    ]),
  ],
})
export class NavbarComponent implements OnInit {
  @ViewChild(IonModal) modal: IonModal;
  @ViewChild(IonPopover) popover: IonPopover;
  @Output() openLoader = new EventEmitter<void>();
  @Output() closeLoader = new EventEmitter<void>();
  username: string;
  branchCode: string;
  // isDarkMode: boolean;
  iconName: string;
  iconColor: string;
  currentLanguage: string = localStorage.getItem("currentLanguage") || "en-GB";
  textDir: string = this.currentLanguage == "en-GB" ? "ltr" : "rtl";

  profileClicked: boolean = true;

  jobUserStatusStaticAction: boolean = false;
  jobUser: boolean;
  jobUserStatus: boolean = true;

  isMobile: boolean = false;
  showLoader: boolean = false;

  notificationNo: string;
  notifications: Notification[];
  allNotifications: Notification[];
  allUsers: Set<string> = new Set();
  sortingOptions: string[][] = [];
  filteringForm: FormGroup;

  isModalOpen: boolean = false;
  isPopOverOpen: boolean = false;

  pageNo: number = 1;
  pageSize: number = 9;

  userInfoObject: UserInfo = { userBranchInfo: null, userBranches: [] };
  showUserInfo: boolean = false;
  changeBranchForm: FormGroup = this.formBuilder.group({
    branchCode: [null],
  });
  constructor(
    @Inject(DOCUMENT) private document: Document,
    private renderer: Renderer2,
    private router: Router,
    private env: EnvService,
    public themeService: ThemeService,
    private authService: MohassilAuthService,
    public translate: TranslateService,
    private formBuilder: FormBuilder,
    private http: HttpClient,
    private alertService: AlertService,
    private userService: UserService,
    private datePipe: DatePipe,
    private jobService: JobsService,
    private referenceService: ReferencesService
  ) {}

  async ngOnInit() {
    this.sortingOptions = [
      [await this.translate.get("generic.sortAsc").toPromise(), "0"],
      [await this.translate.get("generic.sortDesc").toPromise(), "1"],
    ];
    this.filteringForm = this.formBuilder.group({
      filter: [""],
      sort: [""],
    });
    this.authService.getUserInfo().then((userInfo) => {
      this.username = userInfo.user_name;
      this.branchCode = userInfo.branch_code;
      this.notificationNo = this.NotificationDisplayCount(
        parseInt(userInfo.notifications_count)
      );
    });
    interval(5 * 1000)
      .pipe(mergeMap(() => this.GetUserInfo()))
      .subscribe((data) => {
        if (data?.notifications_count)
          this.notificationNo = this.NotificationDisplayCount(
            parseInt(data.notifications_count)
          );
      });
    this.themeService.getOrSetTheme();
    this.SetIcon();

    if (Capacitor.getPlatform() != "web") {
      this.isMobile = true;
    }
    if (!this.currentLanguage)
      localStorage.setItem("currentLanguage", this.currentLanguage);
    this.translate.use(this.currentLanguage);
    this.translate.get(`languages.${this.currentLanguage}.dir`).subscribe({
      next: (dir) => {
        this.textDir = dir;
      },
      error: () => {
        this.textDir = "ltr";
      },
    });
    this.referenceService.getStaticValueById(83).then((res) => {
      this.jobUserStatusStaticAction = res.value == "1" ? true : false;
    });

    this.jobService.checkJobUser().then((res) => {
      this.jobUser = res;
    });
    this.jobService.checkJobUserStatus().then((res) => {
      this.jobUserStatus = res;
    });
  }

  onLogout(e) {
    e.preventDefault();
    localStorage.removeItem("isLoggedin");

    if (!localStorage.getItem("isLoggedin")) {
      this.router.navigate(["/login"]);
    }
  }

  async logOut(): Promise<void> {
    await this.authService.deleteTokens();
    await this.authService.deleteAccessRights();
    await this.authService.logOut();
  }

  SetIcon() {
    if (this.themeService.isDarkMode) {
      this.iconName = "sunny-sharp";
      this.iconColor = "warning";
    } else {
      this.iconName = "moon-sharp";
      this.iconColor = "primary";
    }
  }

  OpenProfile() {
    if (this.profileClicked == true) {
      this.profileClicked = false;
    } else {
      this.profileClicked = true;
    }
  }

  SetTheme() {
    this.themeService.toggle();
    this.SetIcon();
  }
  languageSettings() {
    this.currentLanguage = this.currentLanguage == "ar-EG" ? "en-GB" : "ar-EG";
    localStorage.setItem("currentLanguage", this.currentLanguage);
    this.translate.use(this.currentLanguage);
    location.reload();
  }
  GetUserInfo() {
    return this.authService.getUserInfo();
  }
  NotificationDisplayCount(count: number): string {
    if (count && count > 9) return "+9";
    else return count.toString();
  }
  async onWillPresent() {
    await this.getNotifications(true);
  }
  async onWillPresentModal() {
    this.popover.dismiss(null, "cancel");
    this.filteringForm = this.formBuilder.group({
      filter: [""],
      sort: [""],
    });
    await this.getAllNotifications();
  }
  async getAllNotifications() {
    this.showLoader = true;
    await this.http
      .get<Notification[]>(this.env.API_URL + `api/Job/GetJobUserNotifications`)
      .subscribe({
        next: (data) => {
          this.allNotifications = data["result"];
          this.allUsers = new Set(
            this.allNotifications.map((x) => x.user_name)
          );
          console.log(this.allUsers.values());
          this.filteringForm = this.formBuilder.group({
            filter: [Array.from(this.allUsers)],
            sort: [""],
          });
          this.showLoader = false;
        },
        error: (err) => {
          this.showLoader = false;
          console.log(err);
        },
      });
  }
  cancel() {
    this.modal.dismiss(null, "cancel");
  }
  async getNotifications(initial: boolean) {
    if (initial) {
      this.pageNo = 1;
    } else {
      this.pageNo++;
    }
    this.showLoader = true;
    await this.http
      .get<Notification[]>(
        this.env.API_URL +
          `api/Job/GetJobUserNotificationsPaged?pageNo=${this.pageNo}&pageSize=${this.pageSize}`
      )
      .subscribe({
        next: (data) => {
          if (initial) this.notifications = data["result"];
          else {
            console.log(data["result"], "result");
            let sizeBefore = this.notifications.length;
            this.notifications = this.notifications.concat(data["result"]);

            let sizeAfter = this.notifications.length;
            if (sizeBefore == sizeAfter) this.pageNo--;
          }
          this.showLoader = false;
          console.log(this.notifications);
        },
        error: (err) => {
          this.showLoader = false;
          console.log(err);
        },
      });
  }
  async ChooseRouting(notification: Notification) {
    if (notification.exception == 1) {
      this.openExceptionPage();
    } else {
      if (
        notification.expired == 0 ||
        (notification.expired == 1 && this.username == notification.user_name)
      ) {
        this.openLoanAppReview(
          notification.application_key,
          notification.client_type_code
        );
      } else {
        this.openWorkReassignment(
          notification.job_id,
          notification.user_name,
          notification.application_key
        );
      }
    }
  }
  async openLoanAppReview(
    applicationKey: string,
    clientTypeCode: string
  ): Promise<void> {
    this.router
      .navigate(["/field-review-workflow"], {
        queryParams: {
          applicationKey: applicationKey,
          clientTypeCode: clientTypeCode,
        },
      })
      .then(() => location.reload());
  }
  async openWorkReassignment(
    jobId: number,
    username: string,
    applicationKey: string
  ): Promise<void> {
    this.router
      .navigate(["/job-supervision"], {
        queryParams: {
          jobId: jobId,
          username: username,
          applicationKey: applicationKey,
        },
      })
      .then(() => location.reload());
  }

  async openExceptionPage(): Promise<void> {
    this.router
      .navigate(["/user-suspended-documents"])
      .then(() => location.reload());
  }
  notificationExpiry(notification: Notification): string {
    let expiryDate = new Date(notification.expiry_date);
    const trans = this.translate.instant(`generic.deadline`);
    return `${trans}: ${expiryDate.toLocaleDateString(
      this.currentLanguage
    )} ${expiryDate.toLocaleTimeString(this.currentLanguage)}`;
  }
  notificationDetails(notification: Notification): string {
    const trans = this.translate.instant(`loans.applicationcode`);
    const applicationKey = notification.application_key.padStart(15, "0");
    const fullApplicationCode = `${applicationKey
      .substring(2, 5)
      .replace(/^0+/, "")}/${applicationKey
      .substring(5, 12)
      .replace(/^0+/, "")}/${applicationKey.substring(12).replace(/^0+/, "")}`;
    return `${trans}: ${fullApplicationCode}`;
  }
  notificationLabel(notification: Notification): string {
    if (notification.exception == 0) {
      if (notification.expired == 1) {
        if (this.username == notification.user_name) {
          const trans = this.translate.instant(`notifications.loanAppExpired`);
          return trans;
        } else {
          const transUser = this.translate.instant(`users.user`);
          const transExpired = this.translate.instant(
            `notifications.userLoanAppExpired`
          );
          return `${transUser}: ${notification.user_name} ${transExpired}`;
        }
      } else {
        const trans = this.translate.instant(`notifications.loanAppReview`);
        return trans;
      }
    } else if (notification.exception == 1) {
      const trans = this.translate.instant(`notifications.loanSuspended`);
      return trans;
    }
  }
  async onIonInfinite(ev) {
    await this.getNotifications(false);
    console.log("here");
    (ev as InfiniteScrollCustomEvent).target.complete();
  }
  onWillDismiss() {
    this.isModalOpen = false;
  }
  handleChangeFilter(ev) {
    // console.log("Current value:", JSON.stringify(ev.target.value));
  }
  handleChangeSort(ev) {
    console.log("Current value:", JSON.stringify(ev.target.value));
    if (ev.target.value == "0") {
      this.allNotifications = this.allNotifications.sort((a, b) => {
        return (
          new Date(a.expiry_date).getTime() - new Date(b.expiry_date).getTime()
        );
      });
    } else {
      this.allNotifications = this.allNotifications.sort((a, b) => {
        return (
          new Date(b.expiry_date).getTime() - new Date(a.expiry_date).getTime()
        );
      });
    }
  }
  checkIfInControlValue(controlName: string, value) {
    return Array.from(this.filteringForm.controls[controlName].value).includes(
      value
    );
  }
  async getUserBranchInfo() {
    this.userInfoObject.userBranchInfo =
      await this.userService.getUserBranchInfo();
    this.userInfoObject.userBranches = (
      await this.userService.getUserBranches()
    ).filter((branch) => branch.branch_code.toString() != this.branchCode);
    if (this.userInfoObject.userBranchInfo) {
      this.showUserInfo = true;
      await Preferences.set({
        key: "periodStartDate",
        value: this.datePipe.transform(
          this.userInfoObject.userBranchInfo.period_start_date,
          "yyyy-MM-dd"
        ),
      });
      await Preferences.set({
        key: "periodEndDate",
        value: this.datePipe.transform(
          this.userInfoObject.userBranchInfo.period_end_date,
          "yyyy-MM-dd"
        ),
      });
    }
  }
  async changeBranch(event) {
    if (!event.target.value) return;
    if (!(await this.alertService.SaveAlert())) {
      this.changeBranchForm.patchValue({
        branchCode: null,
      });
      return;
    }
    try {
      this.showLoader = true;
      this.openLoader.emit();
      await this.userService.changeUserBranch(
        this.changeBranchForm.value.branchCode.toString()
      );
      this.showLoader = false;
      this.closeLoader.emit();
      this.alertService.showAlertConfirm("تم تغيير الفرع بنجاح", true);
    } catch (error) {
      this.showLoader = false;
      this.closeLoader.emit();
      this.changeBranchForm.patchValue({
        branchCode: null,
      });
      this.alertService.showAlertError("خطأ عند تغيير الفرع", false);
    }
  }

  async changeUserStatus(ev: any) {
    ev.stopImmediatePropagation();
    ev.preventDefault();
    if (ev.detail.value !== this.jobUserStatus) {
      const action = this.jobUserStatus ? "ايقاف" : "تفعيل";
      const confirm = await this.alertService.SaveAlert(
        `هل تريد ${action} المستخدم؟`
      );
      if (confirm) {
        this.showLoader = true;
        this.openLoader.emit();
        this.jobService
          .changeJobUserStatus()
          .then(() => {
            this.alertService.showAlertConfirm(
              `تم ${action} المستخدم بنجاح`,
              false
            );
            this.jobUserStatus = !this.jobUserStatus;
          })
          .catch((error) => {
            console.log(error);
            this.alertService.showAlertError(
              `خطأ في ${action} المستخدم: ${error.error}`,
              false
            );
            // Revert the toggle to previous state
            this.jobUserStatus = !!this.jobUserStatus;
          })
          .finally(() => {
            this.showLoader = false;
            this.closeLoader.emit();
          });
      } else {
        // Revert the toggle to previous state
        this.jobUserStatus = !!this.jobUserStatus;
      }
    }
  }
}
