import { HttpClient } from "@angular/common/http";
import { Injectable } from "@angular/core";
import { officerResponseModal } from "src/app/views/Models/Officer/Officer";
import { EnvService } from "./env.service";
import { Observable } from "rxjs";
import { catchError, map } from "rxjs/operators";
import {
  GetOfficerTargetHistoryRequest,
  GetOfficerTargetHistoryResponse,
} from "src/app/views/Models/Officer/OfficerTargets";
import { OfficersVisitsWorkFlow } from "src/app/views/Models/Officer/OfficerVisitsWorkFlow";
import {
  GetOfficersByBranchRequest,
  GetOfficersByBranchResponse,
} from "src/app/views/Models/Officer/GetOfficersByBranch";

@Injectable({
  providedIn: "root",
})
export class OfficerService {
  constructor(private env: EnvService, private http: HttpClient) {}

  getAllOfficers = (): Observable<officerResponseModal[]> => {
    return this.http
      .get<officerResponseModal[]>(
        `${this.env.API_URL}api/Officer/GetOfficersByORG`
      )
      .pipe(
        map((officers) => {
          return officers.map((officer) => ({
            ...officer,
            branch_code: Number(officer.branch_code),
            officer_key: Number(officer.officer_key),
            officer_code: Number(officer.officer_code),
          }));
        }),
        catchError((error) => {
          console.error("Error fetching getAllOfficers:", error);
          throw error;
        })
      );
  };
  getOfficerTargetHistory = (
    officersRequests: GetOfficerTargetHistoryRequest
  ): Observable<GetOfficerTargetHistoryResponse[]> => {
    return this.http.post<GetOfficerTargetHistoryResponse[]>(
      this.env.API_URL + "api/Officer/GetOfficerTargetHistory",
      {
        officer_key: officersRequests.officer_key,
        period_type: "2",
        target_start_date: officersRequests.target_start_date,
        target_end_date: officersRequests.target_end_date,
      }
    );
  };
  getOfficerVisitsWorkFlow = (
    applicationKey: string
  ): Observable<OfficersVisitsWorkFlow[]> => {
    return this.http.post<OfficersVisitsWorkFlow[]>(
      this.env.API_URL + `api/Officer/GetOfficerVisitsWorkFlow`,
      {
        application_key: applicationKey,
      }
    );
  };
  GetBranchOfficers = (
    request: GetOfficersByBranchRequest
  ): Observable<GetOfficersByBranchResponse[]> => {
    return this.http.get<GetOfficersByBranchResponse[]>(
      this.env.API_URL + "api/Officer/GetBranchOfficers",
      { params: { branch_code: request.branchCode } }
    );
  };
}
