import { Component, OnInit } from "@angular/core";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";

@Component({
  selector: "app-footer",
  templateUrl: "./footer.component.html",
  styleUrls: ["./footer.component.scss"],
})
export class FooterComponent implements OnInit {
  constructor(private authService: MohassilAuthService) {}

  orgName: string = "";
  year: string = "";

  async ngOnInit(): Promise<void> {
    let userInfo = await this.authService.getUserInfo();
    this.orgName = userInfo.org_name;
    this.year = new Date().getFullYear().toString();
  }
}
