import { Injectable } from "@angular/core";
import { RestoredListenerEvent } from "@capacitor/app";
// import { SecurestoragePlugin } from "capacitor-secure-storage-plugin";
import { ApplicationState } from "../models/ApplicationState";
import { Preferences } from "@capacitor/preferences";

@Injectable({
  providedIn: "root",
})
export class StateService {
  private readonly APP_STATE_KEY: string = "app_state";
  private readonly APP_RESTORED_RESULT_KEY: string = "app_stored_result";

  constructor() {}

  public async saveAppState(appState: ApplicationState): Promise<void> {
    try {
      let serializedState = JSON.stringify(appState);
      await Preferences.set({
        key: this.APP_STATE_KEY,
        value: serializedState,
      });
    } catch (err) {}
  }

  public async savePageState(uri: string, pageState: string): Promise<void> {
    try {
      let appState: ApplicationState = {
        uri: uri,
        state: pageState,
      };
      await this.saveAppState(appState);
    } catch (err) {}
  }

  public async getAppState(): Promise<ApplicationState> {
    try {
      let serializedState = await Preferences.get({
        key: this.APP_STATE_KEY,
      });
      let appState: ApplicationState = JSON.parse(
        serializedState.value
      ) as ApplicationState;
      return appState;
    } catch (err) {
      return null;
    }
  }

  public async getPageState(uri: string): Promise<string> {
    try {
      let appState = await this.getAppState();
      if (!!appState && appState.uri == uri) {
        return appState.state;
      } else {
        return null;
      }
    } catch (err) {
      return null;
    }
  }

  public async clearPageState(uri: string): Promise<void> {
    try {
      let appState = await this.getAppState();
      if (appState.uri == uri) {
        await Preferences.remove({
          key: this.APP_STATE_KEY,
        });
      }
    } catch (error) {}
  }

  public async saveAppRestoredResult(
    result: RestoredListenerEvent
  ): Promise<void> {
    try {
      let serializedResult = JSON.stringify(result);
      await Preferences.set({
        key: this.APP_RESTORED_RESULT_KEY,
        value: serializedResult,
      });
    } catch (err) {}
  }

  public async getAppRestoredResult(): Promise<RestoredListenerEvent> {
    try {
      let serializedResult = await Preferences.get({
        key: this.APP_RESTORED_RESULT_KEY,
      });
      let result: RestoredListenerEvent = JSON.parse(
        serializedResult.value
      ) as RestoredListenerEvent;
      return result;
    } catch (err) {
      return null;
    }
  }

  public async clearAppRestoredResult(): Promise<void> {
    try {
      await Preferences.remove({
        key: this.APP_RESTORED_RESULT_KEY,
      });
    } catch (err) {}
  }

  public serialize(state: any): string {
    return encodeURIComponent(JSON.stringify(state));
  }

  public deserialize(state: string): any {
    return JSON.parse(decodeURIComponent(state));
  }
}
