import {
  Component,
  ElementRef,
  EventEmitter,
  Input,
  OnInit,
  Output,
  ViewChild,
} from "@angular/core";
import { ActionSheetButton, ActionSheetController } from "@ionic/angular";
import {
  NgxGalleryAction,
  NgxGalleryComponent,
  NgxGalleryImage,
  NgxGalleryOptions,
} from "@kolkov/ngx-gallery";
import { ExportingService } from "src/app/core/services/exporting.service";
import { AlertService } from "src/app/core/services/alert.service";
import { CameraService } from "src/app/core/services/camera.service";
import { GetDocumentsByApplicationKey } from "../../Models/Documents/GetDocumentByApplicationKey";
import { PdfViewerService } from "src/app/core/services/pdf-viewer.service";
import { GetDocumentBySerialRequest } from "../../Models/Documents/GetDocumentBySerial";
import { DocumentService } from "src/app/core/services/document.service";

export interface ImagesAndPdfEditedDocumentsOutput {
  validation: {
    valid: boolean;
    errorMessage: string | null;
  };
  documentsInformation: {
    serial: number;
    pageNumber: number;
    imageBase64: string;
  }[];
}

@Component({
  selector: "app-images-and-pdf",
  templateUrl: "./images-and-pdf.component.html",
  styleUrls: ["./images-and-pdf.component.scss"],
})
export class ImagesAndPdfComponent implements OnInit {
  @ViewChild("printButt") printButt: ElementRef;
  @ViewChild("ngxGallery") ngxGallery: NgxGalleryComponent;

  @Input() applicationKey: number;
  @Input() userName: string;
  @Output() editedDocumentsChange =
    new EventEmitter<ImagesAndPdfEditedDocumentsOutput>();

  constructor(
    private actionSheetCtrl: ActionSheetController,
    private alertSerivce: AlertService,
    private cameraService: CameraService,
    private documentService: DocumentService,
    private exportingService: ExportingService,
    private pdfViewerService: PdfViewerService
  ) {}

  //#region variables
  galleryImages: NgxGalleryImage[];
  applicationDocuments: GetDocumentsByApplicationKey[];
  editedDocuments: ImagesAndPdfEditedDocumentsOutput = {
    validation: {
      valid: false,
      errorMessage: null,
    },
    documentsInformation: [],
  };
  galleryOptions: NgxGalleryOptions[];
  private _image: string | null = null;
  showLoader: boolean = false;
  //#endregion

  ngOnInit() {
    this.getApplicationDocuments();
    this.printElement = this.printElement.bind(this);
    this.initializeGalleryImages();
  }

  get image() {
    return this._image;
  }
  set image(image: string | null) {
    this._image = image;
  }
  get disableAccordion() {
    const haveDocuments: boolean = this.applicationDocuments?.length > 0;

    return !haveDocuments;
  }

  get countDocuments() {
    return this.applicationDocuments?.length | 0;
  }

  getApplicationDocuments() {
    this.documentService
      .getDocumentsForClientPerApplicationKey(
        this.applicationKey,
        this.userName
      )
      .subscribe((docs) => {
        this.applicationDocuments = docs;
        //#region  Putting This Here to tell the parent component if the document is valid or not.
        this.editedDocuments.validation =
          this.checkIfAllRequiredDocumentsAreUploaded();
        this.editedDocumentsChange.emit(this.editedDocuments);
        //#endregion
      });
  }

  printElement(): void {
    this.printButt.nativeElement.click();
  }
  initializeGalleryImages() {
    let galleryAction = <NgxGalleryAction>{
      icon: "fa fa-print",
      onClick: this.printElement,
    };

    this.galleryOptions = [
      {
        arrowPrevIcon: "fa fa-arrow-circle-o-left",
        arrowNextIcon: "fa fa-arrow-circle-o-right",
        closeIcon: "fa fa-window-close",
        // fullscreenIcon: "fa fa-arrows",
        spinnerIcon: "fa fa-refresh fa-spin fa-3x fa-fw",
        previewZoom: true,
        previewRotate: true,
        imageArrows: true,
        previewCloseOnEsc: true,
        previewCloseOnClick: true,
        previewAnimation: true,
        previewArrows: false,
        //change here to show the ngx-gallery | starts
        preview: false,
        previewBullets: false,
        thumbnails: false,
        imageSwipe: false,
        previewSwipe: false,
        previewKeyboardNavigation: false,
        // previewForceFullscreen: true,
        //change here to show the ngx-gallery | ends
        previewDownload: true,
        //previewBullets: true,
        // previewFullscreen: true,
        thumbnailsRows: 2,
        thumbnailsPercent: 40,
        imagePercent: 60,
        thumbnailMargin: 5,
        thumbnailsMargin: 5,
        imageSize: "contain",
        actions: [galleryAction],
      },
      {
        thumbnailsMoveSize: 4,
        breakpoint: 500,
        width: "300",
        height: "300",
        thumbnailsColumns: 3,
      },
      {
        breakpoint: 300,
        width: "100%",
        height: "200px",
        thumbnailsColumns: 2,
      },
    ];
  }

  extractGalleryImage(documentBase64, documentTypeDescription, documentDate) {
    const image = "data:image/jpeg;base64," + documentBase64;
    const imageUrls: NgxGalleryImage[] = [
      {
        small: image,
        medium: image,
        big: image,
        description: `نوع المستند: (${documentTypeDescription}) | تاريخ رفع المستند: (${documentDate.slice(
          0,
          10
        )})`,
      },
    ];

    return imageUrls;
  }

  async selectDocument(
    document: GetDocumentsByApplicationKey,
    selectedDocumentIndex: number
  ) {
    const selectedDocument =
      document.documentsInformation[selectedDocumentIndex];

    if (this.isDocumentExist(document.serial, selectedDocument.pageNumber)) {
      const documentImage = await this.getDocumentImage(
        document.serial,
        selectedDocument.pageNumber
      );
      this.image = documentImage;
      const base64Type = this.exportingService.getBase64Type(documentImage);

      await this.viewerHandler(
        document.serial,
        selectedDocument.pageNumber,
        base64Type === "application/pdf" ? "PDF" : "Image"
      );
    } else {
      this.image = null;
      await this.createActionSheet(
        "اضافة مستند",
        document.serial,
        selectedDocument.pageNumber
      );
    }
  }

  async uploadDocument(serial: number, pageNumber: number) {
    let capturePhotoResult = await this.cameraService.getPhoto();

    if (capturePhotoResult.success) {
      this.modifyEditedDocument(
        serial,
        pageNumber,
        capturePhotoResult.photo.base64String
      );

      const base64 = capturePhotoResult.photo.base64String;

      this.image = base64;
    } else {
      this.alertSerivce.showAlertError(capturePhotoResult.message, false);
    }
  }

  isDocumentExist(documentSerial: number, documentPageNumber: number): Boolean {
    const documentSummary = this.applicationDocuments.find(
      (x) => x.serial === documentSerial
    );
    if (!documentSummary) return false;

    const documentDetails = documentSummary.documentsInformation.find(
      (x) => x.pageNumber === documentPageNumber
    );

    const existingInDB = documentDetails.imageExist;

    const existingInEdits = this.editedDocuments.documentsInformation.some(
      (x) => x.pageNumber === documentPageNumber && x.serial === documentSerial
    );
    return existingInDB || existingInEdits;
  }
  getNumberOfImagesExist(documentSerial: number): number {
    const documentSummary = this.applicationDocuments.find(
      (x) => x.serial === documentSerial
    );
    let numberOfImagesExist: number = 0;
    documentSummary.documentsInformation.forEach((doc) => {
      numberOfImagesExist = this.isDocumentExist(documentSerial, doc.pageNumber)
        ? numberOfImagesExist + 1
        : numberOfImagesExist;
    });
    return numberOfImagesExist;
  }
  async getDocumentImage(
    documentSerial: number,
    documentPageNumber: number
  ): Promise<string> {
    const editedDocument = this.editedDocuments.documentsInformation.find(
      (x) => x.pageNumber === documentPageNumber && x.serial === documentSerial
    );

    // if the document is edited
    if (editedDocument) {
      return editedDocument.imageBase64;
    } else {
      // if the document is stored in database
      this.showLoader = true;
      let request: GetDocumentBySerialRequest = {
        docPageNumber: documentPageNumber,
        docSerial: documentSerial,
      };

      const image = await this.documentService
        .getDocumentBySerial(request)
        .toPromise();
      this.showLoader = false;
      return image.image;
    }
  }
  async viewerHandler(
    documentSerial: number,
    documentPageNumber: number,
    documentType: "PDF" | "Image"
  ) {
    const document = this.applicationDocuments.find(
      (x) => x.serial === documentSerial
    );
    const selectedDocument = document.documentsInformation.find(
      (x) => x.pageNumber === documentPageNumber
    );

    const header =
      documentType === "PDF"
        ? "ملفات العميل بصيغة PDF"
        : "ملفات العميل بصيغة PNG/JPEG";

    let buttons: ActionSheetButton[] = [];

    if (documentType === "PDF") {
      buttons.push({
        icon: "eye",
        handler: async () => {
          await this.pdfViewerService.viewPdf(
            this.image!,
            "مستندات العميل بصيغة PDF"
          );
        },
      });
    } else if (documentType === "Image") {
      buttons.push({
        icon: "eye",
        handler: () => {
          this.galleryImages = this.extractGalleryImage(
            this.image,
            document.documentTypeDescription,
            selectedDocument.imageDate
          );
          setTimeout(() => {
            this.ngxGallery.openPreview(0);
          }, 200);
        },
      });
    }

    await this.createActionSheet(
      header,
      documentSerial,
      documentPageNumber,
      buttons
    );
  }

  private async createActionSheet(
    header: string,
    documentSerial: number,
    documentPageNumber: number,
    additionalButtons: ActionSheetButton[] = []
  ) {
    const defaultButtons: ActionSheetButton[] = [
      {
        icon: "cloud-upload",
        handler: async () => {
          actionSheet.dismiss();
          await this.uploadDocument(documentSerial, documentPageNumber);
        },
        id: "uploadDocument",
      },
      {
        icon: "close",
        role: "cancel",
        cssClass: "danger",
        data: { action: "cancel" },
      },
    ];

    const buttons = [...additionalButtons, ...defaultButtons];

    const actionSheet = await this.actionSheetCtrl.create({
      header: header,
      mode: "ios",
      cssClass: "action-sheet",
      buttons: buttons,
    });
    await actionSheet.present();
  }
  modifyEditedDocument(serial: number, pageNumber: number, image: string) {
    let editedDocument = this.editedDocuments.documentsInformation.find(
      (x) => x.pageNumber === pageNumber && x.serial === serial
    );

    if (editedDocument) {
      this.editedDocuments.documentsInformation.find(
        (x) => x.pageNumber === pageNumber && x.serial === serial
      ).imageBase64 = image;
    } else {
      this.editedDocuments.documentsInformation.push({
        imageBase64: image,
        pageNumber: pageNumber,
        serial: serial,
      });
    }
    this.editedDocuments.validation =
      this.checkIfAllRequiredDocumentsAreUploaded();
    this.editedDocumentsChange.emit(this.editedDocuments);
  }

  checkIfAllRequiredDocumentsAreUploaded(): ImagesAndPdfEditedDocumentsOutput["validation"] {
    const missingDocument = this.applicationDocuments.find(
      (document) =>
        document.required && this.getNumberOfImagesExist(document.serial) === 0
    );

    return {
      valid: !missingDocument,
      errorMessage: missingDocument
        ? `يحب اضافة مستند: ${missingDocument.documentTypeDescription}`
        : null,
    };
  }
}
