import { Injectable } from "@angular/core";

import { Capacitor } from "@capacitor/core";
import {
  Camera,
  CameraResultType,
  GalleryImageOptions,
  ImageOptions,
  Photo,
} from "@capacitor/camera";
import {
  CameraResult,
  GalleryResult,
} from "../models/IntentResults/CameraResult";
import { AlertService } from "./alert.service";
import { NgxImageCompressService } from "ngx-image-compress";
import { ActionSheet, ActionSheetButtonStyle } from "@capacitor/action-sheet";
import { FilePicker } from "@capawesome/capacitor-file-picker";
import { ReferencesService } from "./references.service";

@Injectable({
  providedIn: "root",
})
export class CameraService {
  constructor(
    private alertSerivce: AlertService,
    private imageCompressService: NgxImageCompressService,
    private referencesService: ReferencesService
  ) {}

  private async checkCameraPermission(): Promise<boolean> {
    let { photos, camera } = await Camera.checkPermissions();
    return photos == "granted" && camera == "granted";
  }
  private async canAskForCameraPermission(): Promise<boolean> {
    let { photos, camera } = await Camera.checkPermissions();
    return photos != "denied" && camera != "denied";
  }
  private async requestCameraPermission(): Promise<boolean> {
    let granted: boolean = await this.checkCameraPermission();
    if (granted) {
      return true;
    } else {
      const canAskForPermission: boolean =
        await this.canAskForCameraPermission();
      if (canAskForPermission) {
        await Camera.requestPermissions();
        granted = await this.checkCameraPermission();
        if (granted) {
          return true;
        }
      }
    }
    return false;
  }
  public async getPhotoOCR(): Promise<CameraResult> {
    let result: CameraResult;
    try {
      if (Capacitor.getPlatform() != "web") {
        const permission = await this.requestCameraPermission();
        if (permission) {
          const options: ImageOptions = {
            resultType: CameraResultType.Base64,
            saveToGallery: true,
            quality: 90,
            correctOrientation: true,
          };
          let photo = await Camera.getPhoto(options);
          result = {
            success: true,
            message: "تم أخذ الصورة بنجاح",
            photo: photo,
          };
        } else {
          result = {
            success: false,
            message: "خطأ في سماحية الوصول للكاميرا",
          };
        }
      } else {
        result = {
          success: false,
          message: "لا يمكن اخذ صورة الا من خلال التطبيق",
        };
      }
    } catch (err) {
      result = {
        success: false,
        message: `خطأ عند أخذ الصورة<br>${JSON.stringify(err)}`,
      };
    } finally {
      return result;
    }
  }
  public async getPhoto(): Promise<CameraResult> {
    return await this.getCameraPhoto();
  }
  private async getFile(): Promise<CameraResult> {
    const files = await FilePicker.pickFiles({
      multiple: false,
      readData: true,
    });

    const file = files.files[0];

    if (file.size > 1024000) {
      return { success: false, message: "تخطى الملف الحجم المسموح" };
    }

    return {
      success: true,
      photo: {
        saved: true,
        format: file.mimeType,
        base64String: file.data,
      },
      isPhoto: false,
    };
  }
  private async getCameraPhoto(): Promise<CameraResult> {
    let result: CameraResult;
    try {
      let permission: boolean;
      if (Capacitor.getPlatform() === "web") {
        if (!(await this.isWebsiteCanUploadDocuments())) {
          result = {
            success: false,
            message: "لا يمكن اخذ صورة الا من خلال التطبيق",
          };
          return;
        }
      }

      if (Capacitor.getPlatform() != "web") {
        permission = await this.requestCameraPermission();
        if (!permission) {
          result = {
            success: false,
            message: "خطأ في سماحية الوصول للكاميرا",
          };
          return;
        }
      }
      const options: ImageOptions = {
        resultType: CameraResultType.Base64,
        saveToGallery: true,
        quality: 90,
      };
      let photo = await Camera.getPhoto(options);

      if (photo.format == "jpeg") {
        try {
          const compressedImageDataUrl =
            await this.imageCompressService.compressFile(
              "data:image/jpg;base64," + photo.base64String,
              this.imageCompressService.DOC_ORIENTATION.Default,
              undefined,
              25,
              720,
              720
            );

          const compressedImageBase64 =
            compressedImageDataUrl.split("base64,")[1];

          const compressedPhoto: Photo = {
            ...photo,
            base64String: compressedImageBase64,
          };
          result = {
            success: true,
            message: "تم أخذ الصورة بنجاح",
            photo: compressedPhoto,
            isPhoto: true,
          };
        } catch (error) {
          result = {
            success: true,
            message: "تم أخذ الصورة بنجاح",
            photo: photo,
            isPhoto: true,
          };
        }
      } else {
        result = {
          success: true,
          message: "تم أخذ الصورة بنجاح",
          photo: photo,
        };
      }
    } catch (err) {
      result = {
        success: false,
        message: `خطأ عند أخذ الصورة<br>${JSON.stringify(err)}`,
      };
    } finally {
      return result;
    }
  }
  async isWebsiteCanUploadDocuments(): Promise<boolean> {
    let canUpload: boolean;
    try {
      return (await this.referencesService.getStaticValueById(70)).value === "1"
        ? true
        : false;
    } catch (error) {
      canUpload = false;
    }
    return canUpload;
  }
}
