import { IBranch } from "src/app/views/Models/References/Branch";
import { ClientBranchInfo } from "./../../../core/models/Client/ClientBranchInfo";
import { HttpClient } from "@angular/common/http";
import {
  ChangeDetectorRef,
  Component,
  EventEmitter,
  Input,
  OnInit,
  Output,
} from "@angular/core";
import { FormBuilder, FormControl, FormGroup } from "@angular/forms";
import { ModalController } from "@ionic/angular";
import { OverlayEventDetail } from "@ionic/core";
import { EnvService } from "src/app/core/services/env.service";
import { User } from "../../Models/Permissions/User";
import { TranslateService } from "@ngx-translate/core";
import { UserService } from "src/app/core/services/user.service";
import { Preferences } from "@capacitor/preferences";
import { UserBranches } from "../../Models/Users/User";
import { UserInfo } from "src/app/core/models/UserInfo";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { first } from "rxjs/operators";
import { pagingService } from "src/app/core/services/paging.service";

@Component({
  selector: "app-user-search",
  templateUrl: "./user-search.component.html",
  styleUrls: ["./user-search.component.css"],
})
export class UserSearchComponent implements OnInit {
  @Input() resultType: number = 0; // 0 --> user search permissions  && 1 --> user search jobs
  @Input() jobId: number; // 0 --> user search permissions  && 1 --> user search jobs
  @Input() searchInitValue: string = null; // if you need to put a value in the searchinput
  @Input() applyInitialSelection: boolean = false; // if you need to put a value in the searchinput
  @Output() selectedUser: EventEmitter<User> = new EventEmitter();

  showLoader: boolean = false;

  userInfo: UserInfo;
  currentLanguage: string = localStorage.getItem("currentLanguage") || "en-GB";
  textDir: string = "ltr";

  users: User[] = [];
  branches: UserBranches[] = [{ branch_code: null, branch_name: "" }];

  sortTypes: string[] = [
    "لم يتم تحديد أي اختيار",
    "ترتيب تصاعديا",
    "ترتيب تنازلي",
  ];

  branchFilterVal: string;
  branchSortVal: string = "0";
  userSortVal: string = "0";

  initialLoad: boolean = true;
  noResults: boolean = false;

  SearchForm: FormGroup = this.formBuilder.group({
    search_input: new FormControl(
      this.searchInitValue ? this.searchInitValue : ""
    ),
  });
  SortForm: FormGroup = this.formBuilder.group([]);

  pageSize: number; // number of viewed results
  page = 1; // the page we are viewing
  resultsCount; // the nuber of results
  totalPages = 1; // calculate by the pageSize and resultcount this.totalPages = (Math.trunc(x) < (this.resultsCount/this.pageSize)) ? Math.trunc(x)+1:Math.trunc(x) ;

  constructor(
    private formBuilder: FormBuilder,
    private env: EnvService,
    private http: HttpClient,
    private modal: ModalController,
    public translate: TranslateService,
    private authService: MohassilAuthService,
    private userService: UserService,
    private pagingService: pagingService,
    private cdref: ChangeDetectorRef
  ) {}

  async ngOnInit() {
    this.userInfo = await this.authService.getUserInfo();
    this.pageSize = this.pagingService.getPageSizeFromLocalStorage();
    this.sortTypes = [
      await this.translate.get("generic.noSort").toPromise(),
      await this.translate.get("generic.sortAsc").toPromise(),
      await this.translate.get("generic.sortDesc").toPromise(),
    ];
    this.showLoader = true;
    this.translate.use(this.currentLanguage);
    this.translate.get(`languages.${this.currentLanguage}.dir`).subscribe({
      next: (dir) => {
        this.textDir = dir;
      },
      error: () => {
        this.textDir = "ltr";
      },
    });
    this.branchFilterVal = this.userInfo.branch_code;
    this.SortForm = this.formBuilder.group({
      branchFilter: new FormControl(this.branchFilterVal),
      branchSort: new FormControl(this.branchSortVal),
      userSort: new FormControl(this.userSortVal),
    });

    this.userService
      .getUserBranches()
      .then(async (result) => {
        if (result.length > 1)
          this.branches = [{ branch_name: "", branch_code: null }].concat(
            result
          );
        else this.branches = result;
        await this.getUsers();
        this.showLoader = false;
      })
      .catch((error) => {
        this.SortForm = this.formBuilder.group({
          branchFilter: new FormControl(),
          branchSort: new FormControl(),
          userSort: new FormControl(),
        });
        console.log(error.message);
        this.showLoader = false;
      });
  }

  ngAfterContentChecked(): void {
    this.cdref.detectChanges();
  }

  goLast() {
    if (this.page != this.totalPages) {
      this.page = this.totalPages;
    }
  }
  nextPage() {
    if (this.totalPages > this.page) {
      this.page++;
    }
  }
  prevPage() {
    if (this.page > 1) {
      this.page--;
    }
  }
  goFirst() {
    if (this.page != 1) {
      this.page = 1;
    }
  }
  changePage(newPage: number): void {
    this.page = newPage;
  }

  async getUsers(): Promise<void> {
    console.log(
      !this.branchFilterVal ? this.userInfo.branch_code : this.branchFilterVal
    );
    const body = {
      page: this.page == 0 ? 1 : this.page,
      pageSize: this.pageSize,
      searchString: this.SearchForm.controls.search_input.value,
      branchFilter: this.branchFilterVal,
      branchSort: this.branchSortVal,
      userSort: this.userSortVal,
      jobId: this.jobId,
    };
    console.log(body);
    this.showLoader = true;
    this.initialLoad = false;
    await this.http
      .post<any>(
        this.env.API_URL +
          `api/Search/SearchUsers?resultType=${this.resultType}`,
        body
      )
      .toPromise()
      .then((data) => {
        console.log(this.users, "users before");
        this.users = data.entities;
        console.log(this.users, data, "users after");
        this.resultsCount = data.totalCount;
        let x = data.totalCount / this.pageSize;
        this.totalPages =
          Math.trunc(x) < data.totalCount / this.pageSize
            ? Math.trunc(x) + 1
            : Math.trunc(x);
        if (this.users.length > 0) {
          if (
            this.users[0].user_name == this.searchInitValue &&
            this.applyInitialSelection
          ) {
            this.applyInitialSelection = false;
            this.userSelected(this.users[0]);
          }
          this.noResults = false;
        } else {
          this.noResults = true;
        }
      })
      .catch((err) => {
        console.log(err.message);
      })
      .finally(() => {
        this.showLoader = false;
      });
  }
  userSelected(user: User): void {
    this.selectedUser.emit(user);
  }
  get searchForm() {
    return this.SearchForm.controls;
  }
  get sortForm() {
    return this.SortForm.controls;
  }

  async confirm() {
    this.branchFilterVal = this.sortForm.branchFilter.value;
    this.branchSortVal = this.sortForm.branchSort.value;
    this.userSortVal = this.sortForm.userSort.value;
    console.log(this.sortForm);
    this.page = 1;
    await this.getUsers();
    this.modal.dismiss("", "confirm");
  }

  reset() {
    console.log(this.SortForm.controls);
    this.branchFilterVal = this.userInfo.branch_code;
    this.branchSortVal = "0";
    this.userSortVal = "0";
    this.sortForm.branchFilter.setValue(this.userInfo.branch_code);
    this.sortForm.branchSort.setValue("0");
    this.sortForm.userSort.setValue("0");
  }
}
