import {
  Component,
  EventEmitter,
  Input,
  OnDestroy,
  OnInit,
  Output,
} from "@angular/core";
import { ExportingService } from "src/app/core/services/exporting.service";

declare let PDFObject: any;

@Component({
  selector: "app-pdf-viewer",
  templateUrl: "./pdf-viewer.component.html",
  styleUrls: ["./pdf-viewer.component.scss"],
})
export class PdfViewerComponent implements OnInit, OnDestroy {
  @Input() title: string;
  @Input() pdfBase64: string;
  @Output() dismiss: EventEmitter<void> = new EventEmitter<void>();

  constructor(private exportingService: ExportingService) {}

  ngOnInit(): void {
    if (PDFObject.supportsPDFs) {
      // converting base64 into blob to view PDFs with large size(5mb<pdf)
      const blob = this.exportingService.changeBase64ToBlob(this.pdfBase64);
      const objectUrl = URL.createObjectURL(blob);

      PDFObject.embed(objectUrl, "#pdfContainer");
    }
  }

  ngOnDestroy(): void {
    this.title = undefined;
    this.pdfBase64 = undefined;
  }
}
