import { HttpClient } from "@angular/common/http";
import { Injectable } from "@angular/core";
import {
  GetActiveCategoryRequest,
  GetActiveCategoryResponse,
} from "src/app/views/Models/Vendor/ActiveCategory";
import {
  AddCategory,
  Category,
  DeleteCategory,
  EditCategory,
} from "src/app/views/Models/Vendor/category";
import {
  AssignItemsRequest,
  DeleteBranchItem,
  DuplicateContract,
  EditBranchItem,
  VendorBranchInfo,
  VendorBranchItem,
  VendorContract,
  VendorContractBranchRequest,
  VendorInfo,
} from "src/app/views/Models/Vendor/consumer";
import {
  AddItem,
  DeleteItem,
  EditItem,
  ItemInfo,
} from "src/app/views/Models/Vendor/item";
import {
  Vendor,
  VendorBranch,
  VendorSubCategoryItem,
} from "src/app/views/Models/Vendor/vendor.model";
import { EnvService } from "./env.service";
import { pagingService } from "./paging.service";

@Injectable({
  providedIn: "root",
})
export class VendorService {
  constructor(
    private http: HttpClient,
    private env: EnvService,
    private pagingService: pagingService
  ) {}

  getUserVendors = async (): Promise<Vendor[]> => {
    try {
      const response = await this.http
        .get<Vendor[]>(
          `${this.env.API_URL}api/Vendor/GetCurrentUserActiveVendors`
        )
        .toPromise();
      return response;
    } catch (error) {
      console.error("Error fetching User Active Vendors:", error);
      throw error;
    }
  };

  getUserVendorBranches = async (vendor: Vendor): Promise<VendorBranch[]> => {
    try {
      const response = await this.http
        .post<VendorBranch[]>(
          `${this.env.API_URL}api/Vendor/GetCurrentUserActiveVendorBranches`,
          vendor
        )
        .toPromise();
      return response;
    } catch (error) {
      console.error("Error fetching User Active Vendor Branches:", error);
      throw error;
    }
  };

  getSubItemsFromVendorBranch = async (
    branch: VendorBranch
  ): Promise<VendorSubCategoryItem[]> => {
    try {
      const response = await this.http
        .post<VendorSubCategoryItem[]>(
          `${this.env.API_URL}api/Vendor/GetSubItemsFromVendorBranch`,
          branch
        )
        .toPromise();
      return response;
    } catch (error) {
      console.error("Error fetching Branch SubItems:", error);
      throw error;
    }
  };

  getCategories = async (): Promise<Category[]> => {
    try {
      const response = await this.http
        .get<Category[]>(`${this.env.API_URL}api/Vendor/GetCategories`)
        .toPromise();
      return response;
    } catch (error) {
      console.error("Error fetching Categories:", error);
      throw error;
    }
  };

  addCategory = async (category: AddCategory) => {
    try {
      await this.http
        .post(`${this.env.API_URL}api/Vendor/AddCategory`, category)
        .toPromise();
    } catch (error) {
      console.error("Error Adding Category:", error);
      throw error;
    }
  };

  editCategory = async (category: EditCategory) => {
    try {
      await this.http
        .post(`${this.env.API_URL}api/Vendor/EditCategory`, category)
        .toPromise();
    } catch (error) {
      console.error("Error Editing Category:", error);
      throw error;
    }
  };

  deleteCategory = async (category: DeleteCategory) => {
    try {
      await this.http
        .post(`${this.env.API_URL}api/Vendor/DeleteCategory`, category)
        .toPromise();
    } catch (error) {
      console.error("Error Deleting Category:", error);
      throw error;
    }
  };

  getItems(catCode: number, seachTxt: string, page: number) {
    let pageSize = this.pagingService.getPageSizeFromLocalStorage();
    return this.http.get<ItemInfo>(
      `${this.env.API_URL}api/Vendor/GetItems?cat_code=${catCode}&page=${page}&pagesize=${pageSize}&search=${seachTxt}`,
      {}
    );
  }

  getActiveItems(seachTxt: string, page: number, leafCat: string) {
    let pageSize = this.pagingService.getPageSizeFromLocalStorage();
    return this.http.get<ItemInfo[]>(
      `${this.env.API_URL}api/Vendor/GetActiveItems?page=${page}&pagesize=${pageSize}&search=${seachTxt}&leafCat=${leafCat}`,
      {}
    );
  }

  addItem = async (item: AddItem): Promise<string> => {
    try {
      const response = await this.http
        .post(`${this.env.API_URL}api/Vendor/AddItem`, item)
        .toPromise();
      return response as string;
    } catch (error) {
      console.error("Error Adding Item:", error);
      throw error;
    }
  };

  editItem = async (item: EditItem): Promise<string> => {
    try {
      const respsone = await this.http
        .post(`${this.env.API_URL}api/Vendor/EditItem`, item)
        .toPromise();
      return respsone as string;
    } catch (error) {
      console.error("Error Editing item:", error);
      throw error;
    }
  };

  deleteItem = async (item: DeleteItem) => {
    try {
      await this.http
        .post(`${this.env.API_URL}api/Vendor/DeleteItem`, item)
        .toPromise();
    } catch (error) {
      console.error("Error Deleting Item:", error);
      throw error;
    }
  };

  getActiveVendors = async (): Promise<VendorInfo[]> => {
    try {
      const res = await this.http
        .get(`${this.env.API_URL}api/Vendor/V2/ActiveVendors`)
        .toPromise();
      return res as VendorInfo[];
    } catch (error) {
      console.error("Error Getting Active Vendors:", error);
      throw error;
    }
  };

  getVendorContracts = async (
    vendorCode: number
  ): Promise<VendorContract[]> => {
    try {
      const res = await this.http
        .get(
          `${this.env.API_URL}api/Vendor/V2/VendorContracts?vendorCode=${vendorCode}`
        )
        .toPromise();
      return res as VendorContract[];
    } catch (error) {
      console.error("Error Getting Vendor Contracts:", error);
      throw error;
    }
  };

  getActiveVendorContracts = async (
    vendorCode: number
  ): Promise<VendorContract> => {
    try {
      const res = await this.http
        .get(
          `${this.env.API_URL}api/Vendor/V2/ActiveVendorContracts?vendorCode=${vendorCode}`
        )
        .toPromise();
      return res as VendorContract;
    } catch (error) {
      console.error("Error Getting Active Vendor Contracts:", error);
      throw error;
    }
  };

  addVendorContract = async (vendor: VendorContract) => {
    try {
      await this.http
        .post(`${this.env.API_URL}api/Vendor/V2/AddVendorContract`, vendor)
        .toPromise();
    } catch (error) {
      console.error("Error Adding Vendor Contract:", error);
      throw error;
    }
  };

  editVendorContract = async (vendor: VendorContract) => {
    try {
      await this.http
        .post(`${this.env.API_URL}api/Vendor/V2/EditVendorContract`, vendor)
        .toPromise();
    } catch (error) {
      console.error("Error Editing Vendor Contract:", error);
      throw error;
    }
  };

  duplicateVendorContract = async (vendor: DuplicateContract) => {
    try {
      await this.http
        .post(
          `${this.env.API_URL}api/Vendor/V2/DuplicateVendorContract`,
          vendor
        )
        .toPromise();
    } catch (error) {
      console.error("Error Duplicating Vendor Contract:", error);
      throw error;
    }
  };

  getActiveVendorBranches = async (
    vendorCode: number
  ): Promise<VendorBranchInfo[]> => {
    try {
      const res = await this.http
        .get(`${this.env.API_URL}api/Vendor/V2/${vendorCode}/ActiveBranches`)
        .toPromise();
      return res as VendorBranchInfo[];
    } catch (error) {
      console.error("Error Getting Active Vendor Branches:", error);
      throw error;
    }
  };

  getActiveVendorContractBranches = async (
    vendorCode: number
  ): Promise<VendorBranchInfo[]> => {
    try {
      const res = await this.http
        .get(
          `${this.env.API_URL}api/Vendor/V2/${vendorCode}/ActiveContractBranches`
        )
        .toPromise();
      return res as VendorBranchInfo[];
    } catch (error) {
      console.error("Error Getting Active Vendor Contract Branches:", error);
      throw error;
    }
  };

  assignItemsToBranches = async (request: AssignItemsRequest) => {
    try {
      await this.http
        .post(`${this.env.API_URL}api/Vendor/V2/AssignItemsToBranches`, request)
        .toPromise();
    } catch (error) {
      console.error("Error Assigning Items To Branches:", error);
      throw error;
    }
  };

  getBranchItems(
    seachTxt: string,
    page: number,
    vendorCode: number,
    contractCode: number,
    vendorBrCode: number,
    categoryCode?: number
  ) {
    let pageSize = this.pagingService.getPageSizeFromLocalStorage();
    return this.http.get<VendorBranchItem>(
      `${this.env.API_URL}api/Vendor/GetBranchItems`,
      {
        params: {
          page: page,
          pagesize: pageSize,
          vendorCode: vendorCode,
          contractCode: contractCode,
          vendorBrCode: vendorBrCode,
          search: seachTxt,
          categoryCode: categoryCode || 0,
        },
      }
    );
  }

  editBranchItem = async (request: EditBranchItem) => {
    try {
      await this.http
        .post(`${this.env.API_URL}api/Vendor/V2/EditBranchItem`, request)
        .toPromise();
    } catch (error) {
      console.error("Error Editing Branch Item:", error);
      throw error;
    }
  };

  deleteBranchItem = async (request: DeleteBranchItem) => {
    try {
      await this.http
        .post(`${this.env.API_URL}api/Vendor/V2/DeleteBranchItem`, request)
        .toPromise();
    } catch (error) {
      console.error("Error Deleting Branch Item:", error);
      throw error;
    }
  };

  getActiveCategory = async (category: GetActiveCategoryRequest) => {
    try {
      const response = await this.http
        .get<GetActiveCategoryResponse[]>(
          `${this.env.API_URL}api/Vendor/V2/${category.vendorCode}/${category.vendorBranchCode}/Categories/${category.catCode}`
        )
        .toPromise();
      return response;
    } catch (error) {
      console.error("Error fetching User Active Category:", error);
      throw error;
    }
  };

  AddVendorContractBranch = async (request: VendorContractBranchRequest) => {
    try {
      await this.http
        .post(
          `${this.env.API_URL}api/Vendor/V2/AddVendorContractBranch`,
          request
        )
        .toPromise();
    } catch (error) {
      console.error("Error Add Vendor Contract Branch:", error);
      throw error;
    }
  };
}
