import { Injectable } from "@angular/core";
import { EnvService } from "./env.service";
import { HttpClient } from "@angular/common/http";
import {
  EbcBank,
  EbcBankBranch,
  EbcEligibleLoan,
  EbcPendingTransaction,
  EbcUndisbursedTransaction,
} from "src/app/views/Models/E-Disb/EgyptianBanksCompany";

@Injectable({
  providedIn: "root",
})
export class EDisbService {
  constructor(private env: EnvService, private http: HttpClient) {}

  public async getEbcEligibleLoans(
    bankKeys: string[],
    loanDateStart: Date,
    loanDateEnd: Date
  ): Promise<EbcEligibleLoan[]> {
    return await this.http
      .post<EbcEligibleLoan[]>(
        `${this.env.API_URL}api/EDisb/GetEbcEligibleLoans`,
        { bankKeys, loanDateStart, loanDateEnd }
      )
      .toPromise();
  }

  public async getActiveEbcBanks(): Promise<EbcBank[]> {
    return await this.http
      .get<EbcBank[]>(`${this.env.API_URL}api/EDisb/GetActiveEbcBanks`)
      .toPromise();
  }

  public async getActiveEbcBankBranches(
    bankId: number
  ): Promise<EbcBankBranch[]> {
    return await this.http
      .get<EbcBankBranch[]>(
        `${this.env.API_URL}api/EDisb/GetActiveEbcBankBranches?bankId=${bankId}`
      )
      .toPromise();
  }

  public async getEbcPendingTransactions(
    bankKeys: string[],
    loanDateStart: Date,
    loanDateEnd: Date
  ): Promise<EbcPendingTransaction[]> {
    return await this.http
      .post<EbcPendingTransaction[]>(
        `${this.env.API_URL}api/EDisb/GetEbcPendingTransactions`,
        { bankKeys, loanDateStart, loanDateEnd }
      )
      .toPromise();
  }

  public async getEbcFailedTransactions(
    bankKeys: string[],
    loanDateStart: Date,
    loanDateEnd: Date
  ): Promise<EbcPendingTransaction[]> {
    return await this.http
      .post<EbcPendingTransaction[]>(
        `${this.env.API_URL}api/EDisb/GetEbcFailedTransactions`,
        { bankKeys, loanDateStart, loanDateEnd }
      )
      .toPromise();
  }

  public async getEbcUndisbursedTransactions(
    bankKeys: string[],
    loanDateStart: Date,
    loanDateEnd: Date
  ): Promise<EbcUndisbursedTransaction[]> {
    return await this.http
      .post<EbcUndisbursedTransaction[]>(
        `${this.env.API_URL}api/EDisb/GetEbcUndisbursedTransactions`,
        { bankKeys, loanDateStart, loanDateEnd }
      )
      .toPromise();
  }

  public async getEbcCompletedTransactions(
    bankKeys: string[],
    loanDateStart: Date,
    loanDateEnd: Date
  ): Promise<EbcUndisbursedTransaction[]> {
    return await this.http
      .post<EbcUndisbursedTransaction[]>(
        `${this.env.API_URL}api/EDisb/GetEbcCompletedTransactions`,
        { bankKeys, loanDateStart, loanDateEnd }
      )
      .toPromise();
  }

  public async sendEbcTransactions(loanKeys: string[]): Promise<void> {
    await this.http
      .post(`${this.env.API_URL}api/EDisb/SendEbcTransactions`, {
        loanKeys,
      })
      .toPromise();
  }

  public async disburseEbcTransactions(
    transactionIds: number[]
  ): Promise<void> {
    await this.http
      .post(`${this.env.API_URL}api/EDisb/DisburseEbcTransactions`, {
        transactionIds,
      })
      .toPromise();
  }
}
