  getWorkFlowApplications = async (
    nation_id: string
  ): Promise<WorkFlowApp[]> => {
    try {
      const response = await this.http
        .post<WorkFlowApp[]>(
          `${this.env.API_URL}api/LoanApplications/GetWorkFlowApplications`,
          {
            nation_id: nation_id,
          }
        )
        .toPromise();
      return response;
    } catch (error) {
      console.error("Error fetching getAllLoansType:", error);
      throw error;
    }
  };

