import { Component, Input, OnInit } from "@angular/core";
import { FormGroup } from "@angular/forms";

export interface ValidationInput {
  showError: boolean;
  formGroup: FormGroup;
  formControlName: string;
}

@Component({
  selector: "html-validations",
  templateUrl: "./html-validations.component.html",
  styleUrls: ["./html-validations.component.css"],
})
export class HtmlValidationsComponent implements OnInit {
  @Input() validationInput: ValidationInput;
  constructor() {}

  ngOnInit() {}

  getFormControlErrors(
    formGroup: FormGroup,
    formControlName: string
  ): {
    hasError: boolean;
    errorMessage: string;
  } {
    const control = formGroup.controls[formControlName];
    return {
      hasError: !control.valid,
      errorMessage: control.errors?.errorMessage || "",
    };
  }
}
