import { BrowserModule } from "@angular/platform-browser";
import { NgModule } from "@angular/core";
import { BrowserAnimationsModule } from "@angular/platform-browser/animations";

import { AppRoutingModule } from "./app-routing.module";

import { LayoutModule } from "./views/layout/layout.module";
// import { AuthGuard } from "./core/guard/auth.guard";

import { AppComponent } from "./app.component";
import { ErrorPageComponent } from "./views/pages/error-page/error-page.component";
import {
  CameraPreview,
  CameraPreviewPictureOptions,
  CameraPreviewOptions,
  CameraPreviewDimensions,
} from "@awesome-cordova-plugins/camera-preview/ngx";
import { ScreenOrientation } from "@awesome-cordova-plugins/screen-orientation/ngx";
import { HIGHLIGHT_OPTIONS } from "ngx-highlightjs";
import { IonicModule } from "@ionic/angular";
import { FormsModule, ReactiveFormsModule } from "@angular/forms";
import { AuthModule } from "./views/pages/auth/auth.module";
import { HttpClient, HttpClientModule } from "@angular/common/http";
import { ComponentsModule } from "./views/components/components.module";
import { EnvServiceProvider } from "./core/services/env.service.provider";
import { SamplePagesPage } from "./views/pages/sample-pages/sample-pages.page";
import { SamplePagesPageModule } from "./views/pages/sample-pages/sample-pages.module";
import { WebIntent } from "@awesome-cordova-plugins/web-intent/ngx";
import { DatePipe, CommonModule } from "@angular/common";
import { AuthenticationInterceptorProvider } from "./core/interceptors/authentication.interceptor";

import { CallNumber } from "@ionic-native/call-number/ngx";
import { Clipboard } from "@awesome-cordova-plugins/clipboard/ngx";
import { EmailComposer } from "@awesome-cordova-plugins/email-composer/ngx";
import { TranslateLoader, TranslateModule } from "@ngx-translate/core";
import { TranslateHttpLoader } from "@ngx-translate/http-loader";
import { NgxGalleryModule } from "@kolkov/ngx-gallery";
import { NgxPrintModule } from "ngx-print";

// import {
//   AuthInterceptor,
//   authInterceptorProviders,
// } from "./core/services/auth.interceptor";

@NgModule({
  declarations: [AppComponent, ErrorPageComponent],
  imports: [
    NgxPrintModule,
    BrowserModule,
    HttpClientModule,
    FormsModule,
    AppRoutingModule,
    BrowserAnimationsModule,
    LayoutModule,
    ComponentsModule,
    SamplePagesPageModule,
    IonicModule.forRoot(),
    CommonModule,
    ReactiveFormsModule,
    TranslateModule.forRoot({
      defaultLanguage: "en-GB",
      loader: {
        provide: TranslateLoader,
        useFactory: createTranslateLoader,
        deps: [HttpClient],
      },
    }),
    NgxGalleryModule,
  ],
  providers: [
    CallNumber,
    Clipboard,

    EnvServiceProvider,
    {
      provide: HIGHLIGHT_OPTIONS, // https://www.npmjs.com/package/ngx-highlightjs
      useValue: {
        coreLibraryLoader: () => import("highlight.js/lib/core"),
        languages: {
          xml: () => import("highlight.js/lib/languages/xml"),
          typescript: () => import("highlight.js/lib/languages/typescript"),
          scss: () => import("highlight.js/lib/languages/scss"),
        },
      },
    },
    EmailComposer,
    WebIntent,
    DatePipe,
    AuthenticationInterceptorProvider,
    CameraPreview,
    ScreenOrientation,
    // authInterceptorProviders,
    // AuthGuard,
  ],
  bootstrap: [AppComponent],
})
export class AppModule {}

export function createTranslateLoader(http: HttpClient) {
  return new TranslateHttpLoader(http, "./assets/i18n/", ".json");
}
