import { MenuItem, PageType } from "./../../views/layout/sidebar/menu.model";
import { Injectable } from "@angular/core";
import {
  ActivatedRouteSnapshot,
  CanActivate,
  Router,
  RouterStateSnapshot,
} from "@angular/router";
import { MohassilAuthService } from "../services/AuthenticationServices/mohassil-auth.service";
import { MENU } from "../../views/layout/sidebar/menu";
import { flattenMenu } from "../util/menu-utilities";
import { AccessRight } from "src/app/views/Models/Permissions/AccessRight";

@Injectable({
  providedIn: "root",
})
export class AuthenticationGuard implements CanActivate {
  constructor(
    private authService: MohassilAuthService,
    private router: Router
  ) {}

  readonly allowedUrls: string[] = ["/home"];
  readonly fallbackUrl: string = "/home";

  async canActivate(
    route: ActivatedRouteSnapshot,
    state: RouterStateSnapshot
  ): Promise<boolean> {
    // Check for authentication

    const isAccessTokenPresent = await this.authService.isAccessTokenPresent();

    if (!isAccessTokenPresent) {
      await this.authService.logOut();
      return false;
    }

    const isAccessTokenExpired = await this.authService.isAccessTokenExpired();

    if (isAccessTokenExpired) {
      const refreshTokenResult = await this.authService.refreshToken();

      if (!refreshTokenResult) {
        await this.authService.logOut();
        return false;
      }
    }

    // Here, user is authenticated, check for authorization

    const url = state.url.split("?")[0];

    if (this.allowedUrls.includes(url)) {
      return true;
    }

    const { head_office } = await this.authService.getUserInfo();
    const accessRights = await this.authService.getAccessRights();

    const filterBranchAccess = (
      item: MenuItem,
      headOffice: string
    ): boolean => {
      return (
        (item.pageType === PageType.HeadOffice && headOffice === "1") ||
        (item.pageType === PageType.Branch && headOffice === "0") ||
        item.pageType === PageType.HeadOfficeAndBranch
      );
    };

    const menuItem = flattenMenu(MENU)
      .filter((item) => !item.hidden)
      .filter((item) => filterBranchAccess(item, head_office))
      .find((item) => item.link === url);

    if (!menuItem) {
      this.router.navigate([this.fallbackUrl]);
      return false;
    }

    const checkForPermission = async (
      accessRights: AccessRight[],
      windowCodes?: string[]
    ): Promise<boolean> => {
      if (!windowCodes || windowCodes.length === 0) {
        return true;
      }

      return accessRights
        .map((accessRight) => accessRight.window_code)
        .some((accessRightWindowCode) =>
          windowCodes.includes(accessRightWindowCode)
        );
    };

    const hasPermission = await checkForPermission(
      accessRights,
      menuItem.windowCode
    );

    if (!hasPermission) {
      this.router.navigate([this.fallbackUrl]);
      return false;
    }

    return true;
  }
}
