import { animate, style, transition, trigger } from "@angular/animations";
import { HttpErrorResponse } from "@angular/common/http";
import {
  Component,
  EventEmitter,
  Input,
  OnInit,
  Output,
  ViewChild,
} from "@angular/core";
import { IonInput, IonModal } from "@ionic/angular";
import { AlertService } from "src/app/core/services/alert.service";

import { FormBuilder, FormGroup } from "@angular/forms";
import { GetApplicationItemsRequest } from "src/app/core/models/LoanApplication/GetApplicationItems";
import { LoanApplicationsService } from "src/app/core/services/loan-applications.service";
import { VendorService } from "src/app/core/services/vendor.service";
import {
  GetActiveCategoryRequest,
  GetActiveCategoryResponse,
} from "../../Models/Vendor/ActiveCategory";
import { VendorBranchItem, VendorContract } from "../../Models/Vendor/consumer";

enum State {
  categoryList,
  itemList,
  itemDetail,
}
enum PageActions {
  adding,
  editing,
  display,
}

interface CartItem {
  itemName: string;
  itemCode: number;
  originalPrice: number;
  updatedPrice: number;
  fundPrice: number;
  quantity: number;
  totalPrice: number;
}

export interface VendorItemOutput {
  itemName: string;
  itemCode: number;
  itemPrice: number;
  fundPrice: number;
  quantity: number;
  totalPrice: number;
}

@Component({
  selector: "app-vendor-items",
  templateUrl: "./vendor-items.component.html",
  styleUrls: ["./vendor-items.component.scss"],
  animations: [
    // Smooth Slide-in Animation from Left
    trigger("slideIn", [
      transition(":enter", [
        style({ opacity: 0, transform: "translateX(-100%)" }), // Start from left
        animate(
          "1000ms ease-out",
          style({ opacity: 1, transform: "translateX(0)" })
        ),
      ]),
      transition(":leave", [
        animate(
          "200ms ease-in",
          style({ opacity: 0, transform: "translateX(100%)" }) // Exit to right
        ),
      ]),
    ]),

    // Appear from Left Animation (for subcategories)
    trigger("appearFromLeft", [
      transition(":enter", [
        style({ opacity: 0, transform: "translateX(-100%)" }), // Start from left
        animate(
          "1000ms ease-out",
          style({ opacity: 1, transform: "translateY(0)" })
        ),
      ]),
    ]),
  ],
})
export class VendorItemsComponent implements OnInit {
  categories: GetActiveCategoryResponse[] = [];
  breadCrumbs: GetActiveCategoryResponse[] = [];
  constructor(
    private alertService: AlertService,
    private vendorService: VendorService,
    private formBuilder: FormBuilder,
    private loanApplicationService: LoanApplicationsService
  ) {
    // Apply debounce logic
  }
  @ViewChild("searchBranchItemInput") searchBranchItemInput: IonInput;
  @ViewChild(IonModal) modal: IonModal;
  @Input() vendorCode: number;
  @Input() vendorBranchCode: number;
  @Input() applicationKey?: string;
  @Input() set displayOnly(value: boolean) {
    this._displayOnly = value;
    this.modifyPageAction();
  }
  @Output() vendorItemOutput: EventEmitter<VendorItemOutput[]> =
    new EventEmitter();

  private _displayOnly: boolean = false;

  get displayOnly() {
    return this._displayOnly;
  }

  isCartOpen: boolean = false; // Track whether the cart is open or closed

  isExpanded: boolean = false;

  cartItem: CartItem[] = []; // Stores cart items

  searchTerm: string = "";
  filteredCategories: GetActiveCategoryResponse[] = [];
  // cartTotal: any;
  selectedItemIndex: number | null = null; // Store the index of the item being edited
  isPriceChangeEnabled: boolean = false; // Toggle for "تغير السعر"
  moreRight: string = "<";
  moreLeft: string = ">";
  selectedCategory: GetActiveCategoryResponse = null;
  selectedItem: VendorBranchItem = null;
  vendorContract: VendorContract;
  noResults: boolean = false;

  lastAction: string = "";
  isModalOpen = false;
  items: VendorBranchItem[];
  State = State;
  currentViewState: State = State.categoryList;
  itemPage: number = 1;
  itemsCount: number = 0;
  branchItemsSearchTerm: string = "";
  savedBranchItemsSearchTerm: string = "";
  componentModal: boolean = false;
  showLoader: boolean = false;
  pageActions = PageActions;
  currentPageActions: PageActions = PageActions.adding;
  itemModalForm: FormGroup = this.formBuilder.group({
    changePriceFlag: [false],
    updatedPrice: [0],
    fundedPrice: [0],
    quantity: [1],
  });

  async ngOnInit() {
    this.vendorContract = await this.vendorService.getActiveVendorContracts(
      this.vendorCode
    );
    this.loadCategories();
    this.modifyPageAction();
    if (this.applicationKey) {
      await this.addingApplicationItemsIntoCart(this.applicationKey);
      const itemToSave: VendorItemOutput[] = this.cartItem.map((item) => ({
        itemName: item.itemName,
        itemCode: item.itemCode,
        itemPrice: item.updatedPrice,
        fundPrice: item.fundPrice,
        quantity: item.quantity,
        totalPrice: item.fundPrice * item.quantity,
      }));

      this.vendorItemOutput.emit(itemToSave);
    }
  }

  increaseQuantity() {
    const currentQuantity = this.itemModalForm.get("quantity").value;
    this.itemModalForm.patchValue({ quantity: currentQuantity + 1 });
    this.lastAction = "increase";
  }

  decreaseQuantity() {
    const currentQuantity = this.itemModalForm.get("quantity").value;

    if (currentQuantity >= 1) {
      this.itemModalForm.patchValue({ quantity: currentQuantity - 1 });
      this.lastAction = "decrease";
    }
  }

  async removeFromCart(index: number) {
    try {
      const confirm = await this.alertService.SaveAlert(
        "هل أنت متأكد أنك تريد حذف هذا المنتج من السلة؟"
      );

      if (confirm === true) this.cartItem.splice(index, 1);
    } catch (error) {
      await this.alertService.showAlertError(
        `خطأ أثناء حذف العنصر: ${error.message}`,
        false
      );
    }
  }

  // Function to increase quantity of an item in the cart
  increaseCartItemQuantity(item: CartItem) {
    let indexToUpdate = this.getIndexOfItem(item);

    this.cartItem[indexToUpdate].quantity++;

    this.cartItem[indexToUpdate].totalPrice =
      this.cartItem[indexToUpdate].fundPrice *
      this.cartItem[indexToUpdate].quantity;
  }

  // Function to decrease quantity of an item in the cart
  decreaseCartItemQuantity(item: CartItem) {
    let indexToUpdate = this.getIndexOfItem(item);

    this.cartItem[indexToUpdate].quantity--;

    this.cartItem[indexToUpdate].totalPrice =
      this.cartItem[indexToUpdate].fundPrice *
      this.cartItem[indexToUpdate].quantity;
  }

  getIndexOfItem(item: CartItem): number {
    return this.cartItem.findIndex(
      (i) =>
        i.itemCode === item.itemCode &&
        i.updatedPrice === item.updatedPrice &&
        i.fundPrice === item.fundPrice
    );
  }

  async saveItem() {
    if (this.cartItem.length === 0)
      return this.alertService.InfoAlert("لا يوجد عنصر لحفظه.", false);

    const itemToSave: VendorItemOutput[] = this.cartItem.map((item) => ({
      itemName: item.itemName,
      itemCode: item.itemCode,
      itemPrice: item.updatedPrice,
      fundPrice: item.fundPrice,
      quantity: item.quantity,
      totalPrice: item.totalPrice,
    }));
    console.log("2itemToSave", itemToSave);
    this.vendorItemOutput.emit(itemToSave);
    this.componentModal = false;
  }

  validateItem(): boolean {
    let isValid = true;
    let inputs = {
      updatedPrice: this.itemModalForm.get("updatedPrice").value,
      fundPrice: this.itemModalForm.get("fundedPrice").value,
      quantity: this.itemModalForm.get("quantity").value,
    };

    if (!(inputs.quantity >= 0)) {
      this.alertService.InfoAlert("الكمية يجب أن تكون أكبر من 0", false);
      isValid = false;
    } else if (inputs.fundPrice > inputs.updatedPrice) {
      this.alertService.InfoAlert(
        "السعر التمويلي يجب ان يكون اقل من سعر المنتج",
        false
      );
      isValid = false;
    } else if (inputs.updatedPrice < 0) {
      this.alertService.InfoAlert("سعر المنتج غير صحيح", false);
      isValid = false;
    } else if (inputs.fundPrice < 0) {
      this.alertService.InfoAlert("السعر التمويلي غير صحيح", false);
      isValid = false;
    }
    return isValid;
  }

  addToCart() {
    if (!this.validateItem()) return;

    let inputs = {
      updatedPrice: this.itemModalForm.get("updatedPrice").value,
      fundPrice: this.itemModalForm.get("fundedPrice").value,
      quantity: this.itemModalForm.get("quantity").value,
    };

    const item: CartItem = {
      fundPrice: inputs.fundPrice,
      itemName: this.selectedItem.itemName,
      itemCode: this.selectedItem.itemCode,
      originalPrice: this.selectedItem.itemPrice,
      updatedPrice: inputs.updatedPrice,
      quantity: inputs.quantity,
      totalPrice: inputs.fundPrice * inputs.quantity,
    };

    let indexToUpdate = this.getIndexOfItem(item);

    if (indexToUpdate !== -1) {
      this.cartItem[indexToUpdate] = {
        ...this.cartItem[indexToUpdate],
        quantity: this.cartItem[indexToUpdate].quantity + item.quantity,
        totalPrice:
          this.cartItem[indexToUpdate].totalPrice +
          item.fundPrice * item.quantity,
      };
    } else {
      this.cartItem.push(item);
    }

    this.onWillDismiss(); // Close modal after adding
  }

  async onCategorySelected(category: GetActiveCategoryResponse) {
    try {
      this.selectedCategory = category;
      if (category.leafCategory === 1) {
        await this.selectItem(category.rootCategoryCode);
        this.currentViewState = State.itemList;
        return;
      }
      this.manageBreadCrumbs(category);
      this.categories = await this.getCategories(category.rootCategoryCode);
      this.filteredCategories = this.categories;
      this.searchTerm = "";
    } catch (error) {
      this.handleError(error);
    }
  }

  async loadCategories() {
    try {
      this.showLoader = true;
      this.categories = await this.getCategories(0);
      this.filteredCategories = this.categories;
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }

  async getCategories(categoryCode: number) {
    const request: GetActiveCategoryRequest = {
      catCode: categoryCode,
      vendorCode: this.vendorCode,
      vendorBranchCode: this.vendorBranchCode,
    };

    return await this.vendorService.getActiveCategory(request);
  }

  async getItems(categoryCode: number) {
    try {
      this.showLoader = true;
      let result: VendorBranchItem[] = [];

      const res = await this.vendorService
        .getBranchItems(
          this.branchItemsSearchTerm,
          this.itemPage,
          this.vendorCode,
          this.vendorContract[0].vendContractCode,
          this.vendorBranchCode,
          categoryCode
        )
        .toPromise();

      this.itemsCount = res["count"];
      result = res["result"];
      this.items = result;
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }

  async searchBranchItems() {
    this.branchItemsSearchTerm = this.searchBranchItemInput.value.toString();
    if (this.savedBranchItemsSearchTerm != this.branchItemsSearchTerm)
      this.itemPage = 1;
    await this.getItems(this.selectedCategory.rootCategoryCode);
  }

  manageBreadCrumbs(category: GetActiveCategoryResponse) {
    if (
      !this.breadCrumbs.some(
        (cat) => cat.rootCategoryCode === category.rootCategoryCode
      )
    ) {
      this.breadCrumbs.push(category);
      return;
    }

    if (this.breadCrumbs.indexOf(category) + 1 < this.breadCrumbs.length) {
      this.breadCrumbs = this.breadCrumbs.slice(
        0,
        this.breadCrumbs.indexOf(category) + 1
      );
      return;
    }
  }

  changeItemPage = async (newPage: number) => {
    this.itemPage = newPage;
    await this.getItems(this.selectedCategory.rootCategoryCode);
  };

  onSearchInput(searchInput: any) {
    this.searchTerm = searchInput.target.value.trim(); // Update search term

    const searchLower = this.searchTerm.toLowerCase();

    this.filteredCategories = this.categories.filter((item) =>
      item.categoryName.toLowerCase().includes(searchLower)
    );

    // Show "no results" message if nothing found
    if (this.filteredCategories.length === 0) {
      this.noResults = true;
      setTimeout(() => {
        this.noResults = false;
      }, 3000); // Hide after 3 seconds
    } else {
      this.noResults = false;
    }
  }

  async selectItem(categoryCode: number) {
    await this.getItems(categoryCode);

    this.lastAction = ""; // Reset animation state
  }

  async goHome() {
    if (this.breadCrumbs.length === 0) return;
    this.selectedItem = null;
    this.selectedCategory = null;
    this.categories = [];
    this.breadCrumbs = [];
    this.items = [];
    this.itemPage = 1;
    this.itemsCount = 0;
    this.branchItemsSearchTerm = "";
    this.savedBranchItemsSearchTerm = "";
    await this.loadCategories();
    this.currentViewState = State.categoryList;
  }

  async goToCategory(category: GetActiveCategoryResponse) {
    const breadCrumbsLength = this.breadCrumbs.length;

    if (
      this.currentViewState === State.categoryList &&
      this.breadCrumbs[breadCrumbsLength - 1].rootCategoryCode ===
        category.rootCategoryCode
    )
      return;

    this.selectedItem = null; // Reset item
    this.categories = []; // Clear categories

    this.items = [];

    this.itemPage = 1;
    this.itemsCount = 0;
    this.branchItemsSearchTerm = "";
    this.savedBranchItemsSearchTerm = "";

    this.manageBreadCrumbs(category);

    await this.onCategorySelected(category); // Load new category
    this.currentViewState = State.categoryList;
  }

  // Function to toggle cart visibility
  showCartCard(visible: boolean) {
    this.isCartOpen = visible;
  }

  // Function to calculate total price of all items in the cart
  getTotalCartPrice(): number {
    return this.cartItem.reduce(
      (sum, item) => sum + item.fundPrice * item.quantity,
      0
    );
  }

  getTotalItemPrice(): number {
    let inputs = {
      updatedPrice: this.itemModalForm.get("updatedPrice").value,
      fundPrice: this.itemModalForm.get("fundedPrice").value,
      quantity: this.itemModalForm.get("quantity").value,
    };
    return inputs.fundPrice * inputs.quantity;
  }

  onItemSelect(item: VendorBranchItem) {
    this.selectedItem = item;
    this.itemModalForm.patchValue({
      updatedPrice: item.itemPrice,
      fundedPrice: item.fundedPrice,
      quantity: 1,
      changePriceFlag: false,
    });
    this.isPriceChangeEnabled = false;
    this.currentViewState = State.itemDetail;
    this.isModalOpen = true;
  }

  onWillDismiss() {
    this.isModalOpen = false;
    this.currentViewState = State.itemList;
  }

  get limitedText() {
    const itemDesc = this.selectedItem?.itemDesc || "";
    return itemDesc.split(" ").slice(0, 10).join(" ") + "..."; // Show first 10 words
  }

  private handleError(error: unknown) {
    const errorMessage =
      error instanceof HttpErrorResponse
        ? JSON.stringify(error.error)
        : error instanceof Error
        ? error.message
        : String(error);

    this.alertService.showAlertError(errorMessage, false);
    console.error("Error:", error);
  }

  showComponentModal(visible: boolean) {
    this.componentModal = visible;
  }
  async addingApplicationItemsIntoCart(applicationKey: string) {
    try {
      this.showLoader = true;
      const itemsResult = await this.getApplicationItems(applicationKey);
      this.cartItem = itemsResult.map((item) => ({
        itemName: item.itemName,
        itemCode: item.itemCode,
        originalPrice: item.itemPrice,
        updatedPrice: item.itemPrice,
        fundPrice: item.fundedPrice,
        quantity: item.quantity,
        totalPrice: item.fundedPrice * item.quantity,
      }));
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }

  async getApplicationItems(applicationKey: string) {
    const request: GetApplicationItemsRequest = {
      applicationKey: applicationKey,
    };

    return await this.loanApplicationService
      .getApplicationItems(request)
      .toPromise();
  }
  modifyPageAction() {
    if (!this.applicationKey) {
      this.currentPageActions = PageActions.adding;
    }
    if (this.applicationKey) {
      this.currentPageActions = PageActions.editing;
    }
    if (this.applicationKey && this.displayOnly) {
      this.currentPageActions = PageActions.display;
      this.showCartCard(true);
      this.addingApplicationItemsIntoCart(this.applicationKey);
    }
  }
}
