import { HttpClient } from "@angular/common/http";
import { Injectable } from "@angular/core";
import { EnvService } from "./env.service";
import { Document } from "src/app/views/Models/Documents/Document";
import { DocumentType } from "src/app/views/Models/Documents/DocumentType";
import { AlertService } from "./alert.service";
import { Observable } from "rxjs";
import { GetDocumentsByClientKey } from "src/app/views/Models/Documents/GetDocumentByClientKey";
import { GetDocumentsByApplicationKey } from "src/app/views/Models/Documents/GetDocumentByApplicationKey";
import {
  GetDocumentBySerialRequest,
  GetDocumentBySerialResponse,
} from "src/app/views/Models/Documents/GetDocumentBySerial";

@Injectable({
  providedIn: "root",
})
export class DocumentService {
  constructor(
    private env: EnvService,
    private http: HttpClient,
    private alertService: AlertService
  ) {}
  currentDocument: Document;
  addingDocument = async (
    documentTypeCode: string,
    clientKey: string
  ): Promise<Document> => {
    try {
      this.currentDocument = await this.http
        .post<Document>(`${this.env.API_URL}api/Documents/InsertDocument`, {
          documentTypeCode: documentTypeCode,
          clientKey: clientKey,
        })
        .toPromise();
      return this.currentDocument;
    } catch (error) {
      console.error("Error addingDocument:", error);
      throw error;
    }
  };

  uploadPicture = async (index: number, image: string): Promise<any> => {
    try {
      const response = await this.http
        .post<any>(`${this.env.API_URL}api/Documents/UploadImage`, {
          ...this.currentDocument,
          pageNumber: index + 1,
          image: image,
        })
        .toPromise();
      console.log("uploadImage Response", response);
      return response;
    } catch (error) {
      console.error("Error uploadPicture:", error);
      await this.alertService.showAlertError(
        `خطأ في رفع الصورة  : ${error.error}`,
        false
      );
      throw error;
    }
  };

  async addDocumentAndUpload(
    documentTypeCode: string,
    clientKey: string,
    documentsContent: { doc: string }[]
  ) {
    await this.addingDocument(documentTypeCode, clientKey);

    for (let i = 0; i < documentsContent.length; i++) {
      if (documentsContent[i].doc !== null) {
        await this.uploadPicture(i, documentsContent[i].doc);
      }
    }
  }

  getActiveDocumentsTypes = (): Observable<DocumentType[]> => {
    try {
      return this.http.get<DocumentType[]>(
        this.env.API_URL + `api/Documents/AllRefDocumentTypes`
      );
    } catch (error) {
      console.error("Error getActiveDocumentsTypes:", error);
      throw error;
    }
  };

  getActiveClientDocumentsTypes = (): Observable<DocumentType[]> => {
    try {
      return this.http.get<DocumentType[]>(
        this.env.API_URL + `api/Documents/AllDocumentTypes`
      );
    } catch (error) {
      console.error("Error getActiveClientDocumentsTypes:", error);
      throw error;
    }
  };

  getDocumentsForClientPerClientKey = (
    clientKey: number
  ): Observable<GetDocumentsByClientKey[]> => {
    try {
      return this.http.get<GetDocumentsByClientKey[]>(
        this.env.API_URL +
          `api/Documents/GetAllDocumentsByClientKey/${clientKey}`
      );
    } catch (error) {
      console.error("Error getDocumentsForClientPerClientKey:", error);
      throw error;
    }
  };
  getDocumentsForClientPerApplicationKey = (
    applicationKey: number,
    userName: string
  ): Observable<GetDocumentsByApplicationKey[]> => {
    try {
      return this.http.get<GetDocumentsByApplicationKey[]>(
        this.env.API_URL +
          `api/Documents/GetAllDocumentsByApplicationKey/${applicationKey}/${userName}`
      );
    } catch (error) {
      console.error("Error GetAllDocumentsByApplicationKey:", error);
      throw error;
    }
  };
  getDocumentBySerial = (
    request: GetDocumentBySerialRequest
  ): Observable<GetDocumentBySerialResponse> => {
    try {
      return this.http.get<GetDocumentBySerialResponse>(
        this.env.API_URL + `api/Documents/GetDocumentBySerial`,
        {
          params: {
            DocSerial: request.docSerial,
            DocPageNumber: request.docPageNumber,
          },
        }
      );
    } catch (error) {
      console.error("Error getDocumentBySerial:", error);
      throw error;
    }
  };
}
