import { AbstractControl, ValidationErrors, ValidatorFn } from "@angular/forms";

interface ValidatorProps {
  required: boolean;
}

// Regex patterns
const NATIONAL_ID_REGEX =
  /^[23](?:[0-9]{2}(?:(?:(?:0[13578]|1[02])(?:0[1-9]|[12][0-9]|3[01]))|(?:(?:0[469]|11)(?:0[1-9]|[12][0-9]|30))|(?:02(?:0[1-9]|1[0-9]|2[0-8])))|(?:(?:04|08|[2468][048]|[13579][26]|(?<=3)00)0229))(?:0[1-4]|[12][1-9]|3[1-5]|88)[0-9]{4}[1-9]$/;

const MOBILE_NUMBER_REGEX = /^01[0125][0-9]{8}$/;

const NUMBER_ONLY_REGEX = /^[0-9]*$/;

// Custom Validator
export function nationalIdValidator(
  validatorProps: ValidatorProps
): ValidatorFn {
  return (control: AbstractControl): ValidationErrors | null => {
    const value: string =
      control.value === null ? null : control?.value.toString();
    if (!validatorProps.required && value === null) {
      return;
    }
    if (value === null || value === "") {
      return { errorMessage: "يجب ادخال الرقم القومي" };
    } else if (value.length !== 14) {
      return { errorMessage: "يجب ادخال الرقم القومي المكون من 14 رقم" };
    } else if (!NATIONAL_ID_REGEX.test(value)) {
      return { errorMessage: "الرقم القومي غير صحيح" };
    }
    return null;
  };
}

