export function dateTypeStringValidator(
  validatorProps: ValidatorProps & {
    dateCannotBeAfterToday?: boolean;
    dateCannotBeBeforeToday?: boolean;
  }
): ValidatorFn {
  return (control: AbstractControl): ValidationErrors | null => {
    const date: string =
      control.value === null || control.value === undefined
        ? null
        : control?.value.toString();
    if (!validatorProps.required && date === null) {
      return;
    }
    if (date === null || date === "") {
      return { errorMessage: "يجب ادخال التاريخ" };
    }
    if (validatorProps.dateCannotBeAfterToday) {
      const currentDate = new Date();
      const selectedDate = new Date(date);
      if (selectedDate > currentDate) {
        return { errorMessage: "التاريخ لا يمكن ان يكون بعد اليوم الحالي" };
      }
    }
    if (validatorProps.dateCannotBeBeforeToday) {
      const currentDate = new Date();
      const selectedDate = new Date(date);
      if (selectedDate < currentDate) {
        return { errorMessage: "التاريخ لا يمكن ان يكون قبل اليوم الحالي" };
      }
    }
    const validatePattern =
      /^(19[0-9][0-9]|20[0-9][0-9])-(0[1-9]|1[0-2])-(0[1-9]|[12][0-9]|3[01])$/;
    if (!date.match(validatePattern)) {
      return { errorMessage: "صيغة التاريخ غير صحيحة" };
    }
    return null;
  };
}

