export function clientNameValidator(
  validatorProps: ValidatorProps & {
    minimumThreeWord?: boolean;
  }
): ValidatorFn {
  return (control: AbstractControl): ValidationErrors | null => {
    const value: string =
      control.value === null ? null : control?.value.toString();
    if (!validatorProps.required && value === null) {
      return;
    }
    const numberRegex = /^[a-zA-Z\u0600-\u06FF ]+$/;
    if (!numberRegex.test(value)) {
      return { errorMessage: "ادخال حروف فقط" };
    }
    if (!value?.trim()) {
      return { errorMessage: "يجب ادخال اسم العميل" };
    }
    if (validatorProps.minimumThreeWord) {
      const regex = /[^\s]+/g;
      const words = value.toLowerCase().match(regex);
      if (words.length < 3) {
        return { errorMessage: "يجب ادخال الاسم الثلاثي" };
      }
    }
    return null;
  };
}

