export function generalValidation(
  validatorProps: ValidatorProps & {
    minCharacter?: number;
    maxCharacter?: number;
  }
): ValidatorFn {
  return (control: AbstractControl): ValidationErrors | null => {
    const rawValue = control.value;
    const value: string | null =
      rawValue === null || rawValue === undefined
        ? null
        : rawValue.toString().trim();

    if (!validatorProps.required && (value === null || value === ""))
      return null;

    if (value === null || value === "") return { errorMessage: "يجب الادخال" };

    if (
      validatorProps.minCharacter !== undefined &&
      value.length < validatorProps.minCharacter
    )
      return { errorMessage: `لا يقل عن ${validatorProps.minCharacter} حرف` };

    if (
      validatorProps.maxCharacter !== undefined &&
      value.length > validatorProps.maxCharacter
    )
      return {
        errorMessage: `لا يزيد عن ${validatorProps.maxCharacter} حرف`,
      };

    return null;
  };
}

export function numberValidation(validatorProps: ValidatorProps): ValidatorFn {
  return (control: AbstractControl): ValidationErrors | null => {
    const value: string =
      control?.value === null || control.value === undefined
        ? null
        : control?.value.toString();
    if (!validatorProps.required && !value) {
      return;
    } else if (value === null) {
      return { errorMessage: "يجب ادخال" };
    } else if (!NUMBER_ONLY_REGEX.test(value)) {
      return { errorMessage: "يجب ادخال ارقام فقط" };
    }
    return null;
  };
}
