import { DOCUMENT } from "@angular/common";
import {
  Component,
  EventEmitter,
  Inject,
  Input,
  OnInit,
  Output,
  Renderer2,
  ViewChild,
} from "@angular/core";
import { FormGroup } from "@angular/forms";
import { AlertOptions, IonSelect } from "@ionic/angular";

@Component({
  selector: "app-multiplePopover",
  templateUrl: "./multiplePopover.component.html",
  styleUrls: ["./multiplePopover.component.scss"],
})
export class MultiplePopoverComponent implements OnInit {
  @Input() arrayModal: any = [];
  @Input() arrayName: string;
  @Input() arrayValue: string;
  @Input() parentForm: FormGroup;
  @Input() parentFormControllerName: string;
  @Input() placeholderText: string;
  @Input() okText: string;
  @Input() cancelText: string;
  @Input() valuesToDisable?: string[] = null;
  @Input() hidden?: boolean = false;
  @Input() disable?:boolean = false;
  @Output() onFinish: EventEmitter<any> = new EventEmitter();

  @ViewChild("selector") selector: IonSelect;

  constructor(
    @Inject(DOCUMENT) private document: Document,
    private renderer: Renderer2
  ) {}

  //#region Variables
  listener: any;
  checkboxId: any;
  checkBoxes: any;
  alertOption: AlertOptions = {
    header: "",
    subHeader: "",
    message:
      '<ion-checkbox id="checkboxId"></ion-checkbox><ion-label> الكل </ion-label>',
    backdropDismiss: false,
  };
  //#endregion

  ngOnInit() {}

  openSector() {
    this.selector.open().then((alert) => {
      this.checkboxId = this.document.getElementById("checkboxId");
      this.checkBoxes = this.document.getElementsByClassName("alert-checkbox");
      let selectedValue: any[] =
        this.parentForm.controls[this.parentFormControllerName].value;
      if (selectedValue?.length == this.arrayModal.length) {
        (this.checkboxId as HTMLButtonElement).click();
      }
      this.listener = this.renderer.listen(this.checkboxId, "click", () => {
        if (this.checkboxId.checked) {
          for (let checkbox of this.checkBoxes) {
            if (checkbox.getAttribute("aria-checked") === "false") {
              (checkbox as HTMLButtonElement).click();
            }
          }
        } else {
          for (let checkbox of this.checkBoxes) {
            if (checkbox.getAttribute("aria-checked") === "true") {
              (checkbox as HTMLButtonElement).click();
            }
          }
        }
      });
      alert.onWillDismiss().then(() => {
        this.listener();
        const value:any[] = this.parentForm.controls[this.parentFormControllerName].value;
        if(value?.length === 0) this.parentForm.patchValue({[this.parentFormControllerName]: null});

        this.onFinish.emit();
      });
    });
  }
  disableSpecificRow = (specificArray: any): boolean => {
    if (!this.valuesToDisable) return false;
    if (this.valuesToDisable.length > 0) {
      const test = this.valuesToDisable.filter(
        (x) => x === specificArray[this.arrayValue]
      );
      return test.length > 0 ? true : false;
    } else {
      return false;
    }
  };
}
