  getClientById = async (
    nationId: string,
    editAfterDisburse: number = 0,
    editBeforeLoanGenerate: number = 0
  ): Promise<ClientInfo> => {
    try {
      const response = await this.http
        .post<{ count: number; result: ClientInfo[] }>(
          `${this.env.API_URL}api/Clients/GetClientById`,
          {
            nation_id: nationId,
            EditAfterDisb: editAfterDisburse,
            editBeforeLoanGenerate: editBeforeLoanGenerate,
          }
        )
        .toPromise();
      return response?.result[0];
    } catch (error) {
      console.error("Error fetching clientInfo:", error);
      throw error;
    }
  };

