import { UserInfo } from "./../../../core/models/UserInfo";
import {
  Component,
  OnInit,
  ViewChild,
  ElementRef,
  AfterViewInit,
  Renderer2,
  Inject,
  OnDestroy,
} from "@angular/core";
import { DOCUMENT } from "@angular/common";

import MetisMenu from "metismenujs/dist/metismenujs";

import { ThemeService } from "src/app/core/services/theme.service";

import { MENU } from "./menu";
import { MenuItem, PageType } from "./menu.model";
import { Router, NavigationEnd } from "@angular/router";

import { Platform } from "@ionic/angular";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { TranslateService } from "@ngx-translate/core";
import { animate, style, transition, trigger } from "@angular/animations";

@Component({
  selector: "app-sidebar",
  templateUrl: "./sidebar.component.html",
  styleUrls: ["./sidebar.component.scss"],
  animations: [
    trigger("inOutAnimation", [
      transition(":enter", [
        style({ height: "0%", opacity: 0 }),
        animate("0.4s ease-out", style({ height: "100%", opacity: 1 })),
      ]),
      transition(":leave", [
        style({ height: "100%", opacity: 1 }),
        animate("0.4s ease-in", style({ height: "0%", opacity: 0 })),
      ]),
    ]),
  ],
})
export class SidebarComponent implements OnInit, OnDestroy {
  orgName: string = "";
  userInfo: UserInfo;
  menuItems = [];
  toggleSubMenu: any = [];
  currentLanguage: string = localStorage.getItem("currentLanguage") || "ar-EG";
  textDir: string = "ltr";

  constructor(
    public themeService: ThemeService,
    private authService: MohassilAuthService,
    public translate: TranslateService
  ) {}

  async ngOnInit(): Promise<void> {
    this.userInfo = await this.authService.getUserInfo();
    this.orgName = this.userInfo.org_name;
    this.translate.get(`languages.${this.currentLanguage}.dir`).subscribe({
      next: (dir) => {
        this.textDir = dir;
      },
      error: () => {
        this.textDir = "ltr";
      },
    });
    await this.buildMenu();
  }

  ngOnDestroy(): void {
    this.menuItems.forEach((menuItem) => {
      if (menuItem.expanded === true) {
        menuItem.expanded = false;
      }
    });

    this.menuItems = [];
  }

  async buildMenu() {
    this.menuItems = [];
    let accessRights = await this.authService.getAccessRights();
    let featureAccessRights = await this.authService.getFeatureAccessRights();
    let jobCode: string = this.userInfo.job_code;
    // this.UserjobCode = jobCode;
    let windowCodes: string[] = accessRights.map((x) => x.window_code);
    let featureCodes: string[] = featureAccessRights.map((x) => x.window_code);

    this.menuItems = MENU.map((menuEntry) =>
      !!menuEntry.subItems
        ? {
            ...menuEntry,
            windowCodes: menuEntry.subItems
              .filter((subItem) => !!subItem.windowCode)
              .map((subItem) => subItem.windowCode),
          }
        : menuEntry
    )
      .filter(
        (x) =>
          !x.windowCodes ||
          x.windowCodes.some((wc) =>
            //  windowCodes.includes(wc)
            wc.some((wcs) => windowCodes.includes(wcs))
          )
      )
      .filter((x) => !x.jobCodes || x.jobCodes.includes(jobCode))
      .filter((x) => !x.hidden)
      .filter(
        (x) =>
          !x.windowCode ||
          // windowCodes.includes(x.windowCode)
          x.windowCode.some((wc) => windowCodes.includes(wc))
      )
      .map((y) => {
        y.subItems = y.subItems
          ?.filter(
            (x) =>
              !x.windowCode ||
              // windowCodes.includes(x.windowCode)
              x.windowCode.some((wc) => windowCodes.includes(wc))
          )
          ?.filter((x) => !x.jobCodes || x.jobCodes.includes(jobCode))
          ?.filter((x) => !x.hidden)
          .filter(
            (x) =>
              !x.windowCodes ||
              x.windowCodes.some((wc) => windowCodes.includes(wc))
          );
        return y;
      })
      .map((z) => {
        z.subItems = z.subItems?.filter(
          (x) =>
            (x.pageType === PageType.HeadOffice &&
              this.userInfo.head_office === "1") ||
            (x.pageType === PageType.Branch &&
              this.userInfo.head_office === "0") ||
            x.pageType === PageType.HeadOfficeAndBranch
        );
        return z;
      })
      .filter((z) => z.subItems?.length > 0 || !!z.link);
  }

  hasItems(item: MenuItem) {
    return item.subItems !== undefined ? item.subItems.length > 0 : false;
  }

  toggle(item: MenuItem) {
    item.expanded = !item.expanded;
  }

  CloseAllItems() {
    this.menuItems.forEach((item) => {
      item.expanded = false;
    });
  }
}
