import { Injectable } from "@angular/core";
import { Capacitor } from "@capacitor/core";
import { AlertButton, AlertController, ToastController } from "@ionic/angular";
import { Alert } from "selenium-webdriver";

@Injectable({
  providedIn: "root",
})
export class AlertService {
  constructor(
    private alertController: AlertController,
    private toastController: ToastController
  ) {}

  public async popAlertBoolean(
    statusMessage: string = "",
    headerMessage: string = "تنبيه",
    id: string,
    cssClass: string[] = [""],
    buttons: AlertButton[] = [
      {
        text: "OK",
        handler: () => {
          return true;
        },
      },
    ]
  ): Promise<Boolean> {
    statusMessage;
    return new Promise(async (resolve, reject) => {
      const alert = await this.alertController.create({
        header: headerMessage,
        message: statusMessage,
        buttons: buttons,
        id: id,
        cssClass: cssClass,
        backdropDismiss: false,
      });

      await alert.present();
      var data = (await alert.onDidDismiss()).data;
      if (typeof data === "boolean") resolve(data);
      else {
        reject(data);
      }
    });
  }

  public async SaveAlert(message?: string): Promise<boolean> {
    if (message == null) {
      message = "هل أنت متأكد أنك تريد تنفيذ هذة العملية؟ ";
    }
    return new Promise<boolean>(async (resolve) => {
      let alert = await this.alertController.create({
        message:
          `<div id='alertService'><ion-icon name='save-outline' id="saveAlert"></ion-icon><br/>` +
          message +
          `</div>`,
        buttons: [
          {
            text: "نعم",
            role: "OK",
            cssClass: "btn-success",
            handler: () => resolve(true),
          },
          {
            text: "لا",
            cssClass: "btn-danger",
            role: "cancel",
            handler: () => resolve(false),
          },
        ],
        backdropDismiss: false,
      });

      await alert.present();
    });
  }

  public async RejectAlert(message?: string): Promise<boolean> {
    if (message == null) {
      message = "هل أنت متأكد أنك تريد تنفيذ هذة العملية؟ ";
    }
    return new Promise<boolean>(async (resolve) => {
      let alert = await this.alertController.create({
        message:
          `<div id='alertService'><ion-icon name="ban-outline" id="rejectAlert"></ion-icon><br/>` +
          message +
          `</div>`,
        buttons: [
          {
            text: "نعم",
            role: "OK",
            cssClass: "btn-success",
            handler: () => resolve(true),
          },
          {
            text: "لا",
            cssClass: "btn-danger",
            role: "cancel",
            handler: () => resolve(false),
          },
        ],
        backdropDismiss: false,
      });

      await alert.present();
    });
  }

  public async DeleteAlert(message?: string): Promise<boolean> {
    if (message == null) {
      message = "هل أنت متأكد أنك تريد تنفيذ هذة العملية؟ ";
    }
    return new Promise<boolean>(async (resolve) => {
      let alert = await this.alertController.create({
        message:
          `<div id='alertService'><ion-icon name="trash-outline" id="deleteAlert"></ion-icon><br/>` +
          message +
          `</div>`,
        buttons: [
          {
            text: "نعم",
            role: "OK",
            cssClass: "btn-success",
            handler: () => resolve(true),
          },
          {
            text: "لا",
            cssClass: "btn-danger",
            role: "cancel",
            handler: () => resolve(false),
          },
        ],
        backdropDismiss: false,
      });

      await alert.present();
    });
  }

  public async showAlertConfirm(
    message: string,
    reloads: boolean,
    buttonText?: string
  ): Promise<void> {
    let alert = this.alertController.create({
      message:
        `<div id='alertService'><ion-icon name='checkmark-circle-outline' id="showAlertConfirm"></ion-icon><br/>` +
        message +
        `</div>`,
      buttons: [
        {
          text: buttonText == null ? "تم" : buttonText,
          role: "OK",
          handler: () => {
            if (reloads) {
              location.reload();
            }
          },
        },
      ],
      backdropDismiss: false,
    });
    (await alert).present();
  }

  public async showAlertError(
    message: string,
    reloads: boolean,
    buttonText?: string
  ): Promise<void> {
    let alert = this.alertController.create({
      message:
        `<div id='alertService'><ion-icon name='alert-circle-outline' id="showAlertError"></ion-icon><br/><div class="error-message">` +
        message +
        `</div></div>`,
      buttons: [
        {
          text: buttonText == null ? "تم" : buttonText,
          role: "OK",
          handler: () => {
            if (reloads) {
              location.reload();
            }
          },
        },
      ],
      backdropDismiss: false,
    });
    (await alert).present();
  }

  public async InfoAlert(
    message: string,
    reloads: boolean,
    header: string = "معلومات الادخال"
  ): Promise<void> {
    if (message == null) {
      message = "";
    }

    let alert = this.alertController.create({
      header: header,
      message:
        `<div id='alertService'>
        <ion-item>
        <ion-icon name='information-circle' id="InfoAlert" slot='start'></ion-icon>
        ` +
        message +
        `</ion-item>
        </div>`,
      buttons: [
        {
          text: "تم",
          role: "OK",
          cssClass: "btn-success",
          handler: () => {
            if (reloads) {
              location.reload();
            }
          },
        },
      ],
      backdropDismiss: false,
    });

    (await alert).present();
  }

  public async presentToastSuccess(
    header: string,
    message: string
  ): Promise<void> {
    let toast = this.toastController.create({
      header: header,
      message: message,
      cssClass: "toast-primary",
      duration: 2000,
      position: "bottom",
    });
    (await toast).present();
  }

  public async presentToastError(
    header: string,
    message: string
  ): Promise<void> {
    let toast = this.toastController.create({
      header: header,
      message: message,
      cssClass: "toast-error",
      duration: 2000,
      position: "bottom",
    });
    (await toast).present();
  }

  public async showAlertInformation(
    message: string,
    reloads: boolean,
    buttonText?: string
  ): Promise<void> {
    let alert = this.alertController.create({
      message:
        `<div id='alertService'><ion-icon name='information-circle-outline' id="showAlertInformation"></ion-icon><br/>` +
        message +
        `</div>`,
      buttons: [
        {
          text: buttonText == null ? "تم" : buttonText,
          role: "OK",
          handler: () => {
            if (reloads) {
              location.reload();
            }
          },
        },
      ],
      backdropDismiss: false,
    });
    (await alert).present();
  }
}
