import { Injectable } from "@angular/core";
import { MohassilAuthService } from "./AuthenticationServices/mohassil-auth.service";
import { HttpClient } from "@angular/common/http";
import { Report } from "src/app/views/Models/Reports/Report";
import { EnvService } from "./env.service";
import { AlertService } from "./alert.service";
import { PdfViewerService } from "./pdf-viewer.service";
import { InstallmentsInfo } from "src/app/views/Models/Installments/InstallmentsInfo";
import { promise } from "protractor";
import { atobSafe } from "../util/atobSafe";

@Injectable({
  providedIn: "root",
})
export class ReportingService {
  constructor(
    private authService: MohassilAuthService,
    private env: EnvService,
    private http: HttpClient,
    private alertService: AlertService,
    private pdfViewerService: PdfViewerService
  ) {}

  private b64DecodeUnicode(str): string {
    return decodeURIComponent(
      atobSafe(str)
        .split("")
        .map(function (c) {
          return "%" + ("00" + c.charCodeAt(0).toString(16)).slice(-2);
        })
        .join("")
    );
  }
  async getReport(
    reportName: string,
    reportParameter: Array<{ key: string; value: string }>
  ): Promise<string> {
    let token = await this.authService.getAccessToken();
    token = token.replace("-", "+").replace("_", "/");
    const claims = JSON.parse(atobSafe(token.split(".")[1]));
    let username: string = "";
    let pwd: string = "";
    try {
      username = this.b64DecodeUnicode(btoa(claims.user_name));
    } catch (err) {
      username = claims.user_name;
    }
    try {
      pwd = this.b64DecodeUnicode(btoa(claims.pwd));
    } catch (err) {
      pwd = claims.pwd;
    }
    try {
      const data = await this.http
        .post<Report>(this.env.API_URL + `api/Reporting/GetReport`, {
          report_name: reportName,
          report_parameters: reportParameter,
          token: {
            username: username,
            password: pwd,
          },
        })
        .toPromise();

      if (data.status_code == 200) {
        return data.report;
      } else {
        await this.alertService.showAlertError(data.message, false);
        return null;
      }
    } catch (err) {
      await this.alertService.showAlertError(err.error, false);
      return null;
    }
  }

  async getLoanReschedulePreviewReport(
    reportParameter: Array<{ key: string; value: string }>,
    installments: InstallmentsInfo[]
  ): Promise<any> {
    let token = await this.authService.getAccessToken();
    token = token.replace("-", "+").replace("_", "/");
    const claims = JSON.parse(atobSafe(token.split(".")[1]));
    let username: string = "";
    let pwd: string = "";
    try {
      username = this.b64DecodeUnicode(btoa(claims.user_name));
    } catch (err) {
      username = claims.user_name;
    }
    try {
      pwd = this.b64DecodeUnicode(btoa(claims.pwd));
    } catch (err) {
      pwd = claims.pwd;
    }
    try {
      const data = await this.http
        .post<Report>(
          this.env.API_URL + `api/Reporting/GetLoanSchedulePreview`,
          {
            report_name: "Reschedule_report_preview",
            report_parameters: reportParameter,
            token: {
              username: username,
              password: pwd,
            },
            installments: installments,
          }
        )
        .toPromise();

      if (data.status_code == 200) {
        return data.report;
      } else {
        await this.alertService.showAlertError(data.message, false);
        return null;
      }
    } catch (err) {
      await this.alertService.showAlertError(err.error, false);
      return null;
    }
  }
}
