import { Inject, Injectable } from "@angular/core";
import { MediaMatcher } from "@angular/cdk/layout";
import { Meta } from "@angular/platform-browser";
import { DOCUMENT } from "@angular/common";

@Injectable({
  providedIn: "root",
})
export class ThemeService {
  private theme: string;

  constructor(
    private mediaMatcher: MediaMatcher,
    private meta: Meta,
    @Inject(DOCUMENT) private document: Document
  ) {}

  getOrSetTheme(): void {
    if (localStorage.getItem("theme") != null) {
      let preferredMode = localStorage.getItem("theme");
      if (preferredMode == "light") {
        this.theme = "light";
      } else if (preferredMode == "dark") {
        this.theme = "dark";
      }
    } else {
      let darkModePreferred = this.mediaMatcher.matchMedia(
        "(prefers-color-scheme: dark)"
      ).matches;
      if (darkModePreferred) {
        this.theme = "dark";
        localStorage.setItem("theme", "dark");
      } else {
        this.theme = "light";
        localStorage.setItem("theme", "light");
      }
    }
    if (!this.isDarkMode) {
      this.setTheme("light");
      this.document.body.classList.remove("navbar-dark");
      this.document.body.classList.add("navbar-light");
      this.document.body.classList.remove("darkmode");
    } else {
      this.setTheme("dark");
      this.document.body.classList.remove("navbar-light");
      this.document.body.classList.add("navbar-dark");
      this.document.body.classList.add("darkmode");
    }
  }

  setTheme(theme: string): void {
    this.theme = theme;
    localStorage.setItem("theme", theme);
    this.meta.updateTag(
      {
        name: "color-scheme",
        content: theme,
      },
      "name=color-scheme"
    );
  }

  get isDarkMode(): boolean {
    if (!!this.theme) {
      return this.theme == "dark";
    } else {
      this.getOrSetTheme();
      return this.theme == "dark";
    }
  }

  toggle() {
    if (this.isDarkMode) {
      this.setTheme("light");
      this.document.body.classList.remove("navbar-dark");
      this.document.body.classList.add("navbar-light");
      this.document.body.classList.remove("darkmode");
    } else {
      this.setTheme("dark");
      this.document.body.classList.remove("navbar-light");
      this.document.body.classList.add("navbar-dark");
      this.document.body.classList.add("darkmode");
    }
  }
}
