import { Injectable } from "@angular/core";
import { UserService } from "./user.service";

@Injectable({
  providedIn: "root",
})
export class pagingService {
  totalCount: number;
  pageSize: number;

  constructor(public userService: UserService){}

  async ngOnInit() {
    await this.setPageSize();
  }

  Paging<T>(listInput: T[], page: number): T[] {
    if (!this.pageSize) {
      this.pageSize = this.getPageSizeFromLocalStorage();
    }
    const startIndex = (page - 1) * this.pageSize;
    const endIndex = startIndex + this.pageSize;
    this.totalCount = listInput?.length;
    return listInput?.slice(startIndex, endIndex);
  }

  getPageSizeFromLocalStorage(): number | null {
    let pageSize = localStorage.getItem("PageSize");
    if(!pageSize) {
      this.setPageSize();
      pageSize = localStorage.getItem("PageSize");
    }
    return pageSize ? Number(pageSize) : null;
  }

  async setPageSize() : Promise<void> {
    const userPreference = await this.userService.getUserPreference().toPromise();
    this.pageSize = userPreference.grid_page_size;
    localStorage.setItem("PageSize", this.pageSize.toString());
  }
  
}
