import {
  Component,
  OnInit,
  Input,
  OnChanges,
  SimpleChanges,
  ElementRef,
  HostListener,
  forwardRef,
  ViewChild,
  TemplateRef,
  EventEmitter,
  ChangeDetectorRef,
  AfterContentChecked,
  AfterViewInit,
  Output,
  QueryList,
  ViewChildren,
} from "@angular/core";
import {
  NG_VALUE_ACCESSOR,
  ControlValueAccessor,
  FormGroup,
  Validators,
} from "@angular/forms";
import {
  startOfMonth,
  endOfMonth,
  addMonths,
  subMonths,
  setYear,
  eachDayOfInterval,
  getDate,
  getMonth,
  getYear,
  isToday,
  isSameMonth,
  format,
  getDay,
  subDays,
  setDay,
  isAfter,
  isBefore,
  addDays,
  setMonth,
  isSameDay,
  isSameYear,
} from "date-fns";
import {
  ISlimScrollEvent,
  ISlimScrollOptions,
  SlimScrollEvent,
  SlimScrollOptions,
} from "ngx-slimscroll";
import { arEG, enUS } from "date-fns/locale";
import { Capacitor } from "@capacitor/core";
import { DatePipe } from "@angular/common";

export interface DateRange {
  start: Date;
  end: Date;
}
export const createDateRange = (start: Date, end: Date): DateRange => ({
  start: new Date(start.getTime()),
  end: new Date(end.getTime()),
});
export type AddClass = string | string[] | { [k: string]: boolean } | null;
export const isSameDate = (date: Date, current: Date): boolean =>
  isSameDay(date, current) &&
  isSameMonth(date, current) &&
  isSameYear(date, current);
export interface Day {
  date: Date;
  day: number | string;
  month: number;
  year: number | string;
  inThisMonth: boolean;
  isToday: boolean;
  isSelected: boolean;
  isInRange: boolean;
  isSelectable: boolean;
  isStart: boolean;
  isEnd: boolean;
  isVisible: boolean;
}
export interface DatepickerOptions {
  closeOnClickOutside?: boolean;
  closeOnSelection?: boolean;
  includeDays?: "none" | "previous-month" | "next-month" | "all";
  includeNextMonthsFirstFullWeek?: boolean;
  minYear?: number; // default: current year - 30
  maxYear?: number; // default: current year + 30
  displayFormat?: string; // default: 'MMM D[,] YYYY'
  barTitleFormat?: string; // default: 'MMMM YYYY'
  dayNamesFormat?: string; // default 'ddd'
  barTitleIfEmpty?: string;
  selectRange?: boolean;
  rangeSeparator?: string; // default '-'
  firstCalendarDay?: number; // 0 = Sunday (default), 1 = Monday, ..
  locale?: object;
  minDate?: Date;
  maxDate?: Date;
  /** Placeholder for the input field */
  placeholder?: string;
  /** [ngClass] to add to the input field */
  addClass?: AddClass;
  /** [ngStyle] to add to the input field */
  addStyle?: { [k: string]: any } | null;
  /** ID to assign to the input field */
  fieldId?: string;
  /** If false, barTitleIfEmpty will be disregarded and a date will always be shown. Default: true */
  useEmptyBarTitle?: boolean;
  nullInitialValue?: boolean; //open the datePicker with no value selected or select today value
  autoFormatInput?: boolean; //Change Format of Input automatically to match format and restrictions
}

export type PickerPosition =
  | "bottom-left"
  | "bottom-right"
  | "top-left"
  | "top-right"
  | "static";

// Counter for calculating the auto-incrementing field ID
let counter = 0;

/**
 * Internal library helper that helps to check if value is empty
 * @param value
 */
const isNil = (value: Date | DatepickerOptions) => {
  return typeof value === "undefined" || value === null;
};

@Component({
  selector: "ngx-datepicker",
  templateUrl: "./datepicker.component.html",
  styleUrls: ["./datepicker.component.scss"],
  providers: [
    {
      provide: NG_VALUE_ACCESSOR,
      useExisting: forwardRef(() => NGXDatepickerComponent),
      multi: true,
    },
  ],
})
export class NGXDatepickerComponent
  implements ControlValueAccessor, OnInit, OnChanges
{
  @ViewChild("container") calendarContainerElement: ElementRef;
  @ViewChild("inputElement") inputElement: ElementRef;
  @ViewChild("mainCalendarYears") mainCalendarYears: ElementRef;
  @ViewChildren("yearUnit") yearUnits: QueryList<ElementRef>;

  @Input() options: DatepickerOptions;

  /**
   * Disable datepicker's input
   */
  @Input() headless = false;

  /**
   * Set datepicker's visibility state
   */
  @Input() isOpened = false;

  /**
   * Datepicker dropdown position
   */
  @Input() position: PickerPosition = "bottom-left";

  @Input() previousMonthButtonTemplate: TemplateRef<any>;
  @Input() nextMonthButtonTemplate: TemplateRef<any>;

  @Input() parentForm: FormGroup;
  @Input() parentFormControllerName: string;
  @Input() disabledValue: boolean = false;
  @Input() InputDisabled?: boolean = false;

  @Input() scrollOptions: SlimScrollOptions = new SlimScrollOptions(
    this.scrollBarOptions
  );
  // @Output() newItemEvent = new EventEmitter<string>();
  @Output() ionChange: EventEmitter<string> = new EventEmitter();
  @Output() blur = new EventEmitter<string>();
  @Output() focus = new EventEmitter<string>();

  scrollEvents = new EventEmitter<ISlimScrollEvent>();
  currentOptions: DatepickerOptions = {
    closeOnClickOutside: true,
    closeOnSelection: true,
    includeDays: "none", // 'none', 'previous-month', 'next-month', 'all'. Should it render days outside current month.
    includeNextMonthsFirstFullWeek: false,
    minYear: 1900, // Minimal selectable date
    maxYear: 2100, // Maximal selectable date
    displayFormat: "yyyy-MM-dd",
    barTitleFormat: "MMMM",
    dayNamesFormat: "EEE",
    rangeSeparator: "-", // Char that separates start and end dates in input field.
    selectRange: false,
    firstCalendarDay: 0, // 0 - Sunday, 1 - Monday
    barTitleIfEmpty: "Click to select a date",
    locale: { locale: arEG },
    placeholder: "", // HTML input placeholder attribute (default: '')
    addClass: {}, // Optional, value to pass on to [ngClass] on the input field
    addStyle: {}, // Optional, value to pass to [ngStyle] on the input field
    fieldId: this.defaultFieldId, // ID to assign to the input field. Defaults to datepicker-<counter>
    useEmptyBarTitle: true, // Defaults to true. If set to false then barTitleIfEmpty will be disregarded and a date will always be shown
    nullInitialValue: false,
  };

  displayValue: string;
  viewingDate: Date;
  barTitleMonth: string;
  barTitleYear: string;
  view: "days" | "months" | "years";
  years: { year: number | string; isThisYear: boolean }[];
  months: { month: number; name: string; isSelected: boolean }[];
  dayNames: string[];
  days: Day[];
  fieldId: string;
  disabled: boolean;
  currentLanguage: string;
  currentDirection: string;

  localeMap: { [key: string]: any } = {
    "ar-EG": arEG,
    "en-US": enUS,
  };

  directionMap: { [key: string]: any } = {
    "ar-EG": "rtl",
    "en-US": "ltr",
  };

  private _range: DateRange;

  private onTouchedCallback: () => void = () => {};
  private onChangeCallback: (_: any) => void = () => {};

  public setDisabledState(isDisabled: boolean) {
    this.disabled = isDisabled;
  }

  set range(val: DateRange | undefined) {
    this._range = val;
    this.onChangeCallback(this.getValueToEmit(val));
  }

  get range(): DateRange | undefined {
    return this._range;
  }

  constructor(
    private cdref: ChangeDetectorRef,
    public elementRef: ElementRef,
    private datePipe: DatePipe
  ) {}

  async ngOnInit() {
    this.parentForm.controls[this.parentFormControllerName].addValidators(
      Validators.pattern(
        /^(19[0-9][0-9]|20[0-9][0-9])-(0[1-9]|1[0-2])-(0[1-9]|[12][0-9]|3[01])$/
      )
    );
    this.currentLanguage = localStorage.getItem("currentLanguage") || "en-US";
    this.currentDirection = this.directionMap[this.currentLanguage] || "ltr";
    this.currentOptions.locale = {
      locale: this.localeMap[this.currentLanguage] || enUS,
    };
    this.view = "days";
    this.viewingDate = new Date();
    if (
      this.parentForm.controls[this.parentFormControllerName].value !=
        undefined &&
      this.parentForm.controls[this.parentFormControllerName].value != null &&
      this.parentForm.controls[this.parentFormControllerName].value != ""
    ) {
      this.range = {
        start: new Date(
          this.parentForm.controls[this.parentFormControllerName].value
        ),
        end: new Date(
          this.parentForm.controls[this.parentFormControllerName].value
        ),
      };
      this.writeValue(
        new Date(this.parentForm.controls[this.parentFormControllerName].value)
      );
    } else {
      this.range = {
        start: new Date(),
        end: new Date(),
      };
    }
    this.parentForm
      .get(this.parentFormControllerName)
      ?.valueChanges.subscribe((value) => {
        if (value && this.viewingDate && this.viewingDate !== value) {
          if (this.checkIfValid(value)) {
            this.range.start = this.range.end = new Date(value);
            this.viewingDate = new Date(value);
            this.selectDate(new Date(value));
            this.init();
          }
        }
      });
    this.detectDevice();
    this.initDayNames();
    this.initYears();
    this.initMonths();
    this.init();
  }
  private get scrollBarOptions(): ISlimScrollOptions {
    return {
      barBackground: "#dfe3e9",
      gridBackground: "transparent",
      barBorderRadius: "3",
      gridBorderRadius: "3",
      barWidth: "6",
      gridWidth: "6",
      barMargin: "0",
      gridMargin: "0",
    };
  }

  ngOnChanges(changes: SimpleChanges) {
    if ("options" in changes) {
      this.scrollOptions = new SlimScrollOptions(this.scrollBarOptions);
      this.updateOptions(changes.options.currentValue);
      this.initDayNames();
      this.init();
      this.initYears();
      this.initMonths();
    }
  }
  ngAfterContentChecked(): void {
    this.cdref.detectChanges();
  }
  ngAfterViewInit(): void {
    this.cdref.detectChanges();
  }
  get defaultFieldId(): string {
    // Only evaluate and increment if required
    const value = `datepicker-${counter++}`;
    Object.defineProperty(this, "defaultFieldId", { value });

    return value;
  }

  updateOptions(options: DatepickerOptions): void {
    this.currentOptions = {
      ...this.currentOptions,
      ...options,
    };
  }

  nextMonth(): void {
    this.viewingDate = addMonths(this.viewingDate, 1);
    this.init();
  }

  prevMonth(): void {
    this.viewingDate = subMonths(this.viewingDate, 1);
    this.init();
  }

  setDate(i: number): void {
    const date = this.days[i].date;

    if (this.currentOptions.selectRange) {
      if (!this.range.start && !this.range.end) {
        this.range.start = date;
      } else if (
        this.range.start &&
        !this.range.end &&
        isAfter(date, this.range.start)
      ) {
        this.range.end = date;
      } else {
        this.range.end = undefined;
        this.range.start = date;
      }
    } else {
      this.range.start = this.range.end = date;
    }

    this.init();
    this.onChangeCallback(this.getValueToEmit(this.range));
    this.ionChange.emit(this.displayValue);

    if (this.currentOptions.closeOnSelection && this.range.end) {
      this.close();
    }
  }

  setYear(i: number): void {
    this.viewingDate = setYear(
      this.viewingDate,
      Number(this.convertArabicToEnglishNumber(this.years[i].year))
    );
    this.init();
    this.initYears();
    this.view = "months";
  }

  setMonth(i: number): void {
    this.viewingDate = setMonth(this.viewingDate, this.months[i].month);
    this.init();
    this.initMonths();
    this.view = "days";
  }

  init(): void {
    if (!this.viewingDate) {
      return;
    }
    const start = startOfMonth(this.viewingDate);
    const end = endOfMonth(this.viewingDate);

    this.days = eachDayOfInterval({ start, end }).map((date) =>
      this.formatDay(date)
    );

    const firstMonthDay = getDay(start) - this.currentOptions.firstCalendarDay;
    const prevDays =
      firstMonthDay < 0
        ? 7 - this.currentOptions.firstCalendarDay
        : firstMonthDay;
    let nextDays =
      (this.currentOptions.firstCalendarDay === 1 ? 7 : 6) - getDay(end);

    const showPrevMonthDays =
      this.currentOptions.includeDays === "all" ||
      this.currentOptions.includeDays === "previous-month";
    const showNextMonthDays =
      this.currentOptions.includeDays === "all" ||
      this.currentOptions.includeDays === "next-month";

    if (
      showNextMonthDays &&
      this.currentOptions.includeNextMonthsFirstFullWeek
    ) {
      nextDays += 7;
    }

    for (let i = 1; i <= prevDays; i++) {
      this.days.unshift(this.formatDay(subDays(start, i), showPrevMonthDays));
    }

    new Array(nextDays)
      .fill(undefined)
      .forEach((_, i) =>
        this.days.push(this.formatDay(addDays(end, i + 1), showNextMonthDays))
      );
    this.displayValue = this.formatDisplay();

    if (this.range) {
      this.barTitleYear =
        this.currentLanguage === "ar-EG"
          ? this.convertEnglishToArabicNumber(this.viewingDate.getFullYear())
          : this.viewingDate.getFullYear().toString();
      this.barTitleMonth =
        this.currentLanguage === "ar-EG"
          ? this.convertEnglishToArabicNumber(
              format(
                this.viewingDate,
                this.currentOptions.barTitleFormat,
                this.currentOptions.locale
              )
            )
          : format(
              this.viewingDate,
              this.currentOptions.barTitleFormat,
              this.currentOptions.locale
            );
    } else {
      this.barTitleMonth = this.currentOptions.useEmptyBarTitle
        ? this.currentOptions.barTitleIfEmpty
        : format(
            this.viewingDate,
            this.currentOptions.barTitleFormat,
            this.currentOptions.locale
          );
      this.barTitleYear = this.currentOptions.useEmptyBarTitle
        ? this.currentOptions.barTitleIfEmpty
        : this.viewingDate.getFullYear().toString();
    }
  }

  initYears(): void {
    const range = this.currentOptions.maxYear - this.currentOptions.minYear;

    this.years = Array.from(
      new Array(range),
      (x, i) => i + this.currentOptions.minYear
    ).map((year) => {
      return {
        year:
          this.currentLanguage === "ar-EG"
            ? this.convertEnglishToArabicNumber(year)
            : year,
        isThisYear: year === getYear(this.viewingDate),
      };
    });
  }

  initMonths(): void {
    this.months = Array.from(new Array(12), (x, i) =>
      setMonth(new Date(), i)
    ).map((date) => {
      return {
        month: date.getMonth(),
        name: format(date, "MMMM", {
          locale: this.localeMap[this.currentLanguage],
        }),
        isSelected: date.getMonth() === getMonth(this.viewingDate),
      };
    });
  }

  initDayNames(): void {
    this.dayNames = [];
    const start = this.currentOptions.firstCalendarDay;

    for (let i = start; i <= 6 + start; i++) {
      const date = setDay(new Date(), i);

      this.dayNames.push(
        format(
          date,
          this.currentOptions.dayNamesFormat,
          this.currentOptions.locale
        )
      );
    }
  }

  toggleView(): void {
    if (this.view === "years") {
      this.view = "days";
    } else {
      this.view = "years";
      this.cdref.detectChanges();
      this.scrollToYear();
    }
  }
  toggleMonth(): void {
    if (this.view === "months") {
      this.view = "days";
    } else {
      this.view = "months";
    }
  }

  private scrollToYear(): void {
    const parent = this.mainCalendarYears.nativeElement;
    const selectedYear = this.yearUnits.find((el) =>
      el.nativeElement.classList.contains("is-selected")
    );
    const el = selectedYear ? selectedYear.nativeElement : null;

    if (el && parent) {
      const y = el.offsetTop - parent.clientHeight / 2 + el.clientHeight / 2;
      const event = new SlimScrollEvent({ type: "scrollTo", y, duration: 100 });
      this.scrollEvents.emit(event);
    }
  }
  toggle(): void {
    if (this.disabledValue) {
      return;
    }
    this.displayValue = this.datePipe.transform(this.viewingDate, "yyyy-MM-dd");
    this.isOpened = !this.isOpened;
    if (!this.isOpened && this.view === "years") {
      this.toggleView();
    }
  }

  close(): void {
    this.isOpened = false;
    this.view = "days";
  }

  reset(): void {
    this.range = {
      start: new Date(),
      end: new Date(),
    };
    this.init();
  }

  writeValue(val: DateRange | Date | string | undefined) {
    if (val) {
      if (typeof val === "string") {
        this.range.start = this.range.end = new Date(val);
      } else if (val instanceof Date) {
        this.range.start = this.range.end = val;
      } else if (val.start) {
        // Checking if it's instance of DateRange
        this.range = val;
      } else {
        throw Error("Invalid input data type");
      }

      this.viewingDate = this.range.start || this.viewingDate;

      this.init();
    }
  }

  registerOnChange(fn: any) {
    this.onChangeCallback = fn;
  }

  registerOnTouched(fn: any) {
    this.onTouchedCallback = fn;
  }

  @HostListener("document:click", ["$event"]) onBlur(e: MouseEvent) {
    if (!this.isOpened || !this.currentOptions.closeOnClickOutside) {
      return;
    }

    if (!!this.inputElement) {
      return;
    }
    if (
      e.target === this.inputElement.nativeElement ||
      this.inputElement.nativeElement.contains(<any>e.target) ||
      ((<any>e.target).parentElement &&
        (<any>e.target).parentElement.classList.contains("day-unit"))
    ) {
      return;
    }
    if (
      this.calendarContainerElement.nativeElement !== e.target &&
      !this.calendarContainerElement.nativeElement.contains(<any>e.target) &&
      !(<any>e.target).classList.contains("year-unit") &&
      !(<any>e.target).classList.contains("month-unit")
    ) {
      this.close();
    }
  }

  formatDay = (date: Date, isVisible: boolean = true): Day => ({
    date: date,
    day:
      this.currentLanguage === "ar-EG"
        ? this.convertEnglishToArabicNumber(getDate(date))
        : getDate(date),
    month: getMonth(date),
    year:
      this.currentLanguage === "ar-EG"
        ? this.convertEnglishToArabicNumber(getYear(date))
        : getYear(date),
    inThisMonth: isSameMonth(date, this.viewingDate),
    isToday: isVisible && isToday(date),
    isSelected: isVisible && this.isDateSelected(date),
    isInRange: isVisible && this.isInRange(date),
    isSelectable: isVisible && this.isDateSelectable(date),
    isStart: isVisible && this.isRangeBoundary(date, "start"),
    isEnd: isVisible && this.isRangeBoundary(date, "end"),
    isVisible,
  });

  getDayClasses(day: Day): AddClass {
    return {
      "is-prev-month": !day.inThisMonth,
      "is-today": day.isToday,
      "is-selected": day.isSelected,
      "is-in-range": day.isInRange,
      "is-disabled": !day.isSelectable,
      "range-start": day.isStart,
      "range-end": day.isEnd,
      "is-visible": day.isVisible,
    };
  }

  /**
   * Checks if specified date is in range of min and max dates
   * @param date
   */
  private isDateSelectable(date: Date): boolean {
    const minDateSet = !isNil(this.currentOptions.minDate);
    const maxDateSet = !isNil(this.currentOptions.maxDate);
    const timestamp = date.valueOf();
    return (
      (!minDateSet || timestamp >= this.currentOptions.minDate.valueOf()) &&
      (!maxDateSet || timestamp <= this.currentOptions.maxDate.valueOf())
    );
  }

  private isDateSelected(date: Date): boolean {
    return (
      isSameDate(date, this.range.start) || isSameDate(date, this.range.end)
    );
  }

  private isInRange(date: Date): boolean {
    return (
      this.isDateSelected(date) ||
      (isAfter(date, this.range.start) && isBefore(date, this.range.end))
    );
  }

  private formatDisplay(): string {
    if (!this.range) {
      return "";
    }

    const formattedStartDate = format(
      this.range.start,
      this.currentOptions.displayFormat,
      this.currentOptions.locale
    );

    if (this.currentOptions.selectRange) {
      const formattedEndDate = format(
        this.range.end || this.range.start,
        this.currentOptions.displayFormat,
        this.currentOptions.locale
      );
      return `${formattedStartDate}${this.currentOptions.rangeSeparator}${formattedEndDate}`;
    }
    // this to make initial value is null first time
    if (
      this.options?.nullInitialValue !== null &&
      this.options?.nullInitialValue === true
    ) {
      this.options.nullInitialValue = false;
      return null;
    }
    return formattedStartDate;
  }

  private isRangeBoundary(date: Date, boundary: "start" | "end"): boolean {
    return !this.range[boundary] || isSameDate(date, this.range[boundary]);
  }

  private getValueToEmit(range: DateRange): DateRange | Date {
    if (!this.currentOptions.selectRange) {
      return new Date(range.start.getTime());
    }
    if (range.end) {
      return createDateRange(range.start, range.end);
    }

    return createDateRange(range.start, range.start);
  }

  deviceDetect: boolean; // true -> mobile   false -> web
  private detectDevice() {
    if (Capacitor.getPlatform() == "web") {
      this.deviceDetect = false;
    } else {
      this.deviceDetect = true;
    }
  }
  formatWithLeadingZero(value: number): string {
    return value < 10 ? `0${value}` : `${value}`;
  }
  formatDateString(dateString: string): string {
    const [year, month, day] = dateString
      .split("-")
      .map((part) => parseInt(part, 10));
    return `${year}-${this.formatWithLeadingZero(
      month
    )}-${this.formatWithLeadingZero(day)}`;
  }
  sendTheNewValue(event: any) {
    var inputElement = event.target as HTMLInputElement;

    var eventValue = this.getValue(event);
    const validatePattern =
      /^(19[0-9][0-9]|20[0-9][0-9])-(0[1-9]|1[0-2])-(0[1-9]|[12][0-9]|3[01])$/;
    const cleanedValue = eventValue.replace(/[^\d-]/g, "");
    const formattedDateString = this.formatDateString(cleanedValue);

    var dateValues = formattedDateString.match(validatePattern);
    if (dateValues) {
      const date = new Date(cleanedValue);
      const minDate = this.currentOptions.minDate
        ? this.currentOptions.minDate
        : null;
      const maxDate = this.currentOptions.maxDate
        ? this.currentOptions.maxDate
        : null;
      if (minDate && date < minDate) {
        this.selectDate(minDate);
        this.setDate(minDate.getDay());
        this.viewingDate = minDate;
        this.writeValue(minDate);
      } else if (maxDate && date > maxDate) {
        this.selectDate(maxDate);
        this.setDate(maxDate.getDay());
        this.viewingDate = maxDate;
        this.writeValue(maxDate);
      } else {
        this.selectDate(date);
        this.setDate(date.getDay());
        this.viewingDate = date;
        this.writeValue(date);
      }
    }

    inputElement.value = cleanedValue;
  }
  selectDate(date: Date) {
    this.years.map((x) => {
      if (x.isThisYear) {
        x.isThisYear = false;
      }
      if (
        x.year ==
        (this.currentLanguage === "ar-EG"
          ? this.convertEnglishToArabicNumber(date.getFullYear())
          : date.getFullYear())
      ) {
        x.isThisYear = true;
      }
    });
    this.months.map((m) => {
      if (m.isSelected) {
        m.isSelected = false;
      }
      if (m.month == date.getMonth()) {
        m.isSelected = true;
      }
    });
  }

  convertEnglishToArabicNumber(englishNumber) {
    const numberMap = {
      "0": "٠",
      "1": "١",
      "2": "٢",
      "3": "٣",
      "4": "٤",
      "5": "٥",
      "6": "٦",
      "7": "٧",
      "8": "٨",
      "9": "٩",
    };
    const englishNumberStr = englishNumber.toString();
    let arabicNumberStr = "";

    for (let i = 0; i < englishNumberStr.length; i++) {
      const digit = englishNumberStr[i];
      const arabicDigit = numberMap[digit];

      if (arabicDigit !== undefined) {
        arabicNumberStr += arabicDigit;
      } else {
        arabicNumberStr += digit; // Append non-digit characters as they are
      }
    }

    return arabicNumberStr;
  }
  convertArabicToEnglishNumber(arabicNumber) {
    const numberMap = {
      "٠": "0",
      "١": "1",
      "٢": "2",
      "٣": "3",
      "٤": "4",
      "٥": "5",
      "٦": "6",
      "٧": "7",
      "٨": "8",
      "٩": "9",
    };
    const arabicNumberStr = arabicNumber.toString();
    let englishNumberStr = "";

    for (let i = 0; i < arabicNumberStr.length; i++) {
      const digit = arabicNumberStr[i];
      const englishDigit = numberMap[digit];

      if (englishDigit !== undefined) {
        englishNumberStr += englishDigit;
      } else {
        englishNumberStr += digit; // Append non-digit characters as they are
      }
    }

    return englishNumberStr;
  }
  // this method to get the value from the Event
  getValue(event: Event): string {
    return (event.target as HTMLInputElement).value;
  }

  onInputBlur(ev: FocusEvent) {
    if (!this.isInteractingWithCalendar(ev)) {
      this.blur.emit(this.displayValue);
    }
  }

  onInputFocus(ev: FocusEvent) {
    if (!this.isInteractingWithCalendar(ev)) {
      this.focus.emit(this.displayValue);
    }
  }

  isInteractingWithCalendar(event: FocusEvent): boolean {
    const relatedTarget = event.relatedTarget as HTMLElement;
    return (
      relatedTarget &&
      relatedTarget.classList.contains("ngx-dates-picker-calendar-container")
    );
  }
  checkIfValid(date: string): boolean {
    const validatePattern =
      /^(19[0-9][0-9]|20[0-9][0-9])-(0[1-9]|1[0-2])-(0[1-9]|[12][0-9]|3[01])$/;
    const cleanedValue = date.replace(/[^\d-]/g, "");
    const formattedDateString = this.formatDateString(cleanedValue);

    var dateValues = formattedDateString.match(validatePattern);
    if (dateValues) return true;
    else return false;
  }
}
