import {
  Component,
  Input,
  EventEmitter,
  Output,
  ViewChild,
  ElementRef,
  AfterViewInit,
  HostListener,
} from "@angular/core";
import { Tree } from "src/app/views/Models/Users/Tree";
import { IonPopover, Platform } from "@ionic/angular";
import { trigger, transition, style, animate } from "@angular/animations";

@Component({
  selector: "app-tree",
  templateUrl: "./tree.component.html",
  styleUrls: ["./tree.component.scss"],
  animations: [
    trigger("fadeSlideToggle", [
      transition(":enter", [
        style({
          opacity: 0,
          transform: "translateY(-8px)",
        }),
        animate(
          "250ms cubic-bezier(0.4, 0, 0.2, 1)",
          style({
            opacity: 1,
            transform: "translateY(0)",
          })
        ),
      ]),
      transition(":leave", [
        animate(
          "200ms cubic-bezier(0.4, 0, 1, 1)",
          style({
            opacity: 0,
            transform: "translateY(-8px)",
          })
        ),
      ]),
    ]),
  ],
})
export class TreeComponent<T> implements AfterViewInit {
  @Input() node: Tree<T>;
  @Output() Edit = new EventEmitter<Tree<T>>();
  @Output() Select = new EventEmitter<Tree<T>>();
  @Output() Delete = new EventEmitter<Tree<T>>();
  @Output() Add = new EventEmitter<Tree<T>>();

  @ViewChild("popover") popover: IonPopover;
  @ViewChild("childrenContent") childrenContent!: ElementRef<HTMLElement>;

  selectedNode: Tree<T>;
  connectorHeight = 0;
  isOpen = false;
  alignment: "start" | "end" = "start";
  canEdit = true;
  canAdd = true;
  canDelete = true;
  canSelect = true;

  ngAfterViewInit() {
    this.calculateConnectorHeight();
  }

  @HostListener("window:resize")
  onResize() {
    this.calculateConnectorHeight();
  }

  toggleNode(node: Tree<T>) {
    node.collapsed = !node.collapsed;
    setTimeout(() => this.calculateConnectorHeight(), 300);
  }

  toggleAllNestedNodes(node: Tree<T>) {
    const shouldCollapse = !node.collapsed;

    const toggleRecursive = (n: Tree<T>) => {
      n.collapsed = shouldCollapse;
      if (n.children?.length) {
        n.children.forEach((child) => toggleRecursive(child));
      }
    };

    toggleRecursive(node);

    setTimeout(() => this.calculateConnectorHeight(), 300);
  }

  calculateConnectorHeight() {
    if (!this.node.children || this.node.children.length === 0) {
      this.connectorHeight = 0;
      return;
    }
    const wrapper = this.childrenContent?.nativeElement;
    if (wrapper) {
      this.connectorHeight = wrapper.offsetHeight;
    }
  }

  selectNode(node: Tree<T>) {
    this.selectedNode = node;
    this.canAdd = node.canAdd;
    this.canDelete = node.canDelete;
    this.canEdit = node.canEdit;
    this.canSelect = node.canSelect;
  }

  presentPopover(e: Event) {
    this.popover.event = e;
    this.adjustPopoverAlignment(e);
    this.isOpen = true;
  }

  dismissPopover(e: Event) {
    this.popover.event = e;
    this.popover.dismiss(null, "cancel");
    this.isOpen = false;
  }

  submitEdit(node: Tree<T>) {
    this.Edit.emit(node);
  }
  submitDelete(node: Tree<T>) {
    this.Delete.emit(node);
  }
  submitAdd(node: Tree<T>) {
    this.Add.emit(node);
  }
  submitSelect(node: Tree<T>) {
    this.Select.emit(node);
  }

  adjustPopoverAlignment(event: any) {
    this.platform.ready().then(() => {
      const windowHeight = this.platform.height();
      const windowPosition = event.clientY;
      this.alignment = windowPosition > windowHeight / 2 ? "end" : "start";
    });
  }

  constructor(private platform: Platform) {}
}
