import { HttpClient } from "@angular/common/http";
import { Injectable } from "@angular/core";
import { Router } from "@angular/router";
import { Browser } from "@capacitor/browser";
import { SecureStoragePlugin } from "capacitor-secure-storage-plugin";
import { AccessRight } from "src/app/views/Models/Permissions/AccessRight";
import { LoginResponse } from "src/app/views/Models/Settings/LoginResponse";
import { RefreshTokenRequest } from "../../models/RefreshTokenRequest";
import { UserInfo } from "../../models/UserInfo";
import { EnvService } from ".././env.service";
import { LocationService } from "src/app/core/services/location.service";
import { Capacitor } from "@capacitor/core";
import { MENU } from "../../../views/layout/sidebar/menu";
import { pagingService } from "../paging.service";
import { DatePipe } from "@angular/common";
import { UserService } from "../user.service";
import { Preferences } from "@capacitor/preferences";
import { atobSafe } from "../../util/atobSafe";

@Injectable({
  providedIn: "root",
})
export class MohassilAuthService {
  private readonly ACCESS_TOKEN_KEY: string = "access_token";
  private readonly ACCESS_RIGHTS_KEY: string = "access_rights";
  private readonly OTP_TOKEN_KEY: string = "otp_token";
  private readonly SESSION_KEY: string = "session_key";
  private readonly FEATURE_ACCESS_RIGHTS_KEY: string = "feature_access_rights";
  private readonly SERVICE_URL_KEY: string = "service_url";

  private sendLocationInterval: any;
  private locCaptureFreq?: number;
  constructor(
    private router: Router,
    private http: HttpClient,
    private location: LocationService,
    private pagingService: pagingService,
    private envService: EnvService,
    private datePipe: DatePipe,
    private userService: UserService
  ) {}

  /* GETTERS */

  public async getAccessToken(): Promise<string> {
    try {
      const token = await SecureStoragePlugin.get({
        key: this.ACCESS_TOKEN_KEY,
      });
      return token.value;
    } catch (err) {
      return null;
    }
  }

  public async getOtpToken(): Promise<string> {
    try {
      const token = await SecureStoragePlugin.get({
        key: this.OTP_TOKEN_KEY,
      });
      return token.value;
    } catch (err) {
      return null;
    }
  }

  public async getSessionId(): Promise<string> {
    try {
      const session = await SecureStoragePlugin.get({
        key: this.SESSION_KEY,
      });
      return session.value;
    } catch (err) {
      return null;
    }
  }

  public async getUserInfo(): Promise<UserInfo | null> {
    try {
      let token = await this.getAccessToken();
      token = token.replace("-", "+").replace("_", "/");
      const claims = JSON.parse(atobSafe(token.split(".")[1]));
      let orgName: string = "";
      let username: string = "";
      try {
        username = this.b64DecodeUnicode(btoa(claims.user_name));
      } catch (err) {
        username = claims.user_name;
      }
      try {
        orgName = this.b64DecodeUnicode(btoa(claims.org_name));
      } catch (err) {
        orgName = "المحصل";
      }
      let userInfo: UserInfo = {
        user_name: username,
        org_code: claims.org_code,
        org_name: orgName,
        branch_code: claims.branch_code,
        head_office: claims.head_office,
        officer_key: claims.officer_key ?? null,
        job_code: claims.job_code ?? null,
        notifications_count: claims.notifications_count,
        workflow_job_type: claims.workflow_job_type,
        workflow_job_id: claims.workflow_job_id,
      };
      return userInfo;
    } catch (err) {
      return null;
    }
  }

  public async getUserInfoFromOTPToken(): Promise<string> {
    try {
      let token = await this.getOtpToken();
      token = token.replace("-", "+").replace("_", "/");
      const claims = JSON.parse(atobSafe(token.split(".")[1]));
      console.log(claims);
      let username: string = "";
      try {
        username = this.b64DecodeUnicode(btoa(claims.Username));
      } catch (err) {
        username = claims.Username;
      }
      return username;
    } catch (err) {
      return null;
    }
  }

  private b64DecodeUnicode(str): string {
    return decodeURIComponent(
      atobSafe(str)
        .split("")
        .map(function (c) {
          return "%" + ("00" + c.charCodeAt(0).toString(16)).slice(-2);
        })
        .join("")
    );
  }

  public async getServiceUrl(): Promise<string | null> {
    return this.envService.API_URL;
  }

  public async getAccessRights(): Promise<AccessRight[] | null> {
    try {
      let serializedAccessRights = await SecureStoragePlugin.get({
        key: this.ACCESS_RIGHTS_KEY,
      });
      let accessRights: AccessRight[] = JSON.parse(
        decodeURIComponent(serializedAccessRights.value)
      );
      return accessRights;
    } catch (err) {
      return null;
    }
  }

  public async getFeatureAccessRights(): Promise<AccessRight[] | null> {
    try {
      let serializedAccessRights = await SecureStoragePlugin.get({
        key: this.FEATURE_ACCESS_RIGHTS_KEY,
      });
      let accessRights: AccessRight[] = JSON.parse(
        decodeURIComponent(serializedAccessRights.value)
      );
      return accessRights;
    } catch (err) {
      return null;
    }
  }
  /* SETTERS */

  public async setServiceUrl(url: string): Promise<void> {
    try {
      await SecureStoragePlugin.set({
        key: this.SERVICE_URL_KEY,
        value: url,
      });
    } catch (err) {}
  }

  public async saveLoginResponse(loginResponse: LoginResponse): Promise<void> {
    try {
      await Promise.all([
        SecureStoragePlugin.set({
          key: this.ACCESS_TOKEN_KEY,
          value: loginResponse.accessToken,
        }),
      ]);
    } catch (err) {}
  }

  public async saveOtpToken(loginResponse: LoginResponse): Promise<void> {
    try {
      await Promise.all([
        SecureStoragePlugin.set({
          key: this.OTP_TOKEN_KEY,
          value: loginResponse.accessToken,
        }),
      ]);
      await Promise.all([
        SecureStoragePlugin.set({
          key: this.SESSION_KEY,
          value: loginResponse.id,
        }),
      ]);
    } catch (err) {}
  }

  public async saveSessionId(loginResponse: LoginResponse): Promise<void> {
    try {
      await Promise.all([
        SecureStoragePlugin.set({
          key: this.SESSION_KEY,
          value: loginResponse.id,
        }),
      ]);
    } catch (err) {}
  }

  public async deleteTokens(): Promise<void> {
    try {
      await Promise.all([
        SecureStoragePlugin.remove({
          key: this.ACCESS_TOKEN_KEY,
        }),
        SecureStoragePlugin.remove({
          key: this.FEATURE_ACCESS_RIGHTS_KEY,
        }),
        SecureStoragePlugin.remove({
          key: this.ACCESS_RIGHTS_KEY,
        }),
        SecureStoragePlugin.remove({
          key: this.OTP_TOKEN_KEY,
        }),
        SecureStoragePlugin.remove({
          key: this.SESSION_KEY,
        }),
      ]);
    } catch (err) {}
    // await this.logOut();
  }

  public async saveAccessRights(
    accessRights: AccessRight[],
    featureCodes: AccessRight[]
  ): Promise<void> {
    try {
      await SecureStoragePlugin.set({
        key: this.ACCESS_RIGHTS_KEY,
        value: encodeURIComponent(JSON.stringify(accessRights)),
      });

      await SecureStoragePlugin.set({
        key: this.FEATURE_ACCESS_RIGHTS_KEY,
        value: encodeURIComponent(JSON.stringify(featureCodes)),
      });
    } catch (err) {
      console.log(err);
    }
  }

  public async deleteAccessRights(): Promise<void> {
    try {
      await SecureStoragePlugin.remove({
        key: this.ACCESS_RIGHTS_KEY,
      });
      await SecureStoragePlugin.remove({
        key: this.FEATURE_ACCESS_RIGHTS_KEY,
      });
    } catch (err) {}
  }

  /* CHECKERS */

  public async isAccessTokenPresent(): Promise<boolean> {
    try {
      let token = await this.getAccessToken();
      return !!token && token != "";
    } catch (err) {
      return false;
    }
  }

  public async isAccessTokenExpired(): Promise<boolean> {
    try {
      let token = await this.getAccessToken();
      const expiry = JSON.parse(atobSafe(token.split(".")[1])).exp;
      return Math.floor(new Date().getTime() / 1000) >= expiry;
    } catch (err) {
      return true;
    }
  }

  /* ACTIONS */

  public async refreshToken(): Promise<boolean> {
    let serviceUrl: string;
    try {
      serviceUrl = await this.getServiceUrl();
    } catch (err) {
      return false;
    }
    let sessionId = await this.getSessionId();
    let request: RefreshTokenRequest = {
      accessToken: await this.getAccessToken(),
      sessionId: sessionId,
    };
    try {
      let response = await this.http
        .post<LoginResponse>(serviceUrl + `api/auth/refreshtoken`, request)
        .toPromise();
      await this.saveLoginResponse(response);
      // await this.pagingService.setPageSize();
      let windowCodes = MENU.filter((x) => !!x.windowCode)
        .map((x) => x.windowCode)
        .reduce(function (previousValue, currentValue) {
          return previousValue.concat(currentValue);
        });

      var accessRights: AccessRight[][] = await this.http
        .post<AccessRight[][]>(serviceUrl + `api/auth/AccessRights`, {
          WindowCodes: windowCodes,
          latitude: 0,
          longitude: 0,
        })
        .toPromise();
      await this.saveAccessRights(accessRights[0], accessRights[1]);
      return true;
    } catch (error) {
      console.log(error);
      await this.logOut();
      return false;
    }
  }

  public async redirectToLoginScreen(): Promise<void> {
    this.router.navigate(["/login"]);
  }

  public async logOut(): Promise<void> {
    this.deleteTokens();
    this.deleteAccessRights();
    clearInterval(this.sendLocationInterval);
    this.locCaptureFreq = undefined;
    this.router.navigate(["/login"], {
      queryParams: {
        logout: "true",
      },
    });
  }

  public async fetchUserAccessRights() {
    var lat, long;
    if (Capacitor.getPlatform() != "web") {
      await this.location.getLocation().then((response) => {
        console.log(response);
        if (response.success) {
          lat = response.position.coords.latitude;
          long = response.position.coords.longitude;
        } else {
          lat = 0;
          long = 0;
        }
      });
    } else {
      lat = 0;
      long = 0;
    }

    let windowCodes = MENU.filter((x) => !!x.windowCode)
      .map((x) => x.windowCode)
      .reduce(function (previousValue, currentValue) {
        return previousValue.concat(currentValue);
      });

    this.http
      .post<AccessRight[][]>(
        this.envService.API_URL + `api/auth/AccessRights`,
        {
          WindowCodes: windowCodes,
          latitude: lat,
          longitude: long,
        }
      )
      .subscribe({
        next: async (accessRights: AccessRight[][]) => {
          // this.errorMessage = null;
          await this.saveAccessRights(accessRights[0], accessRights[1]);
          this.router.navigate([""]);
          // this.showLoader = false;
          // this.resetLoginForm();
        },
        error: async (err) => {
          await this.deleteTokens();
          if (
            err.error ==
            ".حدث خطأ عند الاتصال بالبرنامج. يرجى التواصل مع الدعم الفنى"
          )
            throw err;
          else {
            throw new Error("خطأ في الاتصال بالخادم");
          }
        },
      });
  }

  private async loggedSuccessfully(response: LoginResponse) {
    await this.saveLoginResponse(response);
    await this.pagingService.setPageSize();
    await this.fetchUserAccessRights();
    let userBranchInfo = await this.userService.getUserBranchInfo();
    if (userBranchInfo) {
      await Preferences.set({
        key: "periodStartDate",
        value: this.datePipe.transform(
          userBranchInfo.period_start_date,
          "yyyy-MM-dd"
        ),
      });
      await Preferences.set({
        key: "periodEndDate",
        value: this.datePipe.transform(
          userBranchInfo.period_end_date,
          "yyyy-MM-dd"
        ),
      });
    }
  }

  public async sendOtp(otp: string): Promise<LoginResponse> {
    try {
      var username = await this.getUserInfoFromOTPToken();
      let otpToken = await this.getOtpToken();
      let sessionId = await this.getSessionId();
      console.log(otpToken, sessionId, otp);
      const response = await this.http
        .post<LoginResponse>(
          `${this.envService.API_URL}api/auth/MohassilLogin`,
          {
            otp: otp,
            twoFAAccessToken: otpToken,
            session: sessionId,
          }
        )
        .toPromise();
      if (!response.twoFactorAuth) {
        await this.loggedSuccessfully(response);
      } else {
        await this.saveOtpToken(response);
      }
      return response;
    } catch (error) {
      let errorMessage =
        error.status === 0
          ? "خطأ في الوصول للخادم"
          : error?.error ?? error?.message ?? "خطأ في الاتصال بالخادم";
      if (
        errorMessage ===
        "انتهت صلاحية كلمة المرور, من فضلك إرجع إلى مشرف النظام"
      ) {
        this.router.navigate(["/change-password-user"], {
          queryParams: {
            username: username,
          },
        });
      } else {
        throw new Error(errorMessage);
      }
    }
  }
  public async login(
    username: string,
    password: string
  ): Promise<LoginResponse | boolean> {
    try {
      const response = await this.http
        .post<LoginResponse>(
          `${this.envService.API_URL}api/auth/MohassilLogin`,
          {
            username,
            password,
          }
        )
        .toPromise();
      if (!response.twoFactorAuth) {
        await this.loggedSuccessfully(response);
        this.initializeSendLocation();
      } else {
        await this.saveOtpToken(response);
      }
      await this.saveSessionId(response);

      return response;
    } catch (error) {
      console.log("errorrrrrrrrrrr: ",error)
      let errorMessage =
        error.status === 0
          ? "خطأ في الوصول للخادم"
          : error?.error ?? error?.message ?? "خطأ في الاتصال بالخادم";
      console.log(
        errorMessage,
        errorMessage ===
          "انتهت صلاحية كلمة المرور, من فضلك إرجع إلى مشرف النظام"
      );
      if (
        errorMessage ===
        "انتهت صلاحية كلمة المرور, من فضلك إرجع إلى مشرف النظام"
      ) {
        return false;
      } else {
        throw new Error(errorMessage);
      }
    }
  }
  initializeSendLocation() {
    if (!this.locCaptureFreq) this.getLocFreq();
    else {
      this.sendLocationInterval = setInterval(() => {
        this.sendLocation();
      }, this.locCaptureFreq);
    }
  }
  getLocFreq() {
    if (this.envService.API_URL) {
      this.http
        .get<string>(this.envService.API_URL + `api/settings/GetLocationFreq`)
        .subscribe({
          next: async (result: string) => {
            this.locCaptureFreq = parseInt(result) * 1000;
            this.sendLocationInterval = setInterval(async () => {
              await this.sendLocation();
            }, this.locCaptureFreq);
          },
          error: (error) => {
            console.error(error);
          },
        });
    }
  }
  async sendLocation() {
    const isAccessTokenPresent = await this.isAccessTokenPresent();
    if (!isAccessTokenPresent) {
      clearInterval(this.sendLocationInterval);
      return;
    }

    var lat = 0,
      long = 0;
    if (Capacitor.getPlatform() != "web") {
      await this.location.getLocation().then((response) => {
        if (response.success) {
          lat = response.position.coords.latitude;
          long = response.position.coords.longitude;
        } else {
          lat = -1;
          long = -1;
        }
      });

      this.http
        .post<string>(
          this.envService.API_URL + `api/location/SendUserLocation`,
          {
            latitude: lat,
            longitude: long,
          }
        )
        .subscribe({
          next: async (result: string) => {
            console.log("ba3at el location", lat, long);
          },
          error: (error) => {
            console.error(error);
          },
        });
    } else {
      clearInterval(this.sendLocationInterval);
    }
  }
}
