import {
  Component,
  ElementRef,
  EventEmitter,
  Input,
  OnInit,
  Output,
  ViewChild,
} from "@angular/core";
import { IonModal, ModalController } from "@ionic/angular";
import {
  NgxGalleryAction,
  NgxGalleryComponent,
  NgxGalleryImage,
  NgxGalleryOptions,
} from "@kolkov/ngx-gallery";
import { CameraService } from "src/app/core/services/camera.service";
import { ExportingService } from "src/app/core/services/exporting.service";
import { Capacitor } from "@capacitor/core";
import { AlertService } from "src/app/core/services/alert.service";
import { PdfAndImgService } from "src/app/core/services/pdf&img.service";
import { PdfViewerService } from "src/app/core/services/pdf-viewer.service";
import { ActionSheetController } from "@ionic/angular";
import { DocumentService } from "src/app/core/services/document.service";
import { DocumentType } from "../../Models/Documents/DocumentType";
import { HttpErrorResponse } from "@angular/common/http";
import { FormBuilder, FormGroup } from "@angular/forms";

interface DocumentsObject {
  formGroup: FormGroup;
  selectedDocuments: DocumentTypes[];
}
interface DocumentTypes extends DocumentType {
  dataForEveryPage: {
    number: number;
    base64: string;
  }[];
}
interface DataBaseResponses {
  allDocumentsTypeInDataBase: DocumentType[];
}
export interface ImageAndPdfIndependentComponentInputs {
  documentsTypesCodes: string[];
  canDocumentsTypeCodesBeRemoved: boolean;
  canEdit: boolean;
  canAddingDocumentsType: boolean;
}
export interface ImageAndPdfIndependentComponentResponse {
  documentTypeCode: string;
  numberOfPagesExist: number;
  details: { pageNumber: number; base64: string }[];
}

@Component({
  selector: "image-and-pdf-independent",
  templateUrl: "./image-and-pdf-independent.component.html",
  styleUrls: ["./image-and-pdf-independent.component.scss"],
})
export class ImageAndPdfIndependentComponent implements OnInit {
  @Input() inputsInterface: ImageAndPdfIndependentComponentInputs;
  @Output() documentComponentResponse: EventEmitter<
    ImageAndPdfIndependentComponentResponse[]
  > = new EventEmitter();
  @ViewChild("ngxGallery") ngxGallery: NgxGalleryComponent;
  constructor(
    private cameraService: CameraService,
    private exportingService: ExportingService,
    private alertService: AlertService,
    private pdfViewerService: PdfViewerService,
    private actionSheetCtrl: ActionSheetController,
    private documentService: DocumentService,
    private formBuilder: FormBuilder
  ) {}

  //#region Variables
  databaseResponses: DataBaseResponses;
  documentsObject: DocumentsObject;
  showLoader: boolean = false;
  galleryOptions: NgxGalleryOptions[];
  galleryImages: NgxGalleryImage[] = [];
  //#endregion

  get selectedDocuments() {
    return this.documentsObject.selectedDocuments;
  }
  get documentTypeCodesFromFormGroup(): string[] | null {
    const documentsTypesCodes: string[] =
      this.documentsObject.formGroup.value.documentsType;
    return documentsTypesCodes;
  }
  set documentTypeCodesFromFormGroup(codes: string[] | null) {
    this.documentsObject.formGroup.patchValue({
      documentsType: codes,
    });
  }
  async ngOnInit() {
    this.initialState();
    await this.handleDocumentTypes();
  }
  initialState() {
    this.databaseResponses = {
      allDocumentsTypeInDataBase: [],
    };
    this.documentsObject = {
      selectedDocuments: [],
      formGroup: this.formBuilder.group({
        documentsType: [null],
      }),
    };
    this.galleryOptions = [
      {
        arrowPrevIcon: "fa fa-arrow-circle-o-left",
        arrowNextIcon: "fa fa-arrow-circle-o-right",
        closeIcon: "fa fa-window-close",
        fullscreenIcon: "fa fa-arrows",
        spinnerIcon: "fa fa-refresh fa-spin fa-3x fa-fw",
        previewZoom: true,
        previewRotate: true,
        imageArrows: true,
        previewCloseOnEsc: true,
        previewCloseOnClick: true,
        previewAnimation: true,
        previewArrows: false,
        //change here to show the ngx-gallery | starts
        preview: false,
        previewBullets: false,
        thumbnails: false,
        imageSwipe: false,
        previewSwipe: false,
        previewKeyboardNavigation: false,
        // previewForceFullscreen: true,
        //change here to show the ngx-gallery | ends
        previewDownload: true,
        //previewBullets: true,
        previewFullscreen: true,
        thumbnailsRows: 2,
        thumbnailsPercent: 40,
        imagePercent: 60,
        thumbnailMargin: 5,
        thumbnailsMargin: 5,
        imageSize: "contain",
        actions: [
          // {
          //   icon: "fa fa-upload",
          //   onClick: this.openDocumentModalObject,
          //   disabled: !this.canEditCurrDoc,
          // },
          // {
          //   icon: "fa fa-print",
          //   onClick: this.printElement,
          // },
        ],
        //actions: [{ icon: "fa fa-print", onClick: this.getImageFromGallery }],
      },
      {
        thumbnailsMoveSize: 4,
        breakpoint: 500,
        width: "300",
        height: "300",
        thumbnailsColumns: 3,
      },
      {
        breakpoint: 300,
        width: "100%",
        height: "200px",
        thumbnailsColumns: 2,
      },
    ];
  }
  async handleDocumentTypes() {
    this.documentTypeCodesFromFormGroup =
      this.inputsInterface.documentsTypesCodes;
    this.databaseResponses.allDocumentsTypeInDataBase =
      await this.documentService.getActiveClientDocumentsTypes().toPromise();
    const selectedDocuments =
      this.databaseResponses.allDocumentsTypeInDataBase.filter((doc) => {
        return this.inputsInterface.documentsTypesCodes.includes(
          doc.documentTypeCode
        );
      });
    this.documentsObject.selectedDocuments = selectedDocuments.map((doc) => ({
      dataForEveryPage: this.addEmptyImagesForDocumentType(
        doc.documentTypeCode
      ),
      documentPagesNumber: doc.documentPagesNumber,
      documentTypeCode: doc.documentTypeCode,
      documentTypeDesc: doc.documentTypeDesc,
      documentTypeRef: doc.documentTypeRef,
    }));
  }
  addEmptyImagesForDocumentType = (documentTypeCode: string) => {
    let result: {
      number: number;
      base64: string;
    }[] = [];
    const selectedDocument =
      this.databaseResponses.allDocumentsTypeInDataBase.find(
        (x) => x.documentTypeCode === documentTypeCode
      );
    selectedDocument.documentPagesNumber;
    for (let i = 0; i < Number(selectedDocument.documentPagesNumber); i++) {
      result.push({
        number: i + 1,
        base64: null,
      });
    }
    return result;
  };
  getNumberOfPagesExist = (documentTypeCode: string): number => {
    const selectedDocument = this.documentsObject.selectedDocuments.find(
      (x) => x.documentTypeCode === documentTypeCode
    );

    return selectedDocument.dataForEveryPage.filter((x) => x.base64 !== null)
      .length;
  };
  async clickOnSpecificPage(
    selectedDocument: DocumentTypes,
    pageNumber: number
  ) {
    try {
      let specificPage = selectedDocument.dataForEveryPage.find(
        (x) => x.number === pageNumber
      );

      if (specificPage.base64 === null && !this.inputsInterface.canEdit) {
        return;
      }
      if (specificPage.base64 === null && this.inputsInterface.canEdit) {
        await this.getBase64FromDevice(selectedDocument, pageNumber);
        return;
      }
      if (specificPage.base64 !== null && !this.inputsInterface.canEdit) {
        this.previewBase64(selectedDocument, pageNumber);
      }
      if (specificPage.base64 !== null && this.inputsInterface.canEdit) {
        this.presentActionSheet(selectedDocument, pageNumber);
      }
    } catch (error) {
      this.handleError(error);
    }
  }
  updateBase64(documentTypeCode: string, pageNumber: number, base64: string) {
    return this.documentsObject.selectedDocuments.map((doc) => {
      if (doc.documentTypeCode === documentTypeCode) {
        doc.dataForEveryPage = doc.dataForEveryPage.map((page) => {
          if (page.number === pageNumber) {
            page.base64 = base64;
          }
          return page;
        });
      }
      return doc;
    });
  }
  showImagePreviewer(base64: string) {
    const imageBase64 =
      "data:" +
      this.exportingService.getBase64Type(base64) +
      ";base64," +
      base64;
    this.galleryImages = [
      {
        small: imageBase64,
        medium: imageBase64,
        big: imageBase64,
      },
    ];
    setTimeout(() => {
      this.ngxGallery.openPreview(0);
    }, 0);
  }
  async presentActionSheet(
    selectedDocument: DocumentTypes,
    pageNumber: number
  ) {
    let specificPage = selectedDocument.dataForEveryPage.find(
      (x) => x.number === pageNumber
    );
    const actionSheet = await this.actionSheetCtrl.create({
      header: `ملفات العميل بصيغة ${
        this.exportingService.getBase64Type(specificPage.base64) ===
        "application/pdf"
          ? "PDF"
          : "JPEG"
      }`,
      mode: "ios",
      cssClass: "my-custom-class",
      buttons: [
        {
          icon: "eye",
          handler: () => {
            this.previewBase64(selectedDocument, pageNumber);
          },
        },
        {
          icon: "cloud-upload",
          handler: async () => {
            await this.getBase64FromDevice(selectedDocument, pageNumber);
          },
        },
        {
          icon: "close",
          role: "cancel",
          cssClass: "danger",
          data: {
            action: "cancel",
          },
        },
      ],
    });
    await actionSheet.present();
  }
  async previewBase64(selectedDocument: DocumentTypes, pageNumber: number) {
    let specificPage = selectedDocument.dataForEveryPage.find(
      (x) => x.number === pageNumber
    );
    switch (this.exportingService.getBase64Type(specificPage.base64)) {
      case "application/pdf": {
        if (this.pdfViewerService.canViewPdf()) {
          await this.pdfViewerService.viewPdf(
            specificPage.base64,
            selectedDocument.documentTypeDesc
          );
        }
        break;
      }
      case "image/jpeg":
      case "image/png": {
        this.showImagePreviewer(specificPage.base64);
        break;
      }
      default: {
        this.alertService.showAlertError("صيغة الملف غير صحيحة", false);
        break;
      }
    }
  }
  async getBase64FromDevice(
    selectedDocument: DocumentTypes,
    pageNumber: number
  ) {
    const photo = await this.cameraService.getPhoto();
    if (photo.success) {
      this.documentsObject.selectedDocuments = this.updateBase64(
        selectedDocument.documentTypeCode,
        pageNumber,
        photo.photo.base64String
      );
      this.returnDocumentComponentResponse();
    } else {
      this.alertService.showAlertError(photo.message, false);
    }
  }
  handleSelectedDocumentTypes() {
    const selectedDocumentTypeCodes = this.selectedDocuments.map(
      (doc) => doc.documentTypeCode
    );
    const formDocumentTypeCodes = this.documentTypeCodesFromFormGroup;

    // Add new document types that are in the form but not in selectedDocuments
    formDocumentTypeCodes.forEach((code) => {
      if (!selectedDocumentTypeCodes.includes(code)) {
        this.addNewDocumentType(code);
      }
    });
    // Remove document types that are in selectedDocuments but not in the form
    selectedDocumentTypeCodes.forEach((code) => {
      if (!formDocumentTypeCodes.includes(code)) {
        this.removeDocumentType(code);
      }
    });
    this.returnDocumentComponentResponse();
  }
  valuesToDisable() {
    if (this.inputsInterface.canDocumentsTypeCodesBeRemoved) return [];
    return this.inputsInterface?.documentsTypesCodes;
  }
  returnDocumentComponentResponse() {
    const response = this.selectedDocuments.map((x) => ({
      documentTypeCode: x.documentTypeCode,
      numberOfPagesExist: this.getNumberOfPagesExist(x.documentTypeCode),
      details: x.dataForEveryPage.map((x) => ({
        pageNumber: x.number,
        base64: x.base64,
      })),
    }));
    this.documentComponentResponse.emit(response);
  }
  addNewDocumentType(documentTypeCode: string) {
    // Check if the document type already exists in selected documents
    const existingDocument = this.selectedDocuments.find(
      (doc) => doc.documentTypeCode === documentTypeCode
    );
    if (existingDocument) return; // Exit if document already exists

    // Find the document type in the database
    const documentTypeData =
      this.databaseResponses.allDocumentsTypeInDataBase.find(
        (doc) => doc.documentTypeCode === documentTypeCode
      );
    if (!documentTypeData) return; // Exit if document type not found in database

    // Add new document type to the selected documents list
    this.documentsObject.selectedDocuments.push({
      dataForEveryPage: this.addEmptyImagesForDocumentType(
        documentTypeData.documentTypeCode
      ),
      documentPagesNumber: documentTypeData.documentPagesNumber,
      documentTypeCode: documentTypeData.documentTypeCode,
      documentTypeDesc: documentTypeData.documentTypeDesc,
      documentTypeRef: documentTypeData.documentTypeRef,
    });
  }
  removeDocumentType(documentTypeCode: string) {
    // Find the index of the document type in selected documents
    const documentIndex = this.selectedDocuments.findIndex(
      (doc) => doc.documentTypeCode === documentTypeCode
    );

    if (documentIndex === -1) return; // Exit if document type doesn't exist

    // Remove the document type from the selected documents list
    this.selectedDocuments.splice(documentIndex, 1);
  }
  private handleError(error: unknown) {
    let errorMessage: string;

    if (error instanceof HttpErrorResponse) {
      errorMessage = JSON.stringify(error.error);
    } else if (error instanceof Error) {
      errorMessage = error.message;
    } else {
      errorMessage = String(error);
    }

    this.alertService.showAlertError(errorMessage, false);
    console.error("Error:", error);
  }
}
