import { PageType, MenuItem } from "src/app/views/layout/sidebar/menu.model";

export const flattenMenu = (menu: MenuItem[]): MenuItem[] => {
  return menu.reduce((acc: MenuItem[], item: MenuItem) => {
    if (item.subItems && item.subItems.length > 0) {
      acc.push(...flattenMenu(item.subItems));
    } else {
      acc.push(item);
    }
    return acc;
  }, []);
};
