import { Component, EventEmitter, Input, OnInit, Output } from "@angular/core";
import { ClientInfo, CosignersInfo } from "../../Models/Client/ClientInfo";
import { FormBuilder, FormGroup } from "@angular/forms";
import { AlertService } from "src/app/core/services/alert.service";
import { HttpClient, HttpErrorResponse } from "@angular/common/http";
import { EnvService } from "src/app/core/services/env.service";
import { IscoreHttpService } from "src/app/core/services/iscore-http.service";
import { PdfViewerService } from "src/app/core/services/pdf-viewer.service";

@Component({
  selector: "app-cosigners",
  templateUrl: "./cosigners.component.html",
  styleUrls: ["./cosigners.component.scss"],
})
export class CosignersComponent implements OnInit {
  isCosignersModalOpened: boolean = false;
  isAddCosignerSearchOpened: boolean = false;
  showLoader: boolean = false;
  @Input() selectedCosigners!: CosignersInfo[];
  @Input() clientInfo: ClientInfo;
  @Input() canEdit: boolean = false;
  @Input() history?: boolean = false;
  @Output() selectedCosignersChange = new EventEmitter<CosignersInfo[]>();

  cosignerSearchForm: FormGroup = this.formBuilder.group({
    search_input: [""],
    search_type: [""],
  });

  search_types = [
    ["الكود في ملف العملاء", 1],
    ["البحث بالرقم القومـــي", 2],
  ];

  iscoreInquiries: { inquiryId: number; inquiryPdfBase64: string }[] = [];

  constructor(
    private formBuilder: FormBuilder,
    private alertService: AlertService,
    private http: HttpClient,
    private env: EnvService,
    private pdfViewerService: PdfViewerService,
    private iscoreHttpService: IscoreHttpService
  ) {}

  ngOnInit() {}

  setIsCosignersModalOpened(isOpened: boolean) {
    this.isCosignersModalOpened = isOpened;
  }

  closeCosignersModal() {
    this.isCosignersModalOpened = false;
    this.isAddCosignerSearchOpened = false;
    this.cosignerSearchForm.patchValue({
      search_input: null,
      search_type: null,
    });
  }

  async deleteCosigner(index: any) {
    if (!(await this.alertService.DeleteAlert())) {
      return;
    }

    this.selectedCosigners.splice(index, 1);
    this.selectedCosignersChange.emit(this.selectedCosigners);
  }
  cosignerSearchValidation() {
    if (
      this.cosignerSearchForm.controls.search_type.value == 1 &&
      this.cosignerSearchForm.controls.search_input.value ==
        this.clientInfo.client_code
    ) {
      this.alertService.showAlertError("كود الضامن هو كود العميل", false);
      return;
    }
    if (
      this.cosignerSearchForm.controls.search_type.value == 2 &&
      this.cosignerSearchForm.controls.search_input.value ==
        this.clientInfo.nation_id
    ) {
      this.alertService.showAlertError(
        "الرقم القومي للضامن هو الرقم القومي للعميل",
        false
      );
      return;
    }
    if (
      this.cosignerSearchForm.controls.search_type.valid &&
      this.cosignerSearchForm.controls.search_input.valid
    )
      this.searchForCosigner();
  }

  async searchForCosigner() {
    if (this.cosignerSearchForm.controls.search_input.value.length > 0) {
      if (this.cosignerSearchForm.controls.search_type.value == 1) {
        this.showLoader = true;
        this.http
          .get<ClientInfo>(
            this.env.API_URL +
              `api/Clients/GetCoSignerByCode?clientCode=${this.cosignerSearchForm.controls.search_input.value}`
          )
          .subscribe({
            next: async (data) => {
              console.log(data);
              if (data) {
                this.addCosignerRow(data);
              }
              this.showLoader = false;
            },
            error: async (err) => {
              console.log(err);
              await this.alertService.showAlertError(err.error, false);
              this.showLoader = false;
            },
          });
      } else {
        if (this.cosignerSearchForm.controls.search_type.value == 2) {
          this.showLoader = true;
          this.http
            .get<ClientInfo>(
              this.env.API_URL +
                `api/Clients/GetCoSignerByNationID?nationID=${this.cosignerSearchForm.controls.search_input.value}`
            )
            .subscribe({
              next: (data) => {
                this.addCosignerRow(data);
                console.log(data);
                this.showLoader = false;
              },
              error: async (err) => {
                console.log(err);
                await this.alertService.showAlertError(err.error, false);
                this.showLoader = false;
              },
            });
        } else {
          await this.alertService.showAlertError("يجب اختيار نوع بحث", false);
        }
      }
    } else {
      await this.alertService.showAlertError("يجب ادخال بحث", false);
    }
  }

  addCosignerRow(cosigner: ClientInfo) {
    const duplicateCosignerIndex = this.selectedCosigners.findIndex((value) => {
      return (
        value.coNationId == cosigner.nation_id ||
        value.coClientKey == cosigner.client_key
      );
    });
    console.log(this.selectedCosigners, duplicateCosignerIndex);
    if (duplicateCosignerIndex > -1) {
      return;
    }

    this.cosignerSearchForm.patchValue({
      search_input: null,
      search_type: null,
    });

    this.selectedCosigners = [
      {
        orgCode: this.clientInfo.org_code,
        coClientCode: cosigner.client_code,
        coClientKey: cosigner.client_key,
        coClientName: cosigner.client_name,
        coNationId: cosigner.nation_id,
        coBirthDate: new Date(cosigner.birth_date),
        coHomeAdd1: cosigner.home_add_1,
        coGender: cosigner.gender,
        mobile1: cosigner.mobile_1,
        isAdded: true,
        iscore: cosigner.iscore,
        iscoreInquiryId: cosigner.iscoreInquiryId,
        iscorePdfAvailable: (cosigner.iscorePdfAvailable = 1 ? true : false),
      },
      ...this.selectedCosigners,
    ];
    this.selectedCosignersChange.emit(this.selectedCosigners);
  }

  addCosigner() {
    this.isAddCosignerSearchOpened = !this.isAddCosignerSearchOpened;
  }

  public async showInquiryPdf(inquiryId: number) {
    if (!this.pdfViewerService.canViewPdf()) {
      await this.alertService.showAlertError(
        "لا يمكن عرض أو تنزيل المستند على المتصفح الحالي",
        false
      );
      return;
    }

    await this.getInquiryPdf(inquiryId);

    await this.pdfViewerService.viewPdf(
      this.iscoreInquiries.find((inquiry) => inquiry.inquiryId == inquiryId)
        .inquiryPdfBase64!,
      `inquiry_${inquiryId}.pdf`,
      "تقرير الاستعلام الائتماني"
    );
  }

  private async getInquiryPdf(inquiryId: number) {
    if (
      !this.iscoreInquiries.some((inquiry) => inquiry.inquiryId == inquiryId)
    ) {
      this.showLoader = true;

      try {
        const pdfResponse = await this.iscoreHttpService
          .getInquiryPdf(inquiryId)
          .toPromise();

        this.iscoreInquiries = [
          ...this.iscoreInquiries.slice(-2),
          { inquiryId, inquiryPdfBase64: pdfResponse.base64String },
        ];

        this.showLoader = false;
      } catch (err) {
        this.showLoader = false;
        if (err instanceof HttpErrorResponse) {
          this.alertService.showAlertError(JSON.stringify(err.error), false);
          return;
        }
      }
    }
  }
  getSelectedCosigners() {
    return this.selectedCosigners;
  }
}
