import {
  Component,
  forwardRef,
  Input,
  OnChanges,
  OnInit,
  SimpleChanges,
  ViewChild,
} from "@angular/core";
import { IonModal } from "@ionic/angular";
import { Item } from "../../Models/Types/item.model";
import { ControlValueAccessor, NG_VALUE_ACCESSOR } from "@angular/forms";

@Component({
  selector: "app-select-with-search",
  templateUrl: "./select-with-search.component.html",
  styleUrls: ["./select-with-search.component.scss"],
  providers: [
    {
      provide: NG_VALUE_ACCESSOR,
      useExisting: forwardRef(() => SelectWithSearchComponent),
      multi: true,
    },
  ],
})
export class SelectWithSearchComponent
  implements ControlValueAccessor, OnInit, OnChanges
{
  @ViewChild("modal", { static: true }) modal!: IonModal;
  @Input() items: Item[] = [];
  @Input() label: string;
  @Input() labelClass: string;
  @Input() title: string;
  @Input() classes: string;
  selectedItemText = "لم يتم اختيار شيء";
  @Input() selectedItem: string = "";
  disabled = false;
  isOpened: boolean = false;

  onChange: any = () => {};
  onTouched: any = () => {};

  ngOnInit(): void {
    if (!this.items || this.items.length == 0)
      this.selectedItemText = "لا توجد بيانات للاختيار من بينها";
    else {
      this.selectedItemText = this.formatData(this.selectedItem);
    }
  }

  ngOnChanges(changes: SimpleChanges): void {
    if (!this.items || this.items.length == 0) {
      this.selectedItem = "";
      this.selectedItemText = "لا توجد بيانات للاختيار من بينها";
    } else {
      this.selectedItemText = this.formatData(this.selectedItem);
    }
  }

  private formatData(data: string) {
    if (this.items && this.items.length > 0) {
      const item = this.items.find((item) => item.value === data?.toString());
      return item ? item.text : "لم يتم اختيار شيء";
    } else {
      return "لا توجد بيانات للاختيار من بينها";
    }
  }

  selectionChanged(item: string) {
    this.selectedItem = item;
    this.selectedItemText = this.formatData(this.selectedItem);
    this.onChange(this.selectedItem);
    this.modal.dismiss();
  }

  writeValue(value: string): void {
    this.selectedItem = value;
    this.selectedItemText = this.formatData(this.selectedItem);
  }

  registerOnChange(fn: any): void {
    this.onChange = fn;
  }

  registerOnTouched(fn: any): void {
    this.onTouched = fn;
  }

  setDisabledState?(isDisabled: boolean): void {
    this.disabled = isDisabled;
  }

  setIsOpened(isOpened: boolean) {
    if (this.items && this.items.length > 0 && !this.disabled)
      this.isOpened = isOpened;
    else this.isOpened = false;
  }

  onWillDismiss(event: Event) {
    this.setIsOpened(false);
  }
}
